INSERT INTO `pula_pytan` (`ID`, `nr_pyt`, `pyt`, `odp_a`, `odp_b`, `odp_c`, `poprawna`, `media`, `zakres`, `pkt`, `kategorie`, `media_migowy_pyt`, `media_migowy_odp_a`, `media_migowy_odp_b`, `media_migowy_odp_c`, `pyt_en`, `odp_a_en`, `odp_b_en`, `odp_c_en`, `pyt_de`, `odp_a_de`, `odp_b_de`, `odp_c_de`, `pyt_ua`, `odp_a_ua`, `odp_b_ua`, `odp_c_ua`) VALUES
(1, 99, 'Czy w tej sytuacji masz obowiązek zatrzymać pojazd?', '', '', '', 'T', 'AK_D05_06_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you obliged to stop the vehicle in the presented situation?', '', '', '', 'Bist du in der dargestellten Situation dazu verpflichtet, das Fahrzeug anzuhalten?', '', '', '', 'Чи зобов\'язані Ви зупинити свій транспортний засіб у цій ситуації?', '', '', ''),
(2, 100, 'Czy w tej sytuacji masz obowiązek zatrzymać pojazd?', '', '', '', 'T', 'AK_D10_30_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm100.wmv', '', '', '', 'Are you obliged to stop the vehicle in the presented situation?', '', '', '', 'Sind Sie in der dargestellten Situation dazu verpflichtet, das Fahrzeug anzuhalten?', '', '', '', 'Чи зобов\'язані Ви зупинити свій транспортний засіб у цій ситуації?', '', '', ''),
(3, 109, 'Czy w przedstawionej sytuacji masz prawo kontynuować jazdę?', '', '', '', 'N', 'AK_D11_43org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm109.wmv', '', '', '', 'Can you continue driving in this situation?', '', '', '', 'Darfst du in der dargestellten Situation die Fahrt fortsetzen?', '', '', '', 'Чи Ви маєте право продовжувати рух у представленій ситуації?', '', '', ''),
(4, 110, 'Czy w przedstawionej sytuacji masz prawo - mimo podawanego sygnału - skręcić w prawo?', '', '', '', 'N', 'AK_D11_45org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you allowed in this situation to turn right despite the light displayed?', '', '', '', 'Darfst du in der dargestellten Situation - trotz des gegebenen Signals - rechts abbiegen?', '', '', '', 'Чи Ви маєте право у представленій ситуації повертати вправо, незважаючи на сигнал, що подається?', '', '', ''),
(5, 290, 'Jaką odległość należy zachować między jadącymi kolumnami samochodów ciężarowych?', 'Nie mniejszą niż 800 metrów.', 'Nie mniejszą niż 500 metrów.', 'Nie mniejszą niż 200 metrów.', 'B', '', 'SPECJALISTYCZNY', 3, 'C', 'pjm290.wmv', 'pjm290a.wmv', 'pjm290b.wmv', 'pjm290c.wmv', 'What should be the safe following distance between columns of lorries?', 'Not less than 800 metres.', 'Not less than 500 metres.', 'Not less than 200 metres.', 'Wie groß soll der Abstand sein, der zwischen den fahrenden LKW- Kolonnen, die Straßentransport für eigenen Bedarf ausführen, zu halten ist?', 'Nicht kleiner als 800 meter.', 'Nicht kleiner als 500 meter.', 'Nicht kleiner als 200 meter.', 'Яку відстань слід дотримуватися між колонами вантажних автомобілів, що рухаються по дорозі?', 'Не менше 800 метрів', 'Не менше 500 метрів', 'Не менше 200 метрів'),
(6, 293, 'Kierujesz samochodem ciężarowym. Który z wymienionych czynników jesteś zobowiązany uwzględnić, aby zachować bezpieczny odstęp od poprzedzającego pojazdu?', 'Prędkość pojazdów.', 'Moc silnika.', 'Szerokość pojazdów.', 'A', '', 'SPECJALISTYCZNY', 3, 'C', 'pjm293.wmv', 'pjm293a.wmv', 'pjm293b.wmv', 'pjm293c.wmv', 'You are driving a lorry. Which of the following factors should you take into account to keep a safe distance from the vehicle in front?', 'Speed of the vehicles.', 'Power of the engine.', 'Width of the vehicles.', 'Sie fahren einen LKW. Welchen der genannten Faktoren haben Sie zu berücksichtigen, damit ein sicherer Abstand zu dem vorausfahrenden Fahrzeug gehalten wird?', 'Die Geschwindigkeit der Fahrzeuge.', 'Die Motorleistung.', 'Die Breite der Fahrzeuge.', 'Ви керуєте вантажним автомобілем. Який із перерахованих чинників Ви зобов\'язані врахувати, щоб дотримуватися безпечної дистанції від транспортного засобу, що їде попереду?', 'Швидкість транспортних засобів', 'Потужність двигуна', 'Ширину транспортних засобів'),
(7, 352, 'Czy na jezdni oznaczonej tym znakiem wolno Ci zawrócić?', '', '', '', 'N', 'IMG_4251orgbm.jpg', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm352.wmv', '', '', '', 'Are you allowed to make a U-turn on a roadway with this sign?', '', '', '', 'Darfst du auf der mit diesem Zeichen gekennzeichneten Fahrbahn wenden?', '', '', '', 'Чи дозволяється розворот Вашого транспортного засобу, якщо проїжджа частина позначена цим знаком?', '', '', ''),
(8, 469, 'Czy w tej sytuacji powinieneś oczekiwać, że następnym sygnałem będzie światło zielone?', '', '', '', 'T', '3106D15_a_org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm469.wmv', '', '', '', 'In the presented situation, should you expect that the next light will be green?', '', '', '', 'Soll man in der dargestellten Situation erwarten, dass als nächstes Signal das grüne Licht kommt?', '', '', '', 'Чи у цій ситуації слід очікувати, що наступним сигналом буде зелене світло світлофора?', '', '', ''),
(9, 475, 'Czy w tej sytuacji wolno Ci skręcić w prawo bez zatrzymania się przed sygnalizatorem?', '', '', '', 'N', '0118D14MM_a_org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm475.wmv', '', '', '', 'In the presented situation are you allowed to turn right without stopping before the traffic lights?', '', '', '', 'Darf man in der dargestellten Situation rechts abbiegen, ohne vor der Ampel angehalten zu haben?', '', '', '', 'Чи можна в цій ситуації повертати вправо, не зупиняючись перед світлофором?', '', '', ''),
(10, 477, 'Czy w tej sytuacji sygnał świetlny nadawany dla Twojego pasa ruchu zezwala Ci na zawracanie?', '', '', '', 'N', '2064D14MM_a_org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm477.wmv', '', '', '', 'Does the light signal for you lane allow for making a U-turn in this situation?', '', '', '', 'Erlaubt in der dargestellten Situation das Lichtsignal, das für Ihre Fahrspur gesendet wird, zu wenden?', '', '', '', 'Чи у цій ситуації сигнал світлофора для Вашої смуги руху дозволяє Вам на розворот транспортного засобу?', '', '', ''),
(11, 478, 'Czy w tej sytuacji nadawany sygnał świetlny oznacza, że podczas jazdy w prawo nie występuje kolizja z innymi uczestnikami ruchu?', '', '', '', 'T', '066D16_a_org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm478.wmv', '', '', '', 'Does the traffic light displayed in this situation denote that when turning right there is no collision with other road users?', '', '', '', 'Bedeutet das in der dargestellten Situation gegebene Leuchtsignal, dass es bei der Fahrt nach rechts keine Gefahr mehr gibt, mit anderen Verkehrsteilnehmern zu kollidieren?', '', '', '', 'Чи у цій ситуації сигнал світлофора означає, що Ви не зіткнетеся з іншими учасниками дорожнього руху, якщо будете повертати вправо?', '', '', ''),
(12, 480, 'Czy w tej sytuacji nadawany sygnał świetlny zezwala Ci na wjazd za sygnalizator?', '', '', '', 'N', 'IMG_0325_9550d5_a_org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm480.wmv', '', '', '', 'Does the traffic light displayed in this situation allow you to drive beyond the traffic light post?', '', '', '', 'Erlaubt das gegebene Leuchtsignal die Weiterfahrt hinter der Ampel?', '', '', '', 'Чи дозволяє в цій ситуації сигнал світлофора в\'їжджати на перехрестя за світлофор?', '', '', ''),
(13, 486, 'Czy w tej sytuacji wolno Ci skręcić w prawo, jeśli nie spowodujesz tym utrudnienia ruchu?', '', '', '', 'N', '0084D18_a_org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm486.wmv', '', '', '', 'Are you allowed to turn right in this situation if you do not cause impediments to traffic?', '', '', '', 'Darf man in der dargestellten Situation rechts abbiegen, sofern man den Straßenverkehr nicht behindert?', '', '', '', 'Чи дозволяється Вам повернути вправо у цій ситуації, за умови, що Ви не створюєте перешкоду для інших транспортних засобів?', '', '', ''),
(14, 544, 'Czy w tej sytuacji wolno Ci zmienić zajmowany pas ruchu, gdy zamierzasz jechać na wprost?', '', '', '', 'T', 'IMG_9324_org.jpg', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm544.wmv', '', '', '', 'Are you allowed in this situation to change the lane you are taking when you intend to go straight?', '', '', '', 'Darf man in der dargestellten Situation die von dir besetzte Fahrbahn wechseln, wenn man die Absicht hat, geradeaus zu fahren?', '', '', '', 'Чи можете Ви в цій ситуації змінити смугу руху, якщо маєте намір їхати прямо?', '', '', ''),
(15, 589, 'Czy na tej drodze możesz spodziewać się rowerzystów nadjeżdżających z przeciwka?', '', '', '', 'T', '4152D15Xorg.jpg', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm589.wmv', '', '', '', 'Can you expect cyclists coming from the opposite direction on this road?', '', '', '', 'Kannst du auf dieser Straße damit rechnen, dass aus entgegengesetzter Richtung Fahrradfahrer kommen?', '', '', '', 'Чи можна на цій дорозі сподіватися велосипедистів з протилежного напрямку?', '', '', ''),
(16, 591, 'Czy w tej sytuacji wolno Ci wjechać na pas ruchu po lewej stronie?', '', '', '', 'N', '4170D15_a_org.jpg', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm591.wmv', '', '', '', 'Are you allowed in this situation to drive onto the lane on the left?', '', '', '', 'Darf man in der dargestellten Situation auf die Fahrbahn auf der linken Seite einfahren?', '', '', '', 'Чи дозволяється Вам у цій ситуації в\'їхати на смугу руху зліва?', '', '', ''),
(17, 595, 'Czy ten znak poziomy wyznacza miejsce bezwzględnego zatrzymania się, nawet w sytuacji, gdy z żadnej ze stron nie nadjeżdża pojazd?', '', '', '', 'T', 'D16_01_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm595.wmv', '', '', '', 'Does this horizontal sign define a place of obligatory stop, even if there is no vehicle approaching from either side?', '', '', '', 'Bestimmt dieses horizontale Zeichen die Stelle, wo obligatorisch anzuhalten ist, sogar in einer solchen Situation, in der aus keiner Richtung ein Fahrzeug kommt?', '', '', '', 'Чи визначає цей горизонтальний знак місце обов’язкової зупинки, навіть якщо з жодної зі сторін не наближається транспортний засіб?', '', '', ''),
(18, 599, 'Czy w tej sytuacji widoczna linia przerywana wyznacza Ci miejsce zatrzymania w związku ze znakiem stop?', '', '', '', 'N', 'D16_05_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm599.wmv', '', '', '', 'Does this dashed line in this situation indicate a place to stop because of the stop sign?', '', '', '', 'Bestimmt in der dargestellten Situation die sichtbare gestrichelte Linie die Stelle, wo das Fahrzueg im Zusammenhang mit dem Zeichen Stopp angehalten werden soll?', '', '', '', 'Чи у цій ситуації переривчата лінія визначає місце Вашої зупинки у зв’язку зі знаком STOP?', '', '', ''),
(19, 600, 'Czy ta linia ciągła wyznacza Ci miejsce zatrzymania pojazdu w związku ze znakiem stop?', '', '', '', 'T', 'D16_06_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm600.wmv', '', '', '', 'Does this solid line in this situation indicate a place to stop because of the stop sign?', '', '', '', 'Bestimmt die durchgezogene Linie die Stelle, wo das Fahrzeug im Zusammenhang mit dem Zeichen Stopp angehalten werden soll?', '', '', '', 'Чи ця суцільна лінія визначає місце Вашої зупинки у зв’язку зі знаком STOP?', '', '', ''),
(20, 610, 'Zamierzasz zawrócić na tym skrzyżowaniu. Czy zajmujesz właściwy pas ruchu?', '', '', '', 'T', 'MM_D14_15_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm610.wmv', '', '', '', 'You intend to make a U-turn at this intersection. Are you taking the proper lane?', '', '', '', 'Sie haben vor, an dieser Kreuzung zu wenden. Befinden Sie sich auf der richtigen Fahrspur?', '', '', '', 'Ви збираєтеся розвернутися на цьому перехресті. Чи правильно Ви вибрали смугу руху?', '', '', ''),
(21, 612, 'Skręcasz w lewo na skrzyżowaniu. Czy po wjechaniu na jezdnię poprzeczną znaki poziome pozwalają Ci zająć pas ruchu przy prawej krawędzi jezdni?', '', '', '', 'T', 'MM_D14_17_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'You are turning left at the intersection. After entering the crosswise road, do the horizontal signs allow you to take the lane by the right edge of the roadway?', '', '', '', 'Sie biegen in der Kreuzung links ab. Erlauben die Fahrbahnmarkierungen, nachdem Sie auf die Querfahrbahn eingefahren sind, die rechte Fahrspur an der Fahrbahnkante in Anspruch zu nehmen?', '', '', '', 'Ви повертаєте ліворуч на перехресті. Чи після того, як Ви здійснили маневр повороту вліво, горизонтальна розмітка дозволяє Вам зайняти праву крайню смугу?', '', '', ''),
(22, 617, 'Czy w tym miejscu wolno Ci skręcić w lewo i wjechać na stację paliw?', '', '', '', 'N', 'MM_D14_24_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm617.wmv', '', '', '', 'Are you allowed in this place to turn left and drive into the petrol station?', '', '', '', 'Darf man an dieser Stelle links abbiegen und auf die Tankstelle einfahren?', '', '', '', 'Чи Вам можна у цьому місці повернути вліво і в\'їхати на заправку?', '', '', ''),
(23, 621, 'Czy widoczna linia złożona z trójkątów wskazuje Ci miejsce zatrzymania pojazdu w celu ustąpienia pierwszeństwa?', '', '', '', 'T', 'MM_D14_29_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm621.wmv', '', '', '', 'Does the line composed of triangles indicate the place to stop your vehicle in order to give the right of way?', '', '', '', 'Zeigt die  dargestellte, aus Dreiecken bestehende Linie die Stelle an, wo man anhalten muss, um die Vorfahrt zu gewähren?', '', '', '', 'Чи розмітка у вигляді трикутників позначає місце, де Ви повинні зупинитися у разі потреби і дати дорогу транспортним засобам, що мають перевагу у русі перед Вами?', '', '', ''),
(24, 623, 'Czy w tym miejscu możesz skręcić w lewo, na parking?', '', '', '', 'N', 'MM_D14_34_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you allowed to turn left to the parking space in the place marked in such a way?', '', '', '', 'Darf man an der so markierten Stelle links, auf den Parkplatz abbiegen?', '', '', '', 'Чи дозволено Вам повернути вліво на парковку в цьому місці?', '', '', ''),
(25, 624, 'Zamierzasz odpocząć. Czy w tym miejscu możesz skręcić w lewo, na parking?', '', '', '', 'N', 'MM_D14_38_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm624.wmv', '', '', '', 'You intend to take a rest. Are you allowed in this place to turn left to the parking space?', '', '', '', 'Sie haben vor, zu rasten. Darf man an dieser Stelle links, zum Parkplatz abbiegen?', '', '', '', 'Ви збираєтеся відпочити. Чи Ви можете повернути тут вліво, на парковку?', '', '', ''),
(26, 626, 'Czy w tej sytuacji wolno Ci skręcić w lewo z zajmowanego przez Ciebie pasa ruchu?', '', '', '', 'N', 'MM_D14_42_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm626.wmv', '', '', '', 'Are you allowed to turn left from the lane you are occupying?', '', '', '', 'Darf man an dieser Stelle von dem in Anspruch genommenen Fahrstreifen links abbiegen?', '', '', '', 'Чи дозволено Вам повертати ліворуч зі своєї смуги в даній ситуації?', '', '', ''),
(27, 627, 'Czy w tym miejscu wolno Ci wjechać na pas ruchu przeznaczony dla pojazdów jadących w przeciwnym kierunku?', '', '', '', 'N', '0445D14MM_aorgbm.jpg', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm627.wmv', '', '', '', 'Are you allowed to drive onto the lane designated to vehicles driving in the opposite direction?', '', '', '', 'Darf man an dieser Stelle auf den Fahrstreifen kommen, der für Fahrzeuge bestimmt ist, die in der entgegengesetzten Richtung fahren?', '', '', '', 'Чи у цьому місці Ви можете в\'їхати на смугу для транспортних засобів, що рухаються в протилежному напрямку?', '', '', ''),
(28, 630, 'Czy w tym miejscu, bezpośrednio przed przejściem dla pieszych, wolno Ci zmienić pas ruchu?', '', '', '', 'N', 'D10MM_3org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm630.wmv', '', '', '', 'Are you allowed in this place, directly in front of the pedestrian crossing to, change the lane?', '', '', '', 'Darf man an der Stelle, die zu sehen ist, direkt vor dem Fußgängerübergang, die Fahrspur wechseln?', '', '', '', 'Чи у цьому місці, безпосередньо перед пішохідним переходом, Вам дозволяється змінити смугу руху?', '', '', ''),
(29, 632, 'Czy widoczny znak poziomy w kształcie trójkąta potwierdza ostrzeżenie o skrzyżowaniu z drogą z pierwszeństwem?', '', '', '', 'T', 'D10MM_10org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm632.wmv', '', '', '', 'Does this horizontal triangular sign confirm the warning of an intersection with the main road?', '', '', '', 'Bestätigt die gezeigte Fahrbahnmarkierung in Form eines Dreiecks die Warnung vor einer Kreuzung mit Vorfahrtsstraße?', '', '', '', 'Чи горизонтальна розмітка у вигляді трикутника попереджає про перехрестя з дорогою з пріоритетним рухом (з головною дорогою)?', '', '', ''),
(30, 637, 'Czy w tej sytuacji wolno Ci wjechać na sąsiedni prawy pas ruchu?', '', '', '', 'T', 'D10MM_22org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm637.wmv', '', '', '', 'Are you allowed in this situation to drive onto the adjacent right lane?', '', '', '', 'Darf man in der dargestellten Situation auf die benachbarte rechte Fahrspur einfahren?', '', '', '', 'Чи можна в цій ситуації виїжджати на сусідню праву смугу руху?', '', '', ''),
(31, 639, 'Czy widoczna poprzeczna linia przerywana wyznacza miejsce warunkowego zatrzymania pojazdu?', '', '', '', 'T', 'D10MM_7org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm639.wmv', '', '', '', 'Does this crosswise dashed line indicate the place for conditional stopping of the vehicle?', '', '', '', 'Bestimmt die sichtbare gestrichelte Querlinie die Stelle, wo das Fahrzeug bedingt angehalten  werden soll?', '', '', '', 'Чи поперечна переривчаста лінія горизонтальної розмітки означає місце умовної зупинки транспортного засобу?', '', '', ''),
(32, 748, 'Czy w tej sytuacji masz prawo wyprzedzać samochód ciężarowy?', '', '', '', 'T', '048D15_a_org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you allowed to overtake the articulated vehicle in this situation?', '', '', '', 'Darf man in dieser Situation den LkW überholen?', '', '', '', 'Чи дозволяється Вам обганяти вантажівку в цій ситуації?', '', '', ''),
(33, 770, 'Planujesz skręcić w lewo, a kierujący pojazdem z przeciwka ma zamiar jechać na wprost. Czy masz przed nim pierwszeństwo?', '', '', '', 'N', 'KW_D22_417_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm770.wmv', '', '', '', 'You plan to turn left and the driver of the oncoming vehicle intends to follow the road ahead. Have you got priority over them?', '', '', '', 'Sie planen, links abzubiegen und das entgegenkommende Fahrzeug hat es vor, geradeaus zu fahren. Haben Sie die Vorfahrt vor ihm?', '', '', '', 'Ви плануєте повернути ліворуч, а зустрічний водій має намір їхати прямо. Чи Ви маєте перевагу в русі перед ним?', '', '', ''),
(34, 771, 'Zamierzasz skręcić w lewo. Czy masz obowiązek ustąpić pierwszeństwa wszystkim pojazdom znajdującym się na skrzyżowaniu?', '', '', '', 'T', 'KW_D22_418_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm771.wmv', '', '', '', 'You intend to turn left. Are you obliged to yield the right-of-way to all vehicles at the junction?', '', '', '', 'Sie haben es vor, links abzubiegen. Sind Sie dazu verpflichtet, allen Fahrzeugen, die sich auf der Kreuzung befinden, Vorfahrt zu geben?', '', '', '', 'Ви маєте намір повернути ліворуч. Чи зобов\'язані Ви дати дорогу всім транспортним засобам, що знаходяться на перехресті?', '', '', ''),
(35, 773, 'Zamierzasz jechać na wprost, a motocyklista chce skręcić w lewo. Czy masz obowiązek ustąpić mu pierwszeństwa?', '', '', '', 'T', 'KW_D22_419_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm773.wmv', '', '', '', 'You are intend to go straight on and the motorcyclist intends to turn left. Do you have to yield the right of way to him?', '', '', '', 'Sie planen, geradeaus zu fahren und der Kraftradführer hat es vor, links abzubiegen. Haben Sie die Pflicht, ihm die Vorfahrt zu geben?', '', '', '', 'Ви маєте намір їхати прямо, а мотоцикліст хоче повернути ліворуч. Чи зобов\'язані Ви уступити йому дорогу?', '', '', ''),
(36, 774, 'Zamierzasz jechać na wprost, a kierujący pojazdem, jadącym z naprzeciwka, chce skręcić w lewo. Czy masz przed nim pierwszeństwo?', '', '', '', 'N', 'KW_D22_419_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm774.wmv', '', '', '', 'You intend to go straight on and the driver of the oncoming vehicle intends to turn left. Do you have the right of way over him?', '', '', '', 'Sie planen, geradeaus zu fahren und das entgegenkommende Fahrzeug hat es vor, links abzubiegen. Haben Sie die Vorfahrt vor ihm?', '', '', '', 'Ви збираєтеся їхати прямо, а водій транспортного засобу, що рухається з протилежного боку, хоче повернути вліво. Чи маєте Ви перевагу у русі перед ним ?', '', '', ''),
(37, 788, 'Zostałeś właśnie wyprzedzony przez pojazd widoczny przed Tobą. Czy bezpośrednio po wyprzedzeniu wolno Ci zwiększyć prędkość?', '', '', '', 'N', 'D26_026org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm788.wmv', '', '', '', 'You have just been overtaken by the vehicle in front of you. Are you allowed to increase your speed immediately after being overtaken?', '', '', '', 'Sie  wurden bereits durch das vorausfahrende Fahrzeug überholt.  Dürfen Sie direkt, nachdem Sie überholt wurden, die Geschwindigkeit erhöhen?', '', '', '', 'Вас щойно обігнав транспортний засіб, який Ви зараз бачите перед собою. Чи одразу після обгону Ви маєте право збільшити швидкість?', '', '', ''),
(38, 799, 'Czy w tej sytuacji, wykonując manewr omijania, masz obowiązek zatrzymać się w razie potrzeby?', '', '', '', 'T', 'D24_AK110org.mp4', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm799.wmv', '', '', '', 'Are you obliged to stop when the need be while passing the stationary obstacle?', '', '', '', 'Soll man in dieser Situation beim Umfahren je nach Bedarf anhalten?', '', '', '', 'Чи в цій ситуації, виконуючи маневр об\'їзду (обминання), Ви зобов’язані затриматися у разі потреби?', '', '', ''),
(39, 809, 'Czy w tej sytuacji, podczas omijania, masz obowiązek zachować szczególną ostrożność?', '', '', '', 'T', 'D24_AK120org.mp4', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm809.wmv', '', '', '', 'Do you have to exercise particular caution when passing a stationary object in this situation?', '', '', '', 'Soll man in dieser Situation beim Umfahren besonders vorsichtig sein?', '', '', '', 'Чи в цій ситуації, під час маневру об\'їзду (обминання), Ви повинні бути особливо обережними?', '', '', ''),
(40, 869, 'Czy widoczna linia wskazuje miejsce obowiązkowego zatrzymania się przed wjazdem na skrzyżowanie?', '', '', '', 'T', 'D16_01_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Does this line indicate the place you must stop before entering the intersection?', '', '', '', 'Zeigt diese Linie diese Stelle an, an der obligatorisch vor dem Einfahren in die Kreuzung anzuhalten ist?', '', '', '', 'Чи вказує лінія, яку Ви бачите, місце де Ви повинні зупинитися перед в\'їздом на перехрестя?', '', '', ''),
(41, 870, 'Czy widoczna linia wskazuje miejsce zatrzymania, które zapewnia Ci najlepszą widoczność na skrzyżowaniu?', '', '', '', 'T', 'D16_01_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Does this line indicate the stop spot that ensures the best visibility at the intersection?', '', '', '', 'Zeigt die dargestellte Linie diese Anhaltstelle an, woher man die besten Sichtverhältnisse in der Kreuzung hat?', '', '', '', 'Чи вказує лінія, яку Ви бачите, на місце зупинки, яке забезпечить Вам найкращу оглядовість на перехресті?', '', '', ''),
(42, 872, 'Czy masz obowiązek zatrzymać się w wyznaczonym linią miejscu, nawet wtedy, gdy upewniłeś się, że drogą z pierwszeństwem przejazdu nie poruszają się inne pojazdy?', '', '', '', 'T', 'D16_01_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you obliged to stop in the indicated place even when you have made sure that there are no other vehicles driving on the main road?', '', '', '', 'Hat man die Pflicht an der markierten Stelle sogar dann anzuhalten, wenn man sich vergewissert hast, dass sich auf der Vorfahrtsstraße keine anderen Fahrzeuge bewegen?', '', '', '', 'Чи зобов\'язані Ви зупинитися в місці, позначеному лінією, навіть якщо Ви переконалися, що на дорозі з першочерговим рухом  немає інших транспортних засобів?', '', '', ''),
(43, 874, 'Czy w miejscu wyznaczonym przez widoczną linię przystankową wolno zatrzymywać się pojazdom przewożącym dzieci do szkół i przedszkoli?', '', '', '', 'T', 'W4(23,54,80)org.mp4', 'PODSTAWOWY', 1, 'D,D1', '', '', '', '', 'Are vehicles, which carry children to schools and pre-schools allowed to stop in the place marked by this bus stop line?', '', '', '', 'Dürfen an der Stelle, die mit der sichtbaren Haltestellelinie abgesteckt ist, Fahrzeuge anhalten, die Kinder in die Schulen und Kindergärten befördern?', '', '', '', '', '', '', ''),
(44, 884, 'Czy w tej sytuacji wolno Ci wjechać na pas ruchu przy prawej krawędzi jezdni?', '', '', '', 'T', 'MM_D14_09_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you allowed in this situation to drive onto the lane by the right edge of the road?', '', '', '', 'Darf man in der dargestellten Situation auf die Fahrspur einfahren, die sich am rechten Straßenrand befindet?', '', '', '', 'Чи можна Вам у цій ситуації в\'їхати на крайню праву смугу руху?', '', '', ''),
(45, 891, 'Czy w przedstawionej sytuacji jesteś ostrzegany o zbliżaniu się do jednego niebezpiecznego zakrętu w prawo?', '', '', '', 'T', 'IMG_0345d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you warned in this situation of a single dangerous bend to the right?', '', '', '', 'Wirst du in der dargestellten Situation vor einer gefährlichen Einzelkurve rechts gewarnt?', '', '', '', 'Чи у наведеній ситуації Вас попереджують про те, що Ви наближаєтеся до одного небезпечного повороту вправо?', '', '', ''),
(46, 892, 'Czy w przedstawionej sytuacji jesteś ostrzegany o kilku niebezpiecznych zakrętach w lewo?', '', '', '', 'N', '1814D15org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm892.wmv', '', '', '', 'Are you warned in this situation of a few dangerous bends to the left?', '', '', '', 'Wirst du in der dargestellten Situation vor mehreren Linkskurven gewarnt?', '', '', '', 'Чи у наведеній ситуації Вас попереджують про те, що Ви наближаєтеся до декількох небезпечних поворотів вліво?', '', '', ''),
(47, 893, 'Czy w przedstawionej sytuacji jesteś ostrzegany o dwóch niebezpiecznych zakrętach?', '', '', '', 'N', 'A-3 zT-4org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm893.wmv', '', '', '', 'Are you warned in this situation of two dangerous bends?', '', '', '', 'Wirst du in der dargestellten Situation vor zwei gefährlichen Kurven gewarnt?', '', '', '', 'Чи у наведеній ситуації Вас попереджають про два небезпечні повороти?', '', '', ''),
(48, 894, 'Czy w przedstawionej sytuacji jesteś ostrzegany o dwóch niebezpiecznych zakrętach, z których pierwszy jest w lewo?', '', '', '', 'T', 'A-4 (5)org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm894.wmv', '', '', '', 'Are you warned in this situation of two dangerous bends, the first to the left?', '', '', '', 'Wirst du in der dargestellten Situation vor zwei gefährlichen Kurven, von denen die erste eine Linkskurve ist, gewarnt?', '', '', '', 'Чи у наведеній ситуації Вас попереджують про два небезпечні повороти, перший з яких - вліво?', '', '', ''),
(49, 898, 'Czy w tej sytuacji jesteś ostrzegany o zbliżaniu się do skrzyżowania, na którym pierwszeństwo przejazdu nie jest określone przy pomocy znaków drogowych?', '', '', '', 'T', 'A-5 (3)org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm898.wmv', '', '', '', 'Are you warned in this situation of an intersection where there are no right of way signs?', '', '', '', 'Wirst du in der dargestellten Situation vor einer Kreuzung gewarnt, auf der die Vorfahrtskennzeichnung ausbleibt?', '', '', '', 'Чи у наведеній ситуації Вас попереджують про те, що Ви наближаєтесь до перехрестя, першочерговість проїзду якого не визначена дорожніми знаками?', '', '', ''),
(50, 904, ' Czy w tej sytuacji należy rozpocząć hamowanie?', '', '', '', 'T', 'D24_20org.mp4', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm904.wmv', '', '', '', 'Should you begin braking your vehicle in this situation?', '', '', '', 'Soll man in der dargestellten Situation mit dem Ausbremsen des Fahrzeuges anfangen?', '', '', '', 'Чи потрібно починати гальмувати в цій ситуації?', '', '', ''),
(51, 916, 'Czy w trakcie prowadzenia pojazdu, wraz z upływem czasu, poprawia się Twoja zdolność dostrzegania znaków i sygnałów drogowych?', '', '', '', 'N', 'IMG_9599org.jpg', 'PODSTAWOWY', 2, 'B', 'pjm916.wmv', '', '', '', 'When driving a vehicle, does your ability to perceive road signs and signals improve with time?', '', '', '', 'Verbessert sich beim Fahrzeuglenken mit dem Ablauf der Zeit Ihre Fähigkeit, Verkehrszeichen- und Signale wahrzunehmen?', '', '', '', 'Чи під час поїздки Ваша здатність реагувати на дорожні знаки та сигнали покращується з часом?', '', '', ''),
(52, 918, 'Kierujesz pojazdem z prędkością 30 km/h. Czy w tej sytuacji powinieneś zatrzymać pojazd przed sygnalizatorem?', '', '', '', 'T', 'AK_D18_07org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm918.wmv', '', '', '', 'You are driving a vehicle at the speed of 30 km/h. Should you stop the vehicle before the traffic lights in this situation?', '', '', '', 'Sie fahren das Fahrzeug mit der Geschwindigkeit von 30 km/h. Sollen Sie das Fahrzeug in dieser Situation vor der Verkehrampel anhalten?', '', '', '', 'Ви керуєте транспортним засобом зі швидкістю 30 км/год. Чи потрібно в цій ситуації зупинятися перед сигналом світлофора?', '', '', ''),
(53, 919, 'Czy gdy prowadzisz w stanie pobudzenia emocjonalnego, to maleje Twoja zdolność koncentracji uwagi?', '', '', '', 'T', 'GND30__4_org.mp4', 'PODSTAWOWY', 2, 'B', 'pjm919.wmv', '', '', '', 'When driving in a state of emotional arousal, does your ability to concentrate decrease?', '', '', '', 'Wenn Sie das Fahrzeug im gereizten Zustand lenken, verringert sich Ihre Konzentrationsfähigkeit?', '', '', '', 'Чи знижується Ваша здатність концентрувати увагу, коли Ви перебуваєте за кермом у стані емоційного збудження?', '', '', ''),
(54, 941, 'Zamierzasz skręcić w lewo. Czy masz obowiązek ustąpić pierwszeństwa pojazdowi nadjeżdżającemu z prawej strony?', '', '', '', 'N', '513_D27KW_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm941.wmv', '', '', '', 'You intend to turn left. Do you have to yield the right of way to the vehicle approaching from the right?', '', '', '', 'Sie möchten links abbiegen. Sollen Sie dem von rechts kommenden Fahrzeug die Vorfahrt geben?', '', '', '', 'Ви збираєтеся повернути вліво. Чи зобов\'язані Ви дати дорогу транспортному засобу, що наближається справа?', '', '', ''),
(55, 942, 'Zamierzasz jechać na wprost. Czy masz obowiązek ustąpić pierwszeństwa pojazdowi nadjeżdżającemu z prawej strony?', '', '', '', 'T', '514_D27KW_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm942.wmv', '', '', '', 'You intend to go straight on. Do you have to yield the right of way to the vehicle approaching from the right?', '', '', '', 'Sie haben  vor, geradeaus zu fahren. Haben Sie die Pflicht, dem von rechts kommenden Fahrzeug den Vorrang zu geben?', '', '', '', 'Ви маєте намір їхати прямо. Чи зобов\'язані Ви дати дорогу транспортному засобу, що наближається справа?', '', '', ''),
(56, 947, 'Zamierzasz jechać na wprost. Czy masz pierwszeństwo przed motocyklistą?', '', '', '', 'N', 'KW_D22_419_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm947.wmv', '', '', '', 'You intend to go straight on. Do you have the right of way over the motorcyclist?', '', '', '', 'Sie haben vor, geradeaus zu fahren. Haben Sie die Vorfahrt vor dem Kraftradfahrer?', '', '', '', 'Ви збираєтеся їхати прямо. Чи маєте Ви перевагу у русі перед мотоциклістом?', '', '', ''),
(57, 974, 'Czy umieszczony na tablicy znak ostrzega Cię o miejscu na drodze, w którym występuje lub może występować niebezpieczeństwo?', '', '', '', 'T', '3436D15org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm974.wmv', '', '', '', 'Does the sign on this board inform you of a place on the road where there is, or there might be a danger?', '', '', '', 'Warnt dich das auf diesem Schild lokalisierte Zeichen vor einer Stelle auf der Straße, die gefährlich ist oder die gefährlich sein kann?', '', '', '', 'Чи попереджає встановлений знак, який Ви бачите, про місце на дорозі, де є або може бути небезпека?', '', '', ''),
(58, 975, 'Czy w przedstawionej sytuacji masz obowiązek zachować szczególną ostrożność?', '', '', '', 'T', 'D20_0061org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,A1,A2,B1,C1,D1', 'pjm975.wmv', '', '', '', 'Do you have to exercise particular caution in the presented situation?', '', '', '', 'Bist du in der dargestellten Situation dazu verpflichtet, besonders vorsichtig zu sein?', '', '', '', 'Чи зобов\'язані Ви бути особливо обережними в наведеній ситуації?', '', '', ''),
(59, 978, 'Czy w przedstawionej sytuacji jesteś ostrzegany o zbliżaniu się do skrzyżowania z jednokierunkową drogą podporządkowaną?', '', '', '', 'T', 'A-6eorg.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm978.wmv', '', '', '', 'In the presented situation, are you warned of an intersection with a one-way minor road?', '', '', '', 'Wirst du in der dargestellten Situation vor einer Kreuzung mit einer untergeordneten Einbahnstraße gewarnt?', '', '', '', 'Чи попереджає Вас знак, який Ви бачите, про те, що Ви наближаєтеся до перехрестя з другорядною дорогою з одностороннім рухом?', '', '', ''),
(60, 980, 'Czy tabliczka umieszczona pod znakiem wskazuje rzeczywisty przebieg drogi z pierwszeństwem przejazdu?', '', '', '', 'T', 'IMG_4003org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In the presented situation, you are warned of an intersection with a major road. Does the plate under the sign indicate its actual route?', '', '', '', 'In der dargestellten Situation wirst du vor einer Kreuzung mit einer Vorfahrtsstraße gewarnt. Zeigt das unter dem Zeichen angebrachte Schild ihren tatsächlichen Verlauf?', '', '', '', 'Чи вказує табличка під знаком на фактичний напрямок руху з пріоритетом?', '', '', ''),
(61, 985, 'Czy w przedstawionej sytuacji jesteś ostrzegany o zbliżaniu się do przejazdu kolejowego wyposażonego w zapory, lub w półzapory?', '', '', '', 'T', '0876D18org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you warned in this situation of a level crossing with full barriers or half-barriers?', '', '', '', 'Wirst du in der abgebildeten Situation vor einem Bahnübergang gewarnt, der weder mit Schranken noch mit Halbschranken ausgestattet ist?', '', '', '', 'Чи у наведеній ситуації попереджають Вас про наближення до переїзду, обладнаного шлагбаумами або напівшлагбаумами?', '', '', ''),
(62, 986, 'Czy w przedstawionej sytuacji jesteś ostrzegany o przejeździe kolejowym wyposażonym w zapory lub półzapory?', '', '', '', 'N', 'A-10 (2)org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm986.wmv', '', '', '', 'Are you warned in this situation of a level crossing with full barriers or half-barriers?', '', '', '', 'Wirst du in der abgebildeten Situation vor einem Bahnübergang gewarnt, der mit Schranken oder Halbschranken ausgestattet ist?', '', '', '', 'Чи в зображеній ситуації Вас попереджають про залізничний переїзд, обладнаний шлагбаумами або напівшлагбаумами?', '', '', ''),
(63, 987, 'Czy w przedstawionej sytuacji jesteś ostrzegany o przejeździe kolejowym wyposażonym w półzapory?', '', '', '', 'N', '1070D18org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you warned in this situation of a level crossing with half-barriers?', '', '', '', 'Wirst du in der abgebildeten Situation vor einem Bahnübergang gewarnt, der mit Halbschranken ausgestattet ist?', '', '', '', 'Чи в зображеній ситуації Вас попереджають про залізничний переїзд з напівшлагбаумами?', '', '', ''),
(64, 988, 'Czy w przedstawionej sytuacji jesteś ostrzegany o poprzecznej nierówności jezdni?', '', '', '', 'T', 'IMG_9274d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you warned in this situation of a transverse unevenness of the roadway?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer Querunebenheit der Fahrbahn gewarnt?', '', '', '', 'Чи знак, який Ви бачите, попереджає Вас про наявність у дорожньому полотні вибоїн?', '', '', ''),
(65, 990, 'Czy w przedstawionej sytuacji jesteś ostrzegany o nierównościach na drodze, występujących na odcinku 1,2 km za znakiem?', '', '', '', 'T', 'IMG_9528d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm990.wmv', '', '', '', 'Are you warned in this situation of a 1.2 km-long rough roadway beyond this sign?', '', '', '', 'Wirst du in der abgebildeten Situation vor Straßenunebenheiten gewarnt, die auf einer Strecke von 1,2 km hinter dem Zeichen auftreten?', '', '', '', 'Чи попереджає Вас знак, який Ви бачите, про нерівну дорогу на відрізку 1,2 км за знаком?', '', '', ''),
(66, 991, 'Czy w przedstawionej sytuacji jesteś ostrzegany o wypukłości jezdni zastosowanej w celu spowolnienia ruchu?', '', '', '', 'N', 'IMG_9274d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you warned in this situation of a hump on the road intended to slow down the traffic?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer Bremsschwelle zwecks Verlangsamung des Verkehrs gewarnt?', '', '', '', 'Чи у наведеній ситуації Вас попереджають про штучну дорожню нерівність («лежачий поліцейський»), яка застосовується для уповільнення руху?', '', '', ''),
(67, 992, 'Czy w przedstawionej sytuacji jesteś ostrzegany o wypukłości na jezdni zastosowanej w celu spowolnienia ruchu?', '', '', '', 'T', 'IMG_8384org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you warned in this situation of hump on the roadway intended to slow down the traffic?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer Bremsschwelle zwecks Verlangsamung des Verkehrs gewarnt?', '', '', '', 'Чи у наведеній ситуації Вас попереджають про штучну дорожню нерівність («лежачий поліцейський»), яка застосовується для уповільнення руху?', '', '', ''),
(68, 994, 'Czy umieszczona pod znakiem ostrzegawczym widocznym na zdjęciu tabliczka, wskazuje jego odległość od miejsca niebezpiecznego?', '', '', '', 'T', 'IMG_8384org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Does the board placed under this warning sign indicate the sign\'s distance from a dangerous spot?', '', '', '', 'Zweigt das unter dem abgebildeten Warnzeichen angebrachte Schild die Entfernung von der gefährlichen Stelle an?', '', '', '', 'Чи вказує табличка під попереджувальним знаком, зображеним на фотографії, відстань до небезпечної зони?', '', '', ''),
(69, 996, 'Czy w przedstawionej sytuacji jesteś ostrzegany o zwężeniu jezdni, które może powodować utrudnienia ruchu?', '', '', '', 'T', 'IMG_0816d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm996.wmv', '', '', '', 'Are you warned in this situation of road narrowing which may cause impediments to the traffic?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer Fahrbahnverengung gewarnt, die den Straßenverkehr behindern kann?', '', '', '', 'Чи попереджають Вас у наведеній ситуації про звуження проїжджої частини, яке може спричинити утруднення руху?', '', '', ''),
(70, 997, 'Czy w przedstawionej sytuacji jesteś ostrzegany o wlocie drogi z prawej strony?', '', '', '', 'N', 'IMG_6630d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm997.wmv', '', '', '', 'Are you warned in this situation of a junction with the road on the right?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer von rechts einmündenden Straße gewarnt?', '', '', '', 'Чи попереджають Вас у наведеній ситуації про прилягання дороги з правого боку?', '', '', ''),
(71, 1000, 'Czy w przedstawionej sytuacji należy spodziewać się utrudnień ruchu?', '', '', '', 'T', 'IMG_7184_1org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1000.wmv', '', '', '', 'Do you need to be prepared for impediments to traffic in this situation?', '', '', '', 'Sollst du in der abgebildeten Situation mit Straßenverkehrsbehinderungen rechnen?', '', '', '', 'Чи в наведеній ситуації варто очікувати утруднень руху?', '', '', ''),
(72, 1001, 'Czy w przedstawionej sytuacji jesteś ostrzegany o zbliżaniu się do wyznaczonego na drodze przejścia dla pieszych?', '', '', '', 'T', '843D15org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1001.wmv', '', '', '', 'Are you warned in this situation of a pedestrian crossing marked on the road?', '', '', '', 'Wirst du in der abgebildeten Situation vor einem auf der Strasse markierten Fußgängerüberweg gewarnt?', '', '', '', 'Чи попереджають Вас у зображеній ситуації, що Ви наближаєтесь до визначеного на дорозі пішохідного переходу?', '', '', ''),
(73, 1003, 'Czy w przedstawionej sytuacji jesteś ostrzegany o miejscu na drodze szczególnie często uczęszczanym przez dzieci lub o bliskości takiego miejsca?', '', '', '', 'T', 'A-17 (2)org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1003.wmv', '', '', '', 'Are you warned in this situation of a place on the road frequently attended by children or of proximity of such a place?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer Stelle auf der Straße gewarnt, die besonders oft von Kindern besucht wird bzw. davor, dass sich eine solche Stelle in der Nähe befindet?', '', '', '', 'Чи попереджають Вас у зображеній ситуації про появу дітей біля проїжджої частини, або про близькість такого місця?', '', '', ''),
(74, 1005, 'Czy w przedstawionej sytuacji jesteś ostrzegany o możliwości napotkania na drodze dzikich zwierząt?', '', '', '', 'T', 'JAZDA NOCĄorg.mp4', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you warned in this situation of a possible encounter with wild animals on the road?', '', '', '', 'Wirst du in der abgebildeten Situation vor Gefahren gewarnt, die sich aus der Möglichkeit ergeben, Wildtieren auf der Straße zu begegnen?', '', '', '', 'Чи попереджають Вас у зображеній ситуації про ділянку дороги, на якій можлива поява диких тварин?', '', '', ''),
(75, 1009, 'Czy w przedstawionej sytuacji jesteś ostrzegany o zbliżaniu się do miejsca, w którym rozpoczyna się ruch dwukierunkowy?', '', '', '', 'T', '1498D15org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1009.wmv', '', '', '', 'Are you warned in this situation of a place where two-way traffic begins?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer Stelle gewarnt, wo Zweibahnverkehr beginnt?', '', '', '', 'Чи попереджають Вас у зображеній ситуації про наближення до місця, де розпочинається двосторонній рух?', '', '', ''),
(76, 1015, 'Czy w przedstawionej sytuacji jesteś ostrzegany o zbliżaniu się do stromego podjazdu?', '', '', '', 'N', '0805D14MMorg.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1015.wmv', '', '', '', 'Are you warned in this situation of a steep uphill road?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer steilen Auffahrt gewarnt?', '', '', '', 'Чи попереджають Вас у зображеній ситуації про наближення до крутого підйому?', '', '', ''),
(77, 1018, 'Czy w przedstawionej sytuacji jesteś ostrzegany o miejscu, w którym rowerzyści wjeżdżają na jezdnię lub przez nią przejeżdżają?', '', '', '', 'T', '0989D18org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1018.wmv', '', '', '', 'Are you warned in this situation of a place where cyclists emerge onto the road or cross it?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer Stelle gewarnt, an der Fahradfahrer auf die Fahrbahn entweder kommen oder sie überqueren?', '', '', '', 'Чи попереджають Вас у зображеній ситуації про місце, де велосипедисти виїжджають на проїжджу частину або перетинають її?', '', '', ''),
(78, 1025, 'Czy w przedstawionej sytuacji jesteś ostrzegany o drodze pokrytej żwirem, który może być wyrzucany spod kół jadących pojazdów?', '', '', '', 'T', 'IMG_9333d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1025.wmv', '', '', '', 'Are you warned in this situation of a road covered with gravel which may be discarded from under the wheels of moving vehicles?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer Straße gewarnt, die mit Kies bedeckt ist, der durch die fahrenden Autos ausgeschleudert wird?', '', '', '', 'Чи попереджають Вас у наведеній ситуації про дорогу, вкриту гравієм, який може вилетіти з-під коліс транспортних засобів, що рухаються?', '', '', ''),
(79, 1028, 'Czy w przedstawionej sytuacji jesteś ostrzegany o skrzyżowaniu, na którym ruch jest kierowany za pomocą sygnalizacji świetlnej?', '', '', '', 'T', 'IMG_9157d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you warned in this situation of a place where the traffic is directed by traffic lights?', '', '', '', 'Wirst du in der abgebildeten Situation vor einer Stelle gewarnt, wo der Straßenverkehr durch die Ampeln geregelt wird?', '', '', '', 'Чи попереджають вас у зображеній ситуації про перехрестя, на якому рух регулюється світлофором?', '', '', ''),
(80, 1033, 'Czy w przedstawionej sytuacji, wjeżdżając na pobocze, powinieneś zrobić to ostrożnie i znacznie zmniejszyć prędkość?', '', '', '', 'T', 'IMG_1387d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1033.wmv', '', '', '', 'In the presented situation, when pulling over, should you do it carefully and slow down significantly if the need be?', '', '', '', 'Hast du in der abgebildeten Situation beim Befahren des Seitenstreifens besonders vorsichtig zu sein und bei Bedarf die Geschwindigkeit wesentlich zu reduzieren?', '', '', '', 'Чи у зображеній ситуації, виїжджаючи на узбіччя дороги, потрібно робити це обережно і значно зменшивши швидкість?', '', '', ''),
(81, 1035, 'Czy na odcinku drogi za widocznym znakiem będziesz ostrzegany o każdym występującym na niej zakręcie?', '', '', '', 'N', 'IMG_7630d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1035.wmv', '', '', '', 'Will you be warned beyond this sign of every single bend on the road?', '', '', '', 'Wirst du auf der Strecke hinter dem abgebildeten Zeichen vor jeder Kurve gewarnt, die es auf dieser Straße gibt?', '', '', '', 'Чи на ділянці дороги за зображеним знаком, Вас кожного разу попереджуватимуть про небезпечний поворот?', '', '', ''),
(82, 1052, 'Czy w tej sytuacji czerwone punktowe elementy odblaskowe wyznaczają prawą krawędź jezdni?', '', '', '', 'T', 'IMG_9751org.jpg', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1052.wmv', '', '', '', 'In this situation, do the red reflective point elements define the right edge of the roadway?', '', '', '', 'Markieren in der abgebildeten Situation die roten Rückstrahlpunkte den rechten Straßenrand?', '', '', '', 'Чи у зображеній ситуації червоні пунктові світловідбивачі позначають правий край проїжджої частини?', '', '', ''),
(83, 1055, 'Czy w tej sytuacji, za linią złożoną z punktowych elementów odblaskowych barwy czerwonej znajduje się pas ruchu?', '', '', '', 'N', 'IMG_9757aorg.jpg', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1055.wmv', '', '', '', 'In the presented situation, is there a lane behind the line composed of red reflective road studs?', '', '', '', 'Befindet sich in der dargestellten Situation hinter der aus roten Punktrückstrahler bestehenden Linie eine Fahrspur?', '', '', '', 'Чи у зображеній ситуації за лінією, що складається з червоних пунктових світловідбивачів знаходиться смуга руху?', '', '', ''),
(84, 1056, 'Czy w tej sytuacji, bezpośrednio za widoczną po prawej stronie drogi linią złożoną z punktowych elementów odblaskowych barwy białej jest pobocze?', '', '', '', 'N', 'IMG_9746org.jpg', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1056.wmv', '', '', '', 'In the presented situation, is there a hard shoulder directly behind the line on the right, composed of white reflective road studs?', '', '', '', 'Befindet sich in der dargestellten Situation direkt hinter der auf der rechten Straßenseite sichtbaren, aus weißen Punktrückstrahlern bestehenden Linie der Randstreifen?', '', '', '', 'Чи у зображеній ситуації безпосередньо за лінією з білих пунктових світловідбивачів знаходиться узбіччя?', '', '', ''),
(85, 1058, 'Czy w tej sytuacji, umieszczone po prawej stronie jezdni punktowe elementy odblaskowe barwy białej informują Cię o krawędzi jezdni?', '', '', '', 'N', 'IMG_9746org.jpg', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1058.wmv', '', '', '', 'In the presented situation, do the white reflective road studs placed on the right side of the road inform you of the edge of the roadway?', '', '', '', 'Informieren in der dargestellten Situation die auf der rechten Fahrbahn angebrachten weißen Punktrückstrahler über die Fahrbahnkante?', '', '', '', 'Чи в зображеній ситуації білі пунктові світловідбивачі, розташовані з правої сторони, інформують Вас про край проїжджої частини?', '', '', '');
INSERT INTO `pula_pytan` (`ID`, `nr_pyt`, `pyt`, `odp_a`, `odp_b`, `odp_c`, `poprawna`, `media`, `zakres`, `pkt`, `kategorie`, `media_migowy_pyt`, `media_migowy_odp_a`, `media_migowy_odp_b`, `media_migowy_odp_c`, `pyt_en`, `odp_a_en`, `odp_b_en`, `odp_c_en`, `pyt_de`, `odp_a_de`, `odp_b_de`, `odp_c_de`, `pyt_ua`, `odp_a_ua`, `odp_b_ua`, `odp_c_ua`) VALUES
(86, 1068, 'Czy w przedstawionej sytuacji masz obowiązek zachować odstęp nie mniejszy niż 1 metr od wyprzedzanego rowerzysty?', '', '', '', 'T', 'D17PWCz_1org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1068.wmv', '', '', '', 'Are you obliged to maintain a distance of at least 1 metre from the overtaken cyclist in this situation?', '', '', '', 'Haben Sie in der dargestellten Situation die Pflicht, von dem zu überholenden Radfahrer einen Abstand von nicht weniger als 1 m zu halten?', '', '', '', 'Чи зобов\'язані Ви в цій ситуації дотримуватися дистанції не менше 1 метра від велосипедиста, якого Ви обганяєте?', '', '', ''),
(87, 1081, 'Czy na tak oznakowanym skrzyżowaniu masz prawo wyprzedzać pojazdy poruszające się innymi pasami?', '', '', '', 'T', 'D29WCzorg.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you allowed to overtake vehicles on other lanes at a junction marked in such a way?', '', '', '', 'Dürfen Sie auf einer so gekennzeichneten Kreuzung die auf anderen Spuren fahrenden Fahrzeuge überholen?', '', '', '', 'Чи на перехресті, позначеному таким чином, Ви маєте право обганяти транспортні засоби, що рухаються по інших смугах?', '', '', ''),
(88, 1090, 'Czy w tej sytuacji możesz wyprzedzać?', '', '', '', 'N', 'D38WCz_2org.mp4', 'PODSTAWOWY', 3, 'B', 'pjm1090.wmv', '', '', '', 'Can you overtake in this situation?', '', '', '', 'Dürfen Sie in dieser Situation überholen?', '', '', '', 'Чи можете Ви здійснити обгін у цій ситуації?', '', '', ''),
(89, 1091, 'Czy w przedstawionej sytuacji zakaz wyrażony znakiem obowiązuje od miejsca jego ustawienia?', '', '', '', 'T', '526D21org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1091.wmv', '', '', '', 'In the presented situation, is the prohibition expressed by this sign binding from the place of its erection?', '', '', '', 'Gilt in der dargestellten Situation das durch dieses Zeichen eingeführte Verbot ab der Stelle, auf der dieses Zeichen aufgestellt ist?', '', '', '', 'Чи в наведеній ситуації заборона, виражена знаком, діє від місця розташування знака?', '', '', ''),
(90, 1092, 'Czy umieszczona pod tym znakiem zakazu tabliczka określa długość odcinka jezdni, na którym zakaz ten obowiązuje?', '', '', '', 'T', '1005D15org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1092.wmv', '', '', '', 'Does the plate under this prohibition sign indicate the length of the road section where the prohibition is binding?', '', '', '', 'Zeigt das unter diesem Verkehrzeichen angebrachte Schild die Länge des Fahrbahnabschnittes an, für den dieses Verbot gilt?', '', '', '', 'Чи табличка під цим заборонним знаком визначає довжину ділянки проїжджої частини, на яку поширюється заборона?', '', '', ''),
(91, 1107, 'Czy w tej sytuacji masz obowiązek ustąpić pierwszeństwa pojazdowi nadjeżdżającemu z lewej strony?', '', '', '', 'T', '511_D27KW_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1107.wmv', '', '', '', 'Are you obliged in this situation to yield the right of way to the vehicle approaching from the left?', '', '', '', 'Haben Sie in dieser Situation die Pflicht, dem von links angefahren kommenden Fahrzeug, die Vorfahrt zu geben?', '', '', '', 'Чи зобов\'язані Ви у цій ситуації уступити дорогу транспортному засобу, що наближається зліва?', '', '', ''),
(92, 1109, 'Zamierzasz kontynuować jazdę na wprost. Czy masz pierwszeństwo przed pojazdem nadjeżdżającym z prawej strony?', '', '', '', 'N', '518_D27KW_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1109.wmv', '', '', '', 'You intend to continue going straight on. Do you have the right of way over the vehicle approaching from the right?', '', '', '', 'Sie möchten die Fahrt geradeaus fortsetzen. Haben Sie die Vorfahrt vor dem von rechts kommenden Fahrzeug?', '', '', '', 'Ви маєте намір продовжити рух прямо. Чи маєте Ви перевагу перед транспортним засобом, що наближається справа?', '', '', ''),
(93, 1111, 'Czy w tej sytuacji masz obowiązek ustąpić pierwszeństwa pojazdowi, który nadjeżdża z lewej strony?', '', '', '', 'T', 'KW_D16_354org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1111.wmv', '', '', '', 'In this situation, do you have to yield the right of way to the vehicle approaching from the left?', '', '', '', 'Sind Sie  in der dargestellten Situation dazu verpflichtet, dem von links kommenden Fahrzeug die Vorfahrt zu geben?', '', '', '', 'Чи зобов\'язані Ви в цій ситуації уступити дорогу транспортному засобу, що наближається зліва?', '', '', ''),
(94, 1112, 'Czy w tej sytuacji masz pierwszeństwo przed pojazdem wjeżdżającym z lewej strony na pas ruchu?', '', '', '', 'N', 'KW_D16_355org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In this situation, do you have priority over the vehicle driving from the left into the traffic lane?', '', '', '', 'Haben Sie in der dargestellten Situation Vorfahrt vor dem Fahrzeug, das von der linken Seite auf die Fahrspur einfährt?', '', '', '', 'Чи у зображеній ситуації Ви маєте право на першочерговий рух перед транспортним засобом, що в\'їжджає в смугу руху зліва?', '', '', ''),
(95, 1114, 'Zamierzasz skręcić w prawo. Czy masz obowiązek ustąpienia pierwszeństwa pojazdowi, który nadjeżdża z lewej strony?', '', '', '', 'N', 'KW_D16_352org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1114.wmv', '', '', '', 'You intend to turn right. Do you have to yield the right of way to the vehicle approaching from the left?', '', '', '', 'Sie möchten rechts abbiegen. Sind Sie dazu verpflichtet, dem von links kommenden Fahrzeug Vorfahrt zu geben?', '', '', '', 'Ви збираєтеся повернути вправо. Чи зобов\'язані Ви уступити дорогу транспортному засобу, що наближається зліва?', '', '', ''),
(96, 1120, 'Zamierzasz skręcić w lewo. Czy masz obowiązek ustąpić pierwszeństwa rowerzyście?', '', '', '', 'T', 'KW_D16_253org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1120.wmv', '', '', '', 'You intend to turn left. Do you have to yield the right of way to the cyclist?', '', '', '', 'Sie möchten links abbiegen. Sind Sie dazu verpflichtet, dem Fahrradfahrer Vorfahrt zu lassen?', '', '', '', 'Ви збираєтеся повернути вліво. Чи зобов\'язані Ви уступити дорогу велосипедисту?', '', '', ''),
(97, 1121, 'Czy w tej sytuacji, jadąc na wprost, masz pierwszeństwo przed pojazdem nadjeżdżającym z prawej strony?', '', '', '', 'T', 'KW_D16_357org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1121.wmv', '', '', '', 'You intend to continue driving straight on. In this situation do you have the right of way over the vehicle approaching from the right?', '', '', '', 'Sie möchten geradeaus fahren. Haben Sie in dieser Situation Vorfahrt vor dem von rechts kommenden Fahrzeug?', '', '', '', 'Чи у наведеній ситуації, якщо Ви їдете прямо, Ви маєте перевагу перед транспортним засобом, що наближається справа?', '', '', ''),
(98, 1127, 'Czy w tej sytuacji należy zrezygnować z rozpoczęcia wyprzedzania?', '', '', '', 'T', 'D26_395org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1127.wmv', '', '', '', 'Should you resign from overtaking in this situation?', '', '', '', 'Ist in der dargestellten Situation auf das Überholmanöver zu verzichten?', '', '', '', 'Чи слід утриматися від обгону в цій ситуації?', '', '', ''),
(99, 1133, 'Czy w przedstawionej sytuacji w obszarze zabudowanym, masz obowiązek zmniejszyć prędkość, aby umożliwić kierującemu autobusem włączenie się do ruchu?', '', '', '', 'T', '705.D34KWorg.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you obliged in this situation to slow down in the built-up area to allow the bus driver to join the traffic?', '', '', '', 'Soll man in der dargestellten Situation in geschlossener Ortschaft die Geschwindigkeit reduzieren, um dem Busfahrer die Möglichkeit zu verschaffen, sich in den Verkehr einzufädeln?', '', '', '', 'Чи у наведеній ситуації, в населеному пункті, Ви зобов\'язані зменшити швидкість, щоб дати можливість водієві автобуса влитися в транспортний потік?', '', '', ''),
(100, 1134, 'Skręcasz w lewo na najbliższym skrzyżowaniu. Czy masz pierwszeństwo przed nadjeżdżającym pojazdem?', '', '', '', 'N', '706.D34KWorg.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1134.wmv', '', '', '', 'You are turning left at the nearest junction. Do you have the right of way over the approaching vehicle?', '', '', '', 'Sie biegen in der nächsten Kreuzung links ab. Haben Sie Vorfahrt vor dem kommenden Fahrzeug?', '', '', '', 'Ви повертаєте вліво на найближчому перехресті. Чи маєте Ви перевагу по відношенню до транспортного засобу, що наближається?', '', '', ''),
(101, 1138, 'Czy kierując autobusem komunikacji miejskiej na obszarze zabudowanym, powinieneś upewnić się, że wyjazd z zatoki nie spowoduje zagrożenia bezpieczeństwa ruchu drogowego?', '', '', '', 'T', '717.D35KWorg.mp4', 'PODSTAWOWY', 3, 'D,D1', '', '', '', '', 'You are driving a public transport bus in the built-up area. Should you make sure that emerging from the lay-by will not pose a threat to road safety?', '', '', '', 'Sie fahren einen Stadtbus in geschlossener Ortschaft. Sollen Sie sichvergewissern, dass das Verlassen der Haltebucht den Straßenverker nicht gefährdet?', '', '', '', '', '', '', ''),
(102, 1139, 'Czy kierując autobusem komunikacji miejskiej poza obszarem zabudowanym masz pierwszeństwo podczas włączania się do ruchu z przystanku?', '', '', '', 'N', '717.D35KWorg.mp4', 'PODSTAWOWY', 3, 'D,D1', '', '', '', '', 'You are driving a public transport bus outside the built-up area. Do you have priority in this situation when joining the traffic from the bus stop?', '', '', '', 'Sie fahren einen Stadtbus außerhalb geschlossener Ortschaft. Haben Sie in der dargestellten Situation beim Einorden in den Verkehr von der Haltestelle die Vorfahrt?', '', '', '', '', '', '', ''),
(103, 1142, 'Czy w tej sytuacji, jadąc na wprost, jesteś włączającym się do ruchu?', '', '', '', 'T', 'D42_8org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1142.wmv', '', '', '', 'You intend to go straight ahead. Are you joining the traffic in this situation?', '', '', '', 'Sie möchten geradeaus fahren. Sind Sie in der dargestellten Situation Derjenige, der sich in den Verkehr einordnet?', '', '', '', 'У цій ситуації, їдучи прямо, Ви вливаєтеся у транспортний потік (розпочинаєте рух)?', '', '', ''),
(104, 1143, 'Czy masz pierwszeństwo przed pojazdem nadjeżdżającym z lewej strony?', '', '', '', 'N', '537.D28KW_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1143.wmv', '', '', '', 'Have you got priority over the vehicle approaching from the left?', '', '', '', 'Haben Sie die Vorfahrt vor dem von links kommenden Fahrzeug?', '', '', '', 'Чи маєте Ви перевагу перед транспортним засобом, що наближається зліва?', '', '', ''),
(105, 1144, 'Czy w tej sytuacji zachowanie pieszego wymaga, abyś użył sygnału dźwiękowego?', '', '', '', 'N', '538.D28KW_org.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1144.wmv', '', '', '', 'Does the behaviour of the pedestrian require you to use the horn?', '', '', '', 'Erfordert die Verhaltensweise des Fußgängers in der dargestellten Situation, dass man die Hupe benutzt?', '', '', '', 'Чи поведінка пішохода у цій ситуації вимагає від Вас застосування звукового сигналу?', '', '', ''),
(106, 1145, 'Zamierzasz skręcić w lewo. Czy w tej sytuacji masz pierwszeństwo przed pojazdem nadjeżdżającym z prawej strony?', '', '', '', 'N', '540.D28KW_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1145.wmv', '', '', '', 'You intend to turn left. Do you have the right of way over the vehicle approaching from the right in this situation?', '', '', '', 'Sie möchten links abbiegen. Haben Sie in dieser Situation die Vorfahrt vor dem von rechts kommenden Fahrzeug?', '', '', '', 'Ви збираєтеся повернути вліво. Чи маєте Ви в цій ситуації перевагу перед транспортним засобом, що наближається справа?', '', '', ''),
(107, 1146, 'Czy masz obowiązek ustąpić pierwszeństwa pojazdowi szynowemu, który wyjeżdża z pętli?', '', '', '', 'N', '544.D28KW_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1146.wmv', '', '', '', 'A rail vehicle is emerging onto the road from a terminus. Are you obliged to yield the right of way?', '', '', '', 'Ein Schienenfahrzeug kommt aus der Wendeschleife auf die Fahrbahn heraus. Sind Sie dazu verpflichtet, ihm Vorrang zu geben?', '', '', '', 'Чи зобов\'язані Ви уступити дорогу рейковому транспортному засобу, який виїжджає з розворотного кільця?', '', '', ''),
(108, 1148, 'Zamierzasz jechać na wprost, a kierujący tramwajem planuje skręcić w lewo. Czy masz przed nim pierwszeństwo?', '', '', '', 'N', '546.D28KW_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1148.wmv', '', '', '', 'You intend to drive straight ahead and the tram driver intends to turn left. Have you got priority over him?', '', '', '', 'Sie haben vor, geradeaus zu fahren und der Straßenbahnführer plant, links abzubiegen. HabenSie die Vorfahrt vor der Straßenbahn?', '', '', '', 'Ви маєте намір їхати прямо, а водій трамвая планує повернути вліво. Чи маєте Ви перевагу у русі перед ним?', '', '', ''),
(109, 1153, 'Zamierzasz skręcić w lewo. Czy masz obowiązek ustąpić pierwszeństwa pojazdowi nadjeżdżającemu z prawej strony?', '', '', '', 'T', '607.D29org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1153.wmv', '', '', '', 'You intend to turn left. Are you obliged to yield the right of way to the vehicle approaching from the right?', '', '', '', 'Sie haben vor, links abzubiegen. Haben Sie die Pflicht, dem von rechts kommenden Fahrzeug die Vorfahrt zu geben?', '', '', '', 'Ви збираєтеся повернути вліво. Чи зобов\'язані Ви уступити дорогу транспортному засобу, що наближається справа?', '', '', ''),
(110, 1157, 'Kierujesz pojazdem na obszarze zabudowanym. Czy w tej sytuacji użycie sygnału dźwiękowego jest zabronione?', '', '', '', 'N', '610.D29GMorg.mp4', 'PODSTAWOWY', 1, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1157.wmv', '', '', '', 'You are driving a vehicle in the built-up area. Is it prohibited in the presented situation to use the horn?', '', '', '', 'Sie lenken ein Fahrzeug in geschlossener Ortschaft. Ist es in dieser Situation verboten, die Hupe zu benutzen?', '', '', '', 'Ви керуєте транспортним засобом у населеному пункті. Чи заборонено в цій ситуації застосовувати звуковий сигнал?', '', '', ''),
(111, 1158, 'Zamierzasz jechać na wprost. Czy masz pierwszeństwo przed pojazdem szynowym skręcającym w prawo do zajezdni ?', '', '', '', 'N', '614.D29GMorg.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1158.wmv', '', '', '', 'You intend to continue driving straight on. Do you have the right of way over a rail vehicle turning right, into the depot?', '', '', '', 'Sie möchten weiter geradeaus fahren und das Schienenfahrzeug biegt rechts zum Straßenbahndepot ab. Haben Sie vor dem Schienenfahrzeug die Vorfahrt?', '', '', '', 'Ви їдете прямо. Чи маєте Ви перевагу у русі перед рейковим транспортним засобом, що повертає вправо у депо?', '', '', ''),
(112, 1162, 'Zamierzasz wjechać na drogę twardą skręcając w prawo. Czy masz pierwszeństwo przed pojazdem nadjeżdżającym z lewej strony?', '', '', '', 'N', '627.D33_2org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1162.wmv', '', '', '', 'You intend to drive into a hardened road by turning right. Do you have the right of way over the vehicle approaching from the left?', '', '', '', 'Sie möchten beim Abbiegen nach rechts auf eine befestigte Straße kommen. Haben Sie den Vorrang vor dem Fahrzeug, das von links kommt?', '', '', '', 'Ви маєте намір виїхати на дорогу з твердим покриттям, повертаючи вправо. Чи Ви маєте перевагу перед транспортним засобом, що наближається зліва?', '', '', ''),
(113, 1163, 'Zamierzasz jechać na wprost. Czy masz obowiązek ustąpić pierwszeństwa pojazdowi nadjeżdżającemu z lewej strony?', '', '', '', 'T', '774. RONDO_12org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1163.wmv', '', '', '', 'You intend to go straight ahead. Are you obliged to yield the right of way to the vehicle approaching from the left?', '', '', '', 'Sie haben vor, geradeaus zu fahren. Haben Sie die Pflicht, dem von links kommenden Fahrzeug die Vorfahrt zu geben?', '', '', '', 'Ви маєте намір їхати прямо. Чи Ви зобов\'язані дати дорогу транспортному засобу, що наближається зліва?', '', '', ''),
(114, 1169, 'Zamierzasz skręcić w lewo. Czy masz pierwszeństwo przed pojazdem szynowym nadjeżdżającym z przeciwka?', '', '', '', 'N', '635.D33_org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1169.wmv', '', '', '', 'You intend to turn left. Do you have the right of way before the rail vehicle approaching from the opposite direction?', '', '', '', 'Sie möchten nach links abbiegen. Haben Sie die Vorfahrt vor dem entgegenkommenden Schienfahrzeug?', '', '', '', 'Ви збираєтеся повернути вліво. Чи маєте Ви перевагу перед рейковим транспортним засобом, що рухається з зустрічного напрямку?', '', '', ''),
(115, 1171, 'Zamierzasz skręcić w prawo. Czy masz obowiązek ustąpić pierwszeństwa pojazdowi nadjeżdżającemu z lewej strony?', '', '', '', 'T', '636.D33org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1171.wmv', '', '', '', 'You intend to turn right. Are you obliged to yield the right of way to the vehicle approaching form the left?', '', '', '', 'Sie haben  vor, rechts abzubiegen. Haben Sie die Pflicht, dem von links kommenden Fahrzeug die Vorfahrt zu geben?', '', '', '', 'Ви збираєтеся повернути вправо. Чи зобов\'язані Ви дати дорогу транспортному засобу, що наближається зліва?', '', '', ''),
(116, 1172, 'Zamierzasz jechać na wprost. Czy masz obowiązek ustąpić pierwszeństwa pojazdowi nadjeżdżającemu z prawej strony?', '', '', '', 'N', '638.D33org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1172.wmv', '', '', '', 'You intend to go straight ahead. Are you obliged to yield the right of way to the vehicle approaching from the right?', '', '', '', 'Sie haben vor, geradeaus zu fahren. Haben Sie die Pflicht, dem von rechts kommenden Fahrzeug die Vorfahrt zu geben?', '', '', '', 'Ви маєте намір їхати прямо. Чи зобов\'язані Ви дати дорогу транспортному засобу, що наближається з правого боку?', '', '', ''),
(117, 1178, 'Czy w tej sytuacji masz pierwszeństwo przed zawracającym pojazdem?', '', '', '', 'N', '640.D33org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1178.wmv', '', '', '', 'Have you got priority over the vehicle making a U-turn in this situation?', '', '', '', 'Haben Sie in der dargestellten Situation vor dem wendenden Fahrzeug die Vorfahrt?', '', '', '', 'Чи у зображеній ситуації Ви маєте перевагу перед транспортним засобом, що розвертається?', '', '', ''),
(118, 1179, 'Czy w tej sytuacji masz pierwszeństwo przed pojazdem jadącym na wprost przez skrzyżowanie?', '', '', '', 'N', '641.D33org.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1179.wmv', '', '', '', 'Have you got priority in this situation before the vehicle going ahead across the junction?', '', '', '', 'Haben Sie in dieser Situation die Vorfahrt vor dem Fahrzeug, das geradeaus die Kreuzung überquert?', '', '', '', 'Чи маєте Ви в цій ситуації перевагу перед транспортним засобом, що рухається прямо через перехрестя?', '', '', ''),
(119, 1181, 'Czy w tej sytuacji, poza obszarem zabudowanym, dozwolone jest wyprzedzenie z prawej strony jadącego przed Tobą pojazdu?', '', '', '', 'T', 'D26_144org.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,AM,A1,A2,B1,C1,D1', 'pjm1181.wmv', '', '', '', 'You are outside a built-up area. Are you allowed in this situation to overtake the preceding vehicle from the right?', '', '', '', 'Ist außerhalb geschlossener Ortschaft das Überholen rechts des vor Ihnen fahrenden Fahrzeugs erlaubt?', '', '', '', 'Чи в даній ситуації, поза населеним пунктом, Ви маєте право на обгін з правого боку транспортного засобу, що рухається попереду?', '', '', ''),
(120, 1202, 'Czy w przedstawionej sytuacji jesteś ostrzegany o opadach śniegu?', '', '', '', 'N', 'IMG_6220d8org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1202.wmv', '', '', '', 'Are you warned in this situation of a snowfall?', '', '', '', 'Wirst du in der abgebildeten Situation vor dem Schneefall gewarnt?', '', '', '', 'Чи попереджають Вас про снігопад у наведеній ситуації?', '', '', ''),
(121, 1203, 'Czy w przedstawionej sytuacji jesteś ostrzegany o częstym występowaniu zablokowania ruchu pojazdów (korka)?', '', '', '', 'T', 'A-33 (5)org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm1203.wmv', '', '', '', 'Are you warned in this situation of frequent occurrence of traffic jams?', '', '', '', 'Wirst du in der abgebildeten Situation davor gewarnt, dass der Fahrzeugverkehr oft blockiert wird (Stauvorkommen)?', '', '', '', 'Чи попереджають Вас у наведеній ситуації про часті затори в дорожньому русі?', '', '', ''),
(122, 1252, 'Kierując motocyklem, uczestniczysz w wypadku drogowym, w którym jest ranny. Czy obowiązuje Cię zakaz usuwania pojazdu z miejsca wypadku?', '', '', '', 'T', 'img_4604zz.jpg', 'PODSTAWOWY', 1, 'A,A1,A2', '', '', '', '', 'When riding a motorcycle you participate in a road accident in with a person got injured. Do you need to abide by the prohibition to remove the vehicle from the scene of the accident?', '', '', '', 'Als Motorradfahrer sind Sie an einem Verkehrsunfall beteiligt, in dem es einen Verletzten gibt. Gilt für Sie das Verbot, das Fahrzeug von der Unfallstelle zu entfernen?', '', '', '', '', '', '', ''),
(123, 1258, 'Czy w tej sytuacji masz obowiązek przesunąć uszkodzony motocykl na pobocze drogi?', '', '', '', 'T', '0590D14MM_motocyklorgbm.jpg', 'PODSTAWOWY', 1, 'A,A1,A2', '', '', '', '', 'Should you move the damaged motorcycle onto the hard shoulder in this situation?', '', '', '', 'Ist in dieser Situation das beschädigte Motorrad auf den Randstreifen zu schieben?', '', '', '', '', '', '', ''),
