(1078, 6119, 'Czy w tej sytuacji masz obowiązek ustąpienia pierwszeństwa pojazdowi nadjeżdżającemu z przeciwka?', '', '', '', 'T', '1A4228.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm6119.wmv', '', '', '', 'In this situation, are you obliged to give the right of way to the vehicle approaching from the opposite direction?', '', '', '', 'Sind Sie in dieser Situation verpflichtet, dem entgegenkommenden Fahrzeug die Vorfahrt zu gewähren?', '', '', '', 'Чи зобов\'язані Ви в цій ситуації дати дорогу зустрічному транспортному засобу?', '', '', ''),
(1079, 6120, 'Czy w tej sytuacji możesz wjechać za sygnalizator, jeśli zatrzymanie wymagałoby gwałtownego hamowania?', '', '', '', 'T', '1A4301.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm6120.wmv', '', '', '', 'In this situation, can you drive past the traffic lights, if stopping in front of the lights would require rapid braking?', '', '', '', 'Dürfen Sie in dieser Situation hinter die Ampel einfahren, wenn das Anhalten vor ihr ein scharfes Bremsen erfordern würde?', '', '', '', 'Чи можна в цій ситуації проїхати на жовтий сигнал світлофора, якщо зупинка вимагала б від Вас різкого гальмування?', '', '', '');
INSERT INTO `pula_pytan` (`ID`, `nr_pyt`, `pyt`, `odp_a`, `odp_b`, `odp_c`, `poprawna`, `media`, `zakres`, `pkt`, `kategorie`, `media_migowy_pyt`, `media_migowy_odp_a`, `media_migowy_odp_b`, `media_migowy_odp_c`, `pyt_en`, `odp_a_en`, `odp_b_en`, `odp_c_en`, `pyt_de`, `odp_a_de`, `odp_b_de`, `odp_c_de`, `pyt_ua`, `odp_a_ua`, `odp_b_ua`, `odp_c_ua`) VALUES
(1080, 6121, 'Czy w tej sytuacji, skręcając w prawo, masz obowiązek ustąpić pierwszeństwa pieszemu?', '', '', '', 'T', '1A4302.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm6121.wmv', '', '', '', 'Turning right in this situation, must you give right of way to the pedestrian?', '', '', '', 'Sollen Sie in dieser Situation beim Rechtsabbiegen dem Fußgänger den Vorrang gewähren?', '', '', '', 'Чи зобов\'язані Ви, в даній ситуації, при повороті вправо дати дорогу пішоходу?', '', '', ''),
(1081, 6123, 'Czy w tej sytuacji wolno Ci skręcić w prawo na skrzyżowaniu bez zatrzymania się przed sygnalizatorem?', '', '', '', 'N', '1A4305.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In this situation, can you unconditionally turn right at the intersection?', '', '', '', 'Dürfen Sie in dieser Situation an der Kreuzung nach rechts abbiegen, ohne vor der Ampel anzuhalten?', '', '', '', 'Чи дозволено Вам, у цій ситуації, повернути на перехресті вправо, не зупиняючись на світлофорі?', '', '', ''),
