(3100, 11269, 'Czy zawsze masz obowiązek zatrzymać się przed tym przejazdem?', '', '', '', 'T', '!RS_Przejazd kolejowy Uwieliny.jpg', 'PODSTAWOWY', 3, 'AM', '', '', '', '', 'Are you always obliged to stop before this crossing?', '', '', '', 'Sollen Sie vor diesem Übergang immer anhalten?', '', '', '', '', '', '', ''),
(3101, 11270, 'Czy w przedstawionej sytuacji wjeżdżasz na przejazd kolejowy wielotorowy?', '', '', '', 'T', '!RS_Przejazd kolejowy Uwieliny.jpg', 'PODSTAWOWY', 3, 'AM', '', '', '', '', 'In this situation, are you driving into a multi-track level crossing?', '', '', '', 'Fahren Sie in dieser Situation auf einen mehrgleisigen Bahnübergang ein?', '', '', '', '', '', '', ''),
(3102, 11271, 'Czy w przedstawionej sytuacji dojeżdżasz do przejazdu kolejowego jednotorowego?', '', '', '', 'N', '!RS_Przejazd kolejowy Uwieliny.jpg', 'PODSTAWOWY', 3, 'AM', '', '', '', '', 'In the situation presented, are you arriving at a single-track crossing?', '', '', '', 'Kommen Sie in dieser Situation an einen eingleisigen Bahnübergang?', '', '', '', '', '', '', ''),
(3103, 11274, 'Czy za najbliższym widocznym znakiem ruch pojazdów odbywa się tylko w jednym kierunku?', '', '', '', 'N', '!RS_Droga bez przejazdu.jpg', 'PODSTAWOWY', 1, 'AM', '', '', '', '', 'Does vehicle traffic move in only one direction beyond the nearest visible sign?', '', '', '', 'Erfolgt der Fahrzeugverkehr hinter diesem Zeichen nur in einer Richtung?', '', '', '', '', '', '', ''),
(3104, 11307, 'Jak można zminimalizować zagrożenie kierując pojazdem podczas gęstej mgły?', 'Zwiększyć prędkość.', 'Zwiększyć odległość od poprzedzającego pojazdu.', 'Zmniejszyć odległość od poprzedzającego pojazdu.', 'B', 'mgla3-ztPIC.jpg', 'SPECJALISTYCZNY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'How can the danger of driving a vehicle in heavy fog be minimised?', 'Increase speed.', 'Increase the distance between you and the preceding vehicle.', 'Reduce the distance between you and the preceding vehicle.', 'Wie lässt sich das Risiko beim Fahren im dichten Nebel minimieren?', 'Durch Geschwindigkeitserhöhung.', 'Durch Vergrößerung der Distanz zum vorausfahrenden Fahrzeug.', 'Durch Reduzierung der Distanz zum vorausfahrenden Fahrzeug.', 'Як мінімізувати небезпеку під час руху в густому тумані?', 'Збільшити швидкість.', 'Збільшити відстань до автомобіля попереду.', 'Зменшити відстань до автомобіля, що їде попереду.'),
(3105, 11309, 'Jakie negatywne skutki dla kierującego pojazdem może powodować zaśnieżenie lub oblodzenie jezdni?', 'Zwiększenie przyczepności opon do jezdni.', 'Zmniejszenie  przyczepności opon do jezdni.', 'Skrócenie drogi hamowania.', 'B', 'sniegidroga1-ztPIC.jpg', 'SPECJALISTYCZNY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'What negative effects can snow or ice on the roadway have on the driver?', 'Increased tyre grip on the road.', 'Reduced tyre grip on the road.', 'Reduced braking distance.', 'Welche negativen Folgen für den Fahrer kann eine Schneeschicht bzw. Vereisung der Straße haben?', 'Erhöhung der Reifenadhäsion auf der Straße.', 'Minderung der Reifenadhäsion auf der Straße.', 'Verkürzung des Bremsweges.', 'Які негативні наслідки для водія може мати засніжена дорога або ожеледиця на дорозі?', 'Збільшення зчеплення шин з дорогою.', 'Зменшення зчеплення шин з дорогою.', 'Скорочення гальмівного шляху.'),
(3106, 11310, 'Jakie negatywne skutki dla kierującego pojazdem może powodować zaśnieżenie lub oblodzenie jezdni?', 'Zwiększone ryzyko poślizgu.', 'Zwiększenie przyczepności opon do jezdni.', 'Skrócenie drogi hamowania.', 'A', 'sniegidroga2-ztPIC.jpg', 'SPECJALISTYCZNY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'What negative effects can snow or ice on the roadway have on the driver?', 'Increased risk of skidding.', 'Increased tyre grip on the road.', 'Reduced braking distance.', 'Welche negativen Folgen für den Fahrer kann eine Schneeschicht bzw. Vereisung der Straße haben?', 'Erhöhtes Schleuderrisiko.', 'Erhöhung der Reifenadhäsion auf der Straße.', 'Verkürzung des Bremsweges.', 'Які негативні наслідки для водія може мати засніжена дорога або ожеледиця на дорозі?', 'Підвищений ризик ковзання і заносу.', 'Збільшення зчеплення шин з дорогою.', 'Скорочення гальмівного шляху.'),
(3107, 11314, 'Jakie zachowanie zwiększa ryzyko wpadnięcia w poślizg na oblodzonej nawierzchni jezdni?', 'Nagłe intensywne hamowanie.', 'Hamowanie silnikiem.', 'Jazda ze stałą prędkością.', 'A', 'sniegidroga1-ztPIC.jpg', 'SPECJALISTYCZNY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'What behaviour increases the risk of skidding on icy road surfaces?', 'Sudden hard braking.', 'Engine braking.', 'Driving at constant speed.', 'Welches Verhalten erhöht das Schleuderrisiko auf vereister Fahrbahn?', 'abruptes, intensives Bremsen', 'Motorbremsen', 'Fahrt mit konstanter Geschwindigkeit', 'Яка поведінка підвищує ризик заносу на зледенілому дорожньому покритті?', 'Раптове інтенсивне гальмування.', 'Гальмування двигуном.', 'Рух з постійною швидкістю.'),
(3108, 11315, 'Jakie zachowanie zwiększa ryzyko wpadnięcia w poślizg na oblodzonej nawierzchni jezdni?', 'Jazda na trzecim biegu.', 'Nagłe zwiększenie prędkości.', 'Zmiana biegu na niższy.', 'B', 'sniegidroga2-ztPIC.jpg', 'SPECJALISTYCZNY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'What behaviour increases the risk of skidding on icy road surfaces?', 'Driving in third gear.', 'Sudden speed increase.', 'Changing to a lower gear.', 'Welches Verhalten erhöht das Schleuderrisiko auf vereister Fahrbahn?', 'Fahrt im dritten Gang', 'abrupte Beschleunigung', 'Gangschaltung auf einen niedrigeren Gang', 'Яка поведінка підвищує ризик заносу на зледенілому дорожньому покритті?', 'Рух на третій передачі.', 'Раптове збільшення швидкості.', 'Перехід на нижчу передачу.'),
(3109, 11316, 'Jakie zachowanie zwiększa ryzyko wpadnięcia w poślizg na oblodzonej nawierzchni jezdni?', 'Jazda ze stałą prędkością.', 'Hamowanie silnikiem.', 'Gwałtowne skręcenie kierownicy.', 'C', 'sniegidroga3-ztPIC.jpg', 'SPECJALISTYCZNY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'What behaviour increases the risk of skidding on icy road surfaces?', 'Driving at constant speed.', 'Engine braking.', 'Violent turning of the steering wheel.', 'Welches Verhalten erhöht das Schleuderrisiko auf vereister Fahrbahn?', 'Fahrt mit konstanter Geschwindigkeit', 'Motorbremsen', 'abrupte Drehung des Lenkrads', 'Яка поведінка підвищує ризик заносу на зледенілому дорожньому покритті?', 'Рух з постійною швидкістю.', 'Гальмування двигуном.', 'Різкий поворот керма.'),
(3110, 11317, 'Jakie zachowanie zwiększa ryzyko wpadnięcia w poślizg na oblodzonej nawierzchni jezdni?', 'Utrzymanie zbyt wysokiej prędkości, zwłaszcza na zakręcie.', 'Jazda ze stałą prędkością.', 'Jazda na drugim biegu.', 'A', 'sniegidroga2-ztPIC.jpg', 'SPECJALISTYCZNY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'What behaviour increases the risk of skidding on icy road surfaces?', 'Maintaining too high speed, particularly in bends.', 'Driving at constant speed.', 'Driving in second gear.', 'Welches Verhalten erhöht das Schleuderrisiko auf vereister Fahrbahn?', 'Einhaltung zu hoher Geschwindigkeit, besonders in einer Kurve', 'Fahrt mit konstanter Geschwindigkeit', 'Fahrt im zweiten Gang', 'Яка поведінка підвищує ризик заносу на зледенілому дорожньому покритті?', 'Занадто висока швидкість, особливо на поворотах.', 'Рух з постійною швидкістю.', 'Рух на другій передачі.'),
(3111, 11402, 'Czy za tym znakiem dozwolone jest wyprzedzanie rowerzysty?', '', '', '', 'T', 'znak_A-25-ztPIC.jpg', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Is it allowed beyond this sign to overtake a cyclist?', '', '', '', 'Darf man hinter diesem Zeichen einen Radfahrer überholen?', '', '', '', 'Чи можна, після проїзду цього знака, обганяти велосипедиста?', '', '', ''),
(3112, 11408, 'Czy w tej sytuacji kierujący omijając pojazd powinien w razie potrzeby zmniejszyć prędkość?', '', '', '', 'T', '10am.JPG', 'PODSTAWOWY', 2, 'AM', '', '', '', '', 'In this situation, should the driver pass the vehicle and reduce speed if necessary?', '', '', '', 'Soll in der Situation der das Fahrzeug umfahrende Fahrer ggf. seine Geschwindigkeit reduzieren?', '', '', '', '', '', '', ''),
(3113, 11409, 'Czy w tej sytuacji powinieneś założyć, że zza pojazdu wykonującego roboty drogowe, może niespodziewanie na jezdnię wejść osoba wykonująca prace remontowe?', '', '', '', 'T', '7am.JPG', 'PODSTAWOWY', 2, 'AM', '', '', '', '', 'In this situation, should you assume that a road worker may unexpectedly step onto the road from behind a vehicle undertaking road repair work?', '', '', '', 'Sollen Sie in der Situation annehmen, dass hinter einem Servicewagen, der die Straßenarbeiten ausführt, ein Straßenarbeiter unerwartet auf die Straße kommen kann?', '', '', '', '', '', '', ''),
(3114, 11412, 'Czy w tej sytuacji jesteś zwolniony z obowiązku stosowania wobec dzieci zasady ograniczonego zaufania, gdyż są one pod opieką osoby dorosłej?', '', '', '', 'N', '12am.JPG', 'PODSTAWOWY', 2, 'AM', '', '', '', '', 'In this situation, are you exempt from the obligation to apply a cautious approach to children, because they are in the care of an adult?', '', '', '', 'Sind Sie in dieser Situation von der Pflicht freigestellt, gegenüber den Kindern das Prinzip des begrenzten Vertrauens anzuwenden, da sie unter Aufsicht eines Erwachsenen sind?', '', '', '', '', '', '', ''),
(3115, 11413, 'Czy w tej sytuacji powinieneś uważnie obserwować pieszych, a wobec dzieci zastosować zasadę ograniczonego zaufania?', '', '', '', 'T', '15am.JPG', 'PODSTAWOWY', 2, 'AM', '', '', '', '', 'In this situation, should you keep a close eye on pedestrians and adopt a cautious approach towards children?', '', '', '', 'Sollen Sie in dieser Situation die Fußgänger aufmerksam beobachten und den Kindern gegenüber das Prinzip des begrenzten Vertrauens anwenden?', '', '', '', '', '', '', ''),
(3116, 11415, 'Czy w tej sytuacji kierujący pojazdem powinien przewidywać, że zza pojazdu może nagle wybiec na jezdnię dziecko?', '', '', '', 'T', '23am.JPG', 'PODSTAWOWY', 2, 'AM', '', '', '', '', 'In this situation, should the driver anticipate that a child might suddenly run onto the road from behind the vehicle?', '', '', '', 'Soll in der Situation der Fahrer voraussehen, dass hinter dem Fahrzeug ein Kind plötzlich auf die Straße laufen kann?', '', '', '', '', '', '', ''),
(3117, 11417, 'Czy kierowanie motorowerem w stanie po użyciu alkoholu lub środka działającego podobnie do alkoholu jest zawsze zabronione?', '', '', '', 'T', '', 'PODSTAWOWY', 2, 'AM', '', '', '', '', 'Is it always prohibited to drive a moped under the influence of alcohol or substances of similar effect to alcohol?', '', '', '', 'Ist das Führen eines Mopeds nach dem Alkoholkonsum bzw. Konsum eines dem Alkohol ähnlich wirkenden Mittels immer verboten?', '', '', '', '', '', '', ''),
(3118, 11418, 'Czy alkohol powoduje u kierującego motorowerem nadmierną pewność siebie prowadzącą do brawury na drodze oraz zaburza ocenę odległości i wydłuża czas reakcji?', '', '', '', 'T', '', 'PODSTAWOWY', 2, 'AM', '', '', '', '', 'Does alcohol induce excessive self-confidence in a moped driver, which leads to bravado on the road as well as impairs distance assessment and increases reaction time?', '', '', '', 'Verursacht der Alkohol beim Mopedfahrer Überheblichkeit, die zum Leichtsinn auf der Straße führt und die Einschätzung der Abstände stört sowie die Reaktionszeit verlängert?', '', '', '', '', '', '', ''),
(3119, 11419, 'Czy spożycie alkoholu przez kierującego pogarsza zdolność do prawidłowej oceny ryzyka na drodze podczas jazdy czterokołowcem?', '', '', '', 'T', '', 'PODSTAWOWY', 2, 'AM', '', '', '', '', 'Does consumption of alcohol by a driver impair the ability to correctly assess risks on the road when driving a quadricycle?', '', '', '', 'Verschlechtert der Alkoholkonsum durch den Quadfahrer die richtige Risikoeinschätzung beim Fahren mit dem Quad im Verkehr?', '', '', '', '', '', '', ''),
(3120, 11420, 'Czy powinieneś powstrzymać się od kierowania motorowerem, jeżeli zażyłeś leki, o których nie masz wiedzy lub informacji, jaki mają wpływ na organizm i bezpieczne kierowanie pojazdami?', '', '', '', 'T', '', 'PODSTAWOWY', 2, 'AM', '', '', '', '', 'Should you refrain from driving a moped if you have taken medication of which you have no knowledge or information about how it affects the body and safe driving?', '', '', '', 'Sollten Sie vom Fahren mit dem Moped absehen, falls Sie Arzneimittel eingenommen haben, von denen Sie nicht wissen, welchen Einfluss sie auf Ihren Körper und eine sichere Führung der Fahrzeuge haben?', '', '', '', '', '', '', ''),
(3121, 11422, 'Czego nie należy robić oceniając stan świadomości poszkodowanego?', 'Polewać mu twarzy wodą.', 'Sprawdzać czy reaguje na głos.', 'Lekko potrząsać za barki.', 'A', '5D116.jpg', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11422.wmv', 'pjm11422a.wmv', 'pjm11422b.wmv', 'pjm11422c.wmv', 'What should you not do when assessing whether an accident victim is conscious or not?', 'Pour water on his face.', 'Check if he reacts to your voice.', 'Gently shake him by the shoulders.', 'Was ist bei der Beurteilung des Bewusstseinszustandes eines Verletzten nicht zu tun?', 'Sein Gesicht mit Wasser begießen.', 'Prüfen, ob er auf das Ansprechen reagiert.', 'Leicht an den Schultern schütteln.', 'Чого не слід робити, оцінюючи стан свідомості постраждалого?', 'Поливати йому обличчя водою.', 'Перевіряти, чи реагує на голос.', 'Легко трясти за плечі.'),
(3122, 11425, 'Co należy wykonać w pierwszej kolejności podczas wycieku substancji niebezpiecznych z pojazdu?', 'Ratować życie i zdrowie ludzi.', 'Chronić przed skażeniem wody gruntowe.', 'Powstrzymać wyciek substancji niebezpiecznych.', 'A', '5D123.jpg', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11425.wmv', 'pjm11425a.wmv', 'pjm11425b.wmv', 'pjm11425c.wmv', 'What is the first thing you should do in case of leakage of dangerous substances from a vehicle?', 'Save life and health of people.', 'Protect groundwater from contamination.', 'Prevent the leakage of dangerous substances.', 'Was soll man als Erstes machen, wenn vom Fahrzeug gefährliche Stoffe auslaufen?', 'Das Leben und die Gesundheit der Menschen retten.', 'Grundwasser vor Verseuchung schützen.', 'Auslauf der gefährlichen Stoffe stoppen.', 'Що потрібно зробити в першу чергу під час витоку небезпечної речовини з транспортного засобу?', 'Рятувати життя та здоров’я людей.', 'Захищати від забруднення ґрунтові води.', 'Зупинити витік небезпечної речовини.'),
(3123, 11426, 'Którą z wymienionych służb powiadomisz, aby podjęła akcję ratowniczą, polegającą na neutralizacji substancji niebezpiecznej na drodze?', 'Policję.', 'Inspekcję Transportu Drogowego.', 'Państwową Straż Pożarną.', 'C', '5D124.jpg', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11426.wmv', 'pjm11426a.wmv', 'pjm11426b.wmv', 'pjm11426c.wmv', 'Which of the following authorities will you call in order to commence rescue operations consisting of neutralization of dangerous substances on the road?', 'The Police.', 'The Road Transport Inspectorate.', 'The State Fire Brigade.', 'Welchen von den genannten Diensten werden Sie alarmieren, damit er eine Rettungsaktion durchführt und den gefährlichen Stoff auf der Straße neutralisiert?', 'Policja. (Polizei)', 'Inspekcja Transportu Drogowego (Überwachung des Straßentransports).', 'Państwowa Straż Pożarna.(Staatliche Feuerwehr)', 'Яку з перелічених служб слід повідомити для проведення рятувальної операції з нейтралізації небезпечної речовини на дорозі?', 'Поліцію', 'Інспекцію транспортного дорожнього нагляду', 'Державну пожежну службу'),
(3124, 11427, 'Czy możesz samodzielnie gasić pożar cysterny przewożącej benzynę?', 'Tak.', 'Nie.', 'Tak, ale tylko gaśnicą proszkową.', 'B', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11427.wmv', 'pjm11427a.wmv', 'pjm11427b.wmv', 'pjm11427c.wmv', 'Can you extinguish fire from a cistern transporting gasoline, by yourself?', 'Yes.', 'No.', 'Yes, only by means of a powder extinguisher.', 'Können Sie selbst den Brand eines mit Benzin beladenen Tankwagens löschen?', 'Ja.', 'Nein.', 'Ja, aber nur mit einem Pulverfeuerlöscher.', 'Чи можна самостійно гасити пожежу цистерни, яка  перевозить бензин?', 'Так', 'Ні', 'Так, але виключно за допомогою вогнегасника порошкового типу'),
(3125, 11428, 'Pod który z podanych numerów telefonu należy dzwonić, aby zgłosić wypadek drogowy z udziałem pojazdu przewożącego towary niebezpieczne?', '996 lub 1212.', '111 lub 9696.', '112 lub 998.', 'C', '5D126.jpg', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11428.wmv', 'pjm11428a.wmv', 'pjm11428b.wmv', 'pjm11428c.wmv', 'Which of the following numbers must you call in order to report a car accident involving a vehicle transporting dangerous goods?', '996 or 1212.', '111 or 9696.', '112 or 998.', 'Welche von den angegebenen Telefonnummern soll man anrufen, um einen Verkehrsunfall mit einem Fahrzeug, das gefährliche Stoffe befördert, zu melden?', '996 oder 1212.', '111 oder 9696.', '112 oder 998.', 'На який із вказаних номерів телефону слід дзвонити для повідомлення про ДТП з участю транспортного засобу, що перевозить небезпечні вантажі?', '996 або 1212', '111 або 9696', '112 або 998'),
(3126, 11429, 'Czy u poszkodowanego, który omyłkowo połknął substancję żrącą, należy wywołać wymioty?', 'Tak, jak najszybciej.', 'Nie, w żadnym przypadku.', 'Tak, ale tylko w przypadku gdy substancja żrąca była mocno rozcieńczona.', 'B', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11429.wmv', 'pjm11429a.wmv', 'pjm11429b.wmv', 'pjm11429c.wmv', 'If a victim has mistakenly swallowed a caustic substance, should you induce vomiting?', 'Yes, as quickly as possible.', 'No, under no circumstances.', 'Yes, but only if the corrosive substance was highly diluted.', 'Soll man bei einem Betroffenen, der versehentlich eine ätzende Flüssigkeit geschluckt hat, Erbrechen provozieren?', 'Ja, so schnell wie möglich.', 'Nein, auf keinen Fall.', 'Ja, aber nur wenn die ätzende Flüssigkeit stark verdünnt war.', 'Чи потрібно викликати блювоту (рвотний рефлекс) у постраждалого, який випадково проковтнув їдку хімічну речовину?', 'Так, якомога швидше', 'Ні, у жодному разі', 'Так, але лише якщо речовина була сильно розбавлена'),
(3127, 11432, 'Po jakim czasie mózg poszkodowanego, u którego doszło do zatrzymania krążenia umiera?', 'Po ok. 4-5 minutach.', 'Po 20 minutach.', 'Po 1 godzinie.', 'A', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11432.wmv', 'pjm11432a.wmv', 'pjm11432b.wmv', 'pjm11432c.wmv', 'After what time the does the ischemic brain of an accident casualty die?', 'After approx. 4-5 minutes.', 'After 20 minutes.', 'After an hour.', 'Nach welcher Zeit tritt bei einem Verkehrsunfallopfer, dessen Gehirn mit Blut unterversorgt wird, der Gehirntod ein?', 'Nach etwa 4-5 Minuten.', 'Nach 20 Minuten.', 'Nach 1 Stunde.', 'Через який час після зупинки серця мозок постраждалого гине?', 'Приблизно через 4-5 хвилин', 'Через 20 хвилин', 'Через 1 годину'),
(3128, 11433, 'Dlaczego pozycja boczna ustalona jest bezpieczna dla osoby rannej w wypadku drogowym?', 'Ponieważ jest wygodna dla osoby rannej.', 'Ponieważ jest stabilna, zapewnia drożność dróg oddechowych i zabezpiecza osobę ranną przed zachłyśnięciem się.', 'Ponieważ pozwala przeprowadzić ratującemu działania resuscytacyjne.', 'B', '5D160_4.jpg', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11433.wmv', 'pjm11433a.wmv', 'pjm11433b.wmv', 'pjm11433c.wmv', 'The recovery position is deemed safe for the person injured in a road accident because:', 'it is comfortable for the injured person.', 'it is stable, it provides a clear airway and prevents the injured person from choking.', 'it enables the rescuer to perform resuscitation.', 'Eine stabile Seitenlage ist für eine während eines Verkehrsunfalls verletzte Person sicher, weil sie:', 'Für die verletzte Person bequem ist.', 'Stabilisiert und die Durchgängigkeit der Atemwege gewährleistet sowie die verletzte Person vor dem Verschlucken schützt.', 'Dem Nothelfer erlaubt, die Wiederbelebungsmaßnahmen einzuleiten.', 'Чому бічна стабільна позиція вважається безпечною для постраждалого в ДТП?', 'Тому що вона зручна для постраждалого.', 'Тому що це стабільне положення, яке забезпечує прохідність дихальних шляхів і не дає постраждалому захлинутися.', 'Тому що дозволяє рятувальнику проводити реанімаційні дії'),
(3129, 11434, 'Jak długo powinieneś prowadzić masaż serca i sztuczne oddychanie wobec osoby rannej w wypadku?', 'Przez 60 minut.', 'Do momentu odzyskania przez nią oddechu lub przekazania jej ratownikowi medycznemu.', 'Przez 5 minut.', 'B', '5D162_4.jpg', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11434.wmv', 'pjm11434a.wmv', 'pjm11434b.wmv', 'pjm11434c.wmv', 'How long should you perform cardiac massage and artificial respiration to a person injured in an accident?', 'For 60 minutes.', 'Until the person regains their breath or is handed over to a paramedic.', 'For 5 minutes.', 'Wie lange soll man eine Herzdruckmassage und die Mund-zu-Mund-Beatmung bei einer im Verkehrsunfall verletzten Person vornehmen?', '60 Minuten lang.', 'Bis zur Wiedereinsetzung der Atmung und der Übergabe an das medizinische Rettungspersonal.', '5 Minuten lang.', 'Як довго слід проводити масаж серця та штучне дихання постраждалому в ДТП?', 'Протягом 60 хвилин.', 'До моменту відновлення самостійного дихання або до передачі постраждалого бригаді екстреної медичної допомоги.', 'Протягом 5 хвилин.'),
(3130, 11436, 'Jaka jest maksymalna dopuszczalna długość ładunku, który wystaje z przodu pojazdu, licząc od siedzenia dla kierującego?', '2 m.', '1,5 m.', '2,5 m.', 'B', '5A212.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11436.wmv', 'pjm11436a.wmv', 'pjm11436b.wmv', 'pjm11436c.wmv', 'What is the maximum front overhang of a load transported in a motor vehicle, counting from the driver\'s seat?', '2 m.', '1.5 m.', '2.5 m.', 'Wie weit darf Ladung nach vorne über das Fahrzeug hinausragen, gerechnet ab dem Fahrersitz?', '2 m.', '1,5 m.', '2,5 m.', 'Яка максимально допустима довжина вантажу, що виступає спереду транспортного засобу, міряючи від сидіння водія?', '2 м.', '1,5 м.', '2,5 м.'),
(3131, 11437, 'Czy poduszka powietrzna spełni swoją funkcję w czasie wypadku, jeżeli nie zapniesz pasów bezpieczeństwa?', 'Tak, są to dwa niezależne systemy bezpieczeństwa.', 'Nie, zadziałanie poduszki powietrznej narazi Cię na urazy głowy lub kręgosłupa.', 'Tak, poduszka powietrzna zastępuje użycie pasów bezpieczeństwa.', 'B', '5A213.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11437.wmv', 'pjm11437a.wmv', 'pjm11437b.wmv', 'pjm11437c.wmv', 'Will the airbag serve its function during an accident, if you fail to fasten the seatbelts?', 'Yes, they are two independent safety systems.', 'No, if the airbag opens, this will expose you to head or spine injuries.', 'Yes, the airbag substitutes for the use of seat belts.', 'Wird der Airbag seine Funktion bei einem Unfall erfüllen, wenn Sie den Sicherheitsgurt nicht anschnallen?', 'Ja, das sind zwei unabhängige Sicherheitssysteme.', 'Nein, der ausgelöste Airbag wird Sie einer Kopf- oder Wirbelsäule-Verletzung aussetzen.', 'Ja, der Airbag ersetzt den Sicherheitsgurt.', 'Чи виконає подушка безпеки свою функцію під час ДТП, якщо Ви не пристебнули ремені безпеки?', 'Так, це дві незалежні системи безпеки.', 'Ні, спрацювання подушки безпеки може призвести до травм голови чи хребта.', 'Так, подушка безпеки замінює використання ременів безпеки.'),
(3132, 11438, 'Jak jest maksymalna dopuszczalna wysokość pojazdu z ładunkiem?', '3 m.', '3,5 m.', '4 m.', 'C', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11438.wmv', 'pjm11438a.wmv', 'pjm11438b.wmv', 'pjm11438c.wmv', 'The height of a vehicle with a load must not exceed:', '3 m.', '3.5 m.', '4 m.', 'Die Höhe des Fahrzeugs incl. der Ladung darf nicht überschreiten:', '3 m.', '3,5 m.', '4 m.', 'Яка максимально допустима висота транспортного засобу з вантажем?', '3 м.', '3,5 м.', '4 м.'),
(3133, 11440, 'Na rozwinięcie jakiej maksymalnej prędkości pozwala ogranicznik prędkości zamontowany w samochodzie ciężarowym o dopuszczalnej masie całkowitej przekraczającej 3,5 t?', '90 km/h.', '100 km/h.', '120 km/h.', 'A', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11440.wmv', 'pjm11440a.wmv', 'pjm11440b.wmv', 'pjm11440c.wmv', 'The speed limiter fitted in a lorry of gross vehicle weight rating of over 3.5 tons should limit the maximum speed to:', '90 km/h.', '100 km/h.', '120 km/h.', 'Der in einem LKW mit einer zulässigen Gesamtmasse von mehr als 3,5 t eingebaute Geschwindigkeitsbegrenzer sollte auf eine Höchstgeschwindigkeit eingestellt werden von:', '90 km/h.', '100 km/h.', '120 km/h.', 'Яку максимальну швидкість дозволяє розвинути обмежувач швидкості, встановлений на вантажному автомобілі з дозволеною максимальною масою понад 3,5 т?', '90 км/год.', '100 км/год.', '120 км/год.'),
(3134, 11442, 'W ile gaśnic masz obowiązek wyposażyć samochód ciężarowy, którym przewozisz osoby poza kabiną kierowcy?', 'Jedną.', 'Dwie.', 'Trzy.', 'B', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11442.wmv', 'pjm11442a.wmv', 'pjm11442b.wmv', 'pjm11442c.wmv', 'How many fire extinguishers should be fitted in a lorry in which you carry persons outside the driver\'s cab?', 'One.', 'Two.', 'Three.', 'Mit wie vielen Feuerlöschern sollte ein LKW ausgestattet sein, mit dem man Personen außerhalb des Fahrerhauses befördert?', 'Mit einem.', 'Zwei.', 'Drei.', 'Скільки вогнегасників Ви зобов\'язані мати у вантажному автомобілі, яким перевозите людей поза кабіною водія?', 'Один.', 'Два.', 'Три.'),
(3135, 11443, 'Czy masz prawo przewozić samochodem ciężarowym ładunek sypki, gdy wysokość tego pojazdu wraz z ładunkiem wynosi 4,5 m?', 'Tak, ale wyłącznie na autostradzie.', 'Tak, na wszystkich drogach poza obszarem zabudowanym.', 'Nie, jest to zabronione na wszystkich drogach.', 'C', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11443.wmv', 'pjm11443a.wmv', 'pjm11443b.wmv', 'pjm11443c.wmv', 'Are you allowed to carry loose material in a lorry, when the vehicle height together with the load is 4.5 m?', 'Yes, but only on a motorway.', 'Yes, on all roads except in a built-up area.', 'No, it is forbidden on all roads.', 'Ist es gestattet, eine lose Ladung mit einem Lastkraftwagen zu befördern, wenn die Fahrzeughöhe samt Ladung 4,5 m beträgt?', 'Ja, jedoch ausschließlich auf einer Autobahn.', 'Ja, auf allen Straßen außerhalb geschlossener Ortschaft.', 'Nein, das ist auf allen Straßen verboten.', 'Чи маєте Ви право перевозити вантажним автомобілем сипучий вантаж, якщо висота автомобіля разом з вантажем становить 4,5 м?', 'Так, але виключно на автомагістралі.', 'Так, на всіх дорогах поза межами населених пунктів.', 'Ні, це заборонено на всіх дорогах.'),
(3136, 11444, 'Przewozisz samochodem ciężarowym o szerokości 2,55 m ładunek o szerokości 3 m. Na jaką maksymalną odległość może on wystawać z jednej strony pojazdu?', '45 cm.', '25 cm.', '23 cm.', 'C', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11444.wmv', 'pjm11444a.wmv', 'pjm11444b.wmv', 'pjm11444c.wmv', 'You are carrying a load of 3m in width in a lorry of 2.55m in width. How far can the load protrude from one side of the vehicle?', '45 cm.', '25 cm.', '23 cm.', 'Sie befördern mit einem Lastkraftwagen mit einer Breite von 2,55 m eine Ladung, die 3 m breit ist. Wie maximal weit darf diese Ladung über eine Seite des Fahrzeugs hinausragen?', '45 cm.', '25 cm.', '23 cm.', 'Ви перевозите вантажним автомобілем шириною 2,55 м вантаж шириною 3 м. На яку максимальну відстань він може виступати з одного боку транспортного засобу?', '45 см.', '25 см.', '23 см.'),
(3137, 11445, 'Jakiej wartości nie może przekraczać nacisk pojedynczej osi nienapędowej?', '8 ton.', '10 ton.', '7 ton.', 'B', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11445.wmv', 'pjm11445a.wmv', 'pjm11445b.wmv', 'pjm11445c.wmv', 'The pressure on a single non-drive axle must not exceed:', '8 tons.', '10 tons.', '7 tons.', 'Die Belastung einer Einzelachse, die keine Antriebsachse ist, darf nicht höher sein als:', '8 t.', '10 t.', '7 t.', 'Якого значення не може перевищувати навантаження на одиночну неведучу вісь?', '8 тонн.', '10 тонн.', '7 тонн.'),
(3138, 11447, 'Jaki odstęp masz obowiązek zachować, wyprzedzając samochodem ciężarowym inny samochód ciężarowy?', 'Bezpieczny.', 'Co najmniej 1 metr.', 'Co najmniej 2 metry.', 'A', '', 'SPECJALISTYCZNY', 3, 'C', 'pjm11447.wmv', 'pjm11447a.wmv', 'pjm11447b.wmv', 'pjm11447c.wmv', 'When driving a lorry what distance are you obliged to keep while overtaking another lorry?', 'Safe.', 'At least 1 metre.', 'At least 2 metres.', 'Welchen Abstand haben Sie zu halten, wenn Sie mit einem LKW einen anderen LKW überholen möchten?', 'Einen sicheren Abstand.', 'Mindestens 1 m.', 'Mindestens 2 m.', 'Якої дистанції Ви зобов\'язані дотримуватися, обганяючи вантажним автомобілем інший вантажний автомобіль?', 'Безпечну', 'Не менше 1 метра', 'Не менше 2 метрів');
INSERT INTO `pula_pytan` (`ID`, `nr_pyt`, `pyt`, `odp_a`, `odp_b`, `odp_c`, `poprawna`, `media`, `zakres`, `pkt`, `kategorie`, `media_migowy_pyt`, `media_migowy_odp_a`, `media_migowy_odp_b`, `media_migowy_odp_c`, `pyt_en`, `odp_a_en`, `odp_b_en`, `odp_c_en`, `pyt_de`, `odp_a_de`, `odp_b_de`, `odp_c_de`, `pyt_ua`, `odp_a_ua`, `odp_b_ua`, `odp_c_ua`) VALUES
(3139, 11450, 'Który czynnik ma największy wpływ na przyczepność opony samochodu ciężarowego do podłoża?', 'Wielkość opony.', 'Moc silnika pojazdu.', 'Rodzaj i stan nawierzchni jezdni.', 'C', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11450.wmv', 'pjm11450a.wmv', 'pjm11450b.wmv', 'pjm11450c.wmv', 'Which of the following factors has the greatest impact on the grip of the truck tyre to the ground?', 'The size of a tyre.', 'The engine power of a vehicle.', 'The type and condition of the road surface.', 'Welcher der genannten Faktoren übt den größten Einfluss auf den Kraftschluss zwischen einem Lkw-Reifen und der Fahrbahn aus?', 'Größe des Reifens.', 'Leistung des Fahrzeugmotors.', 'Beschaffenheit und Zustand der Fahrbahndecke.', 'Який чинник найбільше впливає на зчеплення шин вантажного автомобіля з дорогою?', 'Розмір шини', 'Потужність двигуна автомобіля', 'Тип і стан дорожнього покриття'),
(3140, 11452, 'Jaki wpływ na skuteczność hamowania samochodu ciężarowego ma przegrzanie hamulców?', 'Może się ona zwiększyć.', 'Może się ona zmniejszyć.', 'Nie zmienia się, niezależnie od stopnia ich przegrzania.', 'B', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11452.wmv', 'pjm11452a.wmv', 'pjm11452b.wmv', 'pjm11452c.wmv', 'With overheating of the brakes the braking performance:', 'may increase.', 'may decrease.', 'does not change, regardless of the degree of overheating.', 'Bei Überhitzung der Fahrzeugbremsen kann die Bremswirkung beim Bremsen eines Lkws:', 'Sich verstärken.', 'Schwächer werden.', 'Unverändert bleiben, unabhängig vom Überhitzungsgrad.', 'Який вплив на ефективність гальмування вантажного автомобіля має перегрів гальм?', 'Ефективність може збільшитися', 'Ефективність може зменшитися', 'Ефективність не змінюється незалежно від ступеня їх перегріву'),
(3141, 11453, 'Jaki wpływ na drogę hamowania ma zbyt duże ciśnienie w ogumieniu samochodu ciężarowego?', 'Może skrócić drogę hamowania.', 'Może wydłużyć drogę hamowania.', 'Nie zmienia długości drogi hamowania.', 'B', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11453.wmv', 'pjm11453a.wmv', 'pjm11453b.wmv', 'pjm11453c.wmv', 'Too high pressure in the lorry tyres:', 'may shorten the braking distance of the vehicle.', 'may lengthen the braking distance of the vehicle.', 'does not change the braking distance of the vehicle.', 'Ein zu hoher Luftdruck in den Reifen eines Lastkraftwagens:', 'Kann den Bremsweg des LKWs verkürzen.', 'Kann den Bremsweg des LKWs verlängern.', 'Ändert die Bremsweglänge des Lkws nicht.', 'Як надмірний тиск у шинах вантажного автомобіля впливає на гальмівний шлях?', 'Може скоротити гальмівний шлях', 'Може подовжити гальмівний шлях', 'Не змінює довжини гальмівного шляху'),
(3142, 11457, 'Kiedy kierując samochodem ciężarowym masz obowiązek wyłączyć tylne światła przeciwmgłowe?', 'Gdy widoczność wzrośnie do 30 m.', 'Gdy widoczność wzrośnie do 40 m.', 'Gdy widoczność wzrośnie do 60 m.', 'C', '5B234.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11457.wmv', 'pjm11457a.wmv', 'pjm11457b.wmv', 'pjm11457c.wmv', 'While driving a truck, when do you have to turn off the rear anti-fog lights?', 'When visibility increases to 30 m.', 'When visibility increases to 40 m.', 'When visibility increases to 60 m.', 'Wann sollen Sie Nebelschlussleuchte ausschalten, wenn Sie einen Lkw führen?', 'Wenn sich die Sichtweite bis 30 m erhöht.', 'Wenn sich die Sichtweite bis 40 m erhöht.', 'Wenn sich die Sichtweite bis 60 m erhöht.', 'Коли під час керування вантажним автомобілем Ви зобов\'язані вимкнути задні протитуманні фари?', 'Коли видимість покращиться до 30 метрів', 'Коли видимість покращиться до 40 метрів', 'Коли видимість покращиться до 60 метрів'),
(3143, 11463, 'Jak należy się zachować w przypadku pomylenia zjazdu na drodze o wzmożonym ruchu?', 'Zatrzymać się przed pierwszą sygnalizacją świetlną, aby zapytać pieszych o dalszą drogę.', 'Podczas nieprzerwanej jazdy sprawdzić na mapie drogę powrotną.', 'Jechać dalej do miejsca, w którym będzie możliwe bezpieczne zatrzymanie pojazdu.', 'C', 'C0338.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11463.wmv', 'pjm11463a.wmv', 'pjm11463b.wmv', 'pjm11463c.wmv', 'How should you behave in the event of missing an exit on a road with heightened traffic?', 'Stop at the next traffic lights to ask pedestrians for further direction.', 'While driving, check for a return road on a road map.', 'Continue driving to a place where can safely stop the vehicle.', 'Wie soll man sich verhalten, falls man die Ausfahrt auf einer verkehrsreichen Straße überfährt?', 'vor der ersten Ampel anhalten, um die Fußgänger nach dem weiteren Weg zu fragen', 'bei ununterbrochenen Fahrt auf der Karte den Rückweg überprüfen', 'weiter bis zu einer Stelle fahren, wo das sichere Anhalten möglich ist', 'Як слід поводитися у разі помилкового пропуску з\'їзду на дорозі з інтенсивним рухом?', 'Зупинитися перед першим світлофором, щоб запитати пішоходів про подальший шлях', 'Під час безперервного руху перевірити на карті зворотний маршрут', 'Продовжувати рух до місця, де можна буде безпечно зупинити транспортний засіб'),
(3144, 11464, 'Jak powinieneś pokonywać zakręty samochodem ciężarowym?', 'Płynnie korygować tor jazdy uwzględniając krzywiznę zakrętu.', 'Pokonywać zakręt z wciśniętym pedałem sprzęgła.', 'Utrzymywać maksymalne obroty silnika na całej długości zakrętu.', 'A', '5B319.jpg', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11464.wmv', 'pjm11464a.wmv', 'pjm11464b.wmv', 'pjm11464c.wmv', 'How should you negotiate a bend when driving a truck?', 'By smoothly adjusting the trajectory, taking the bend into account.', 'By negotiating the bend with the clutch pedal pressed.', 'By maintaining the engine\'s maximum RPM along the whole length of the bend.', 'Wie sollen Sie mit einem Lkw Kurven fahren?', 'Die Fahrlinie sanft korrigieren, unter Berücksichtigung der Kurvenkrümmung.', 'Die Kurve mit gedrucktem Kupplungspedal befahren.', 'Die maximale Umdrehungen des Motors über die ganze Länge der Kurve erhalten.', 'Як слід проходити повороти вантажним автомобілем?', 'Плавно коректувати траєкторію руху з урахуванням форми повороту', 'Проходити поворот із натиснутою педаллю зчеплення', 'Підтримувати максимальні оберти двигуна на всьому протязі повороту'),
(3145, 11467, 'Jaki jest najbardziej efektywny sposób rozpędzania samochodu ciężarowego?', 'Poprzez osiąganie maksymalnych obrotów silnika na kolejnych biegach.', 'Poprzez taką zmianę biegów, by obroty silnika nie były niższe niż wartość rozpoczynająca zielone pole obrotomierza.', 'Poprzez wykorzystanie kolejno wszystkich biegów, nawet jeśli wskaźnik obrotomierza jest na czerwonym polu.', 'B', '5B311.jpg', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11467.wmv', 'pjm11467a.wmv', 'pjm11467b.wmv', 'pjm11467c.wmv', 'What is the most effective method of acceleration in a truck?', 'By reaching the maximum rotations of the engine in all subsequent gears.', 'By changing gears in such a way that the RPM\'s of the engines are not lower than the value at which the green area on the speedometer starts.', 'By using all gears successively, even though the speedometer indicator is in the red area.', 'Wie ist ein Lkw am effektivsten zu beschleunigen?', 'Durch Erreichen der höchsten Drehzahl in den einzelnen Gängen.', 'Durch solche Gangschaltung, dass die Drehzahl nicht niedriger ist als der Wert, mit dem das grüne Feld des Drehzahlmessers beginnt.', 'Durch Schalten in alle Gänge nacheinander, auch wenn der Zeiger des Drehzahlmessers im roten Feld steht.', 'Який спосіб розгону вантажного автомобіля є найефективнішим?', 'Досягаючи максимальних обертів двигуна на кожній передачі', 'Перемикаючи передачі так, щоб оберти двигуна не опускалися нижче значення, що позначає початок зеленого поля тахометра (обертоміра)', 'Використовуючи послідовно всі передачі, навіть якщо стрілка тахометра (обертоміра) знаходиться у червоній зоні'),
(3146, 11469, 'W którym z przypadków używanie tempomatu jest najbardziej uzasadnione?', 'Podczas jazdy po drogach w terenie górzystym.', 'Podczas jazdy w ruchu miejskim.', 'Podczas długotrwałej jazdy ze stałą prędkością.', 'C', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11469.wmv', 'pjm11469a.wmv', 'pjm11469b.wmv', 'pjm11469c.wmv', 'In which of the following cases is the use of a cruise control most justified?', 'While driving on roads in a  mountainous area.', 'While driving in city traffic.', 'While driving for a long time at constant speed.', 'In welchem der genannten Fälle ist der Einsatz eines Tempomaten am meisten begründet?', 'Bei Fahren auf Straßen im gebirgigen Gelände.', 'Beim Fahren im Stadtverkehr.', 'Beim Fahren auf langen Strecken mit konstanter Geschwindigkeit.', 'У якому з випадків використання круїз-контролю є найбільш виправданим?', 'Під час їзди дорогами у гірській місцевості.', 'Під час їзди по місту.', 'Під час тривалої їзди зі сталою швидкістю'),
(3147, 11471, 'Jaką funkcję spełnia system ABS zastosowany w samochodzie ciężarowym?', 'Skraca drogę hamowania w każdych warunkach drogowych.', 'Jest niewrażliwy na rodzaj nawierzchni jezdni.', 'Umożliwia kierowanie pojazdem w czasie hamowania awaryjnego.', 'C', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11471.wmv', 'pjm11471a.wmv', 'pjm11471b.wmv', 'pjm11471c.wmv', 'What is the function of the ABS in a lorry?', 'It shortens the braking distance in all weather conditions.', 'It is insensitive to the type of road surface.', 'It enables driving during emergency braking.', 'Das in einem Lastkraftwagen eingebaute ABS-System:', 'Verkürzt den Bremsweg unter beliebigen Straßenverhältnissen.', 'Wird nicht von der Beschaffenheit der Fahrbahn beeinflusst.', 'Gewährleistet das Fahrzeuglenken bei Notbremsung.', 'Яку функцію виконує система ABS, встановлена у вантажному автомобілі?', 'Скорочує гальмівний шлях за будь-яких дорожніх умов.', 'Не залежить від типу дорожнього покриття.', 'Дозволяє керувати автомобілем під час екстреного гальмування.'),
(3148, 11472, 'Który z wymienionych sposobów hamowania samochodu ciężarowego wyposażonego w system ABS zapewnia najszybsze zatrzymanie pojazdu?', 'Pulsacyjne wciskanie pedału hamulca.', 'Jak najmocniejsze wciśnięcie pedału hamulca i jednoczesne wciśnięcie pedału sprzęgła.', 'Stopniowe wciskanie pedału hamulca.', 'B', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11472.wmv', 'pjm11472a.wmv', 'pjm11472b.wmv', 'pjm11472c.wmv', 'Which of these methods of braking a lorry equipped with an ABS system guarantees the fastest way of stopping the vehicle?', 'Pulse pressing of the brake pedal.', 'Simultaneously pressing the brake and clutch pedals as strong as possible.', 'gradually pressing the brake pedal.', 'Welche von den genannten Bremsmethoden mit einem LkW mit dem ABS-System ermöglicht das schnellste Anhalten des Fahrzeugs?', 'Intervaldrücken des Bremspedals', 'möglichst stärkstes Bremsen und gleichzeitiges Drücken des Kupplungpedals', 'stufenweises Drücken des Bremspedals', 'Який із перерахованих способів гальмування вантажного автомобіля з системою ABS забезпечує найшвидшу зупинку?', 'Імпульсне натискання педалі гальма.', 'Якнайсильніше натискання педалі гальма та одночасне натискання педалі зчеплення.', 'Поступове натискання педалі гальма.'),
(3149, 11474, 'Czy ładunek przewożony samochodem ciężarowym może powodować przekroczenie dopuszczalnej ładowności?', 'Tak, ale nie więcej niż o 20%.', 'Tak, o ile nie zostaną przekroczone dopuszczalne naciski osi na jezdnię.', 'Nie.', 'C', '5C101.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11474.wmv', 'pjm11474a.wmv', 'pjm11474b.wmv', 'pjm11474c.wmv', 'Can a cargo cause a truck to exceed the maximum permissible capacity of the vehicle?', 'Yes, but by no more than 20%.', 'Yes, as long as the permitted axle load on the road is not exceeded.', 'No.', 'Kann durch die mit einem Lkw transportierte Ladung die zulässige Nutzlast überschritten werden?', 'Ja, aber höchstens um 20%.', 'Ja, sofern die zulässigen Achslasten nicht überschritten werden.', 'Nein.', 'Чи може вантаж, що перевозиться вантажним автомобілем, перевищувати його допустиму вантажопідйомність?', 'Так, але не більше ніж на 20%.', 'Так, за умови, що не будуть перевищені допустимі навантаження осі на проїжджу частину.', 'Ні.'),
(3150, 11475, 'W jaki sposób należy umieścić ładunek w samochodzie ciężarowym?', 'Tak, aby nie przekraczał całkowitej szerokości pojazdu.', 'Tak, aby nie wystawał z tyłu na odległość większą niż 1 metr od tylnej płaszczyzny obrysu pojazdu.', 'Tak, aby nie naruszał stateczności pojazdu i nie utrudniał kierowania.', 'C', '5C102.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11475.wmv', 'pjm11475a.wmv', 'pjm11475b.wmv', 'pjm11475c.wmv', 'How should a load be placed in a truck?', 'In a way, so that it does not exceed the total width of the vehicle.', 'In a way, so that it does not overhang at the back for more than 1 meter from the rear outline of the vehicle.', 'In a way, so that it does not affect the stability of the vehicle and does not obstruct driving.', 'Wie soll die Ladung auf dem Fahrzeug verstaut sein?', 'So, dass sie die Gesamtbreite des Fahrzeuges nicht überschreitet.', 'So, dass sie nach hinten nicht mehr als 1 Meter von der hinteren Fläche des Fahrzeugumrisses hinausragt.', 'So, dass die Stabilität des Fahrzeugs nicht gefährdet und die Lenkung nicht erschwert wird.', 'Яким чином слід розміщувати вантаж у вантажному автомобілі?', 'Так, щоб він не перевищував загальну ширину транспортного засобу.', 'Так, щоб не виступав ззаду на відстань більшу ніж 1 метр від задньої площини обрису транспортного засобу.', 'Так, щоб не порушував стабільність транспортного засобу та не утруднював керування ним.'),
(3151, 11476, 'Który sposób oznakowania ładunku wystającego ponad 0,5 m poza tylną płaszczyznę obrysu samochodu ciężarowego jest właściwy?', 'Chorągiewka barwy czerwonej o wymiarach 30 cm x 30 cm.', 'Odblaskowy trójkąt ostrzegawczy.', 'Tarcza z pasami białymi i czerwonymi o łącznej powierzchni nie mniejszej niż 1000 cm2.', 'C', '5C103.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11476.wmv', 'pjm11476a.wmv', 'pjm11476b.wmv', 'pjm11476c.wmv', 'Which of the following methods of marking a load overhanging for more than 0.5 m from the rear outline of the truck is correct?', 'A red flag with the dimensions of 30cm x 30cm.', 'A warning triangle.', 'A plaque with white-and-red stripes with a total surface area of no less than 1000 cm2.', 'Welche von den Kennzeichnungen der Ladung, die mehr als 0,5 m über die hintere Fläche des Fahrzeugumrisses hinausragt, ist richtig?', 'Eine rote Fahne, 30cm x 30cm groß.', 'Ein rückstrahlendes Warndreieck.', 'Ein Schild mit weißen und roten Streifen, mindestens 1000 cm2 groß.', 'Який спосіб позначення вантажу, що виступає більш ніж на 0,5 м за задню площину обрису вантажного автомобіля, є правильним?', 'Червоний прапорець розміром 30 см × 30 см.', 'Відбивний попереджувальний трикутник.', 'Щит з білими та червоними смугами загальною площею не менше ніж 1000 см².'),
(3152, 11477, 'Czy masz prawo kierować samochodem ciężarowym, którego szerokość wraz z ładunkiem jest większa od dopuszczalnej?', 'Tak, bez dodatkowego zezwolenia, jeśli trasa przewozu na to pozwala.', 'Nie, w żadnym przypadku.', 'Tak, ale tylko pod warunkiem uzyskania odpowiedniego zezwolenia.', 'C', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11477.wmv', 'pjm11477a.wmv', 'pjm11477b.wmv', 'pjm11477c.wmv', 'Can you drive a truck whose width, including the cargo, exceeds the maximum permissible width?', 'Yes, without an additional permit, if the route allows it.', 'No, under no circumstances.', 'Yes, but provided you obtain a suitable permit.', 'Dürfen Sie einen Lkw führen, dessen Breite zusammen mit der Landung größer als zulässig ist?', 'Ja, ohne zusätzliche Genehmigung, wenn die Strecke, auf der es befördert wird, dies erlaubt.', 'Nein, auf keinen Fall.', 'Ja, aber nur unter der Voraussetzung, dass eine entsprechende Genehmigung eingeholt wird.', 'Чи Ви маєте право керувати вантажним автомобілем, ширина якого разом із вантажем перевищує допустиму?', 'Так, без додаткового дозволу, якщо маршрут перевезення на це дозволяє.', 'Ні, за жодних обставин.', 'Так, але лише за умови отримання відповідного дозволу.'),
(3153, 11480, 'Czy położenie środka ciężkości ładunku przewożonego samochodem ciężarowym ma wpływ na stateczność pojazdu?', 'Tak, może zmniejszyć stateczność pojazdu.', 'Nie.', 'Tak, ale wyłącznie na ostrych zakrętach.', 'A', '5C110.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11480.wmv', 'pjm11480a.wmv', 'pjm11480b.wmv', 'pjm11480c.wmv', 'Does the location of the centre of gravity of a load transported by a truck affect the stability of the truck?', 'Yes, it may reduce the stability of the vehicle.', 'No.', 'Yes, but only on sharp bends.', 'Hat die Lage des Schwerpunktes der Ladung einen Einfluss auf die Stabilität des Fahrzeugs?', 'Ja, sie kann die Stabilität des Fahrzeugs mindern.', 'Nein.', 'Ja, aber nur in scharfen Kurven.', 'Чи впливає розташування центра ваги вантажу, що перевозиться вантажним автомобілем, на стабільність транспортного засобу?', 'Так, може зменшити стабільність транспортного засобу.', 'Ні.', 'Так, але лише на крутих поворотах.'),
(3154, 11482, 'Czy ładunki płynne w zbiornikach lub cysternach częściowo wypełnionych mogą wpływać na niestabilność pojazdu?', 'Nie, jeśli objętość ładunku nie przekracza połowy zbiornika.', 'Nie.', 'Tak.', 'C', '5C114.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11482.wmv', 'pjm11482a.wmv', 'pjm11482b.wmv', 'pjm11482c.wmv', 'Can a liquid cargo in partly-filled containers or cisterns affect the stability of the vehicle?', 'No, if the volume of the load does not exceed a half of the container.', 'No.', 'Yes.', 'Können flüssige Ladungen in Behältern oder Tanks, die zum Teil gefüllt werden, die Stabilität des Fahrzeugs beeinflussen?', 'Nein, wenn das Volumen der Ladung die Hälfte des Behälters nicht übersteigt.', 'Nein.', 'Ja.', 'Чи можуть рідкі вантажі у частково заповнених баках або цистернах впливати на нестабільність транспортного засобу?', 'Ні, якщо об’єм вантажу не перевищує половини ємності бака.', 'Ні.', 'Так.'),
(3155, 11483, 'Czy przy transporcie ciężkich maszyn roboczych lub sprzętu budowlanego masz obowiązek używać odciągów stalowych i klinów?', 'Tak.', 'Nie, jeśli pojazdy transportowane są pozostawione z zaciągniętym hamulcem postojowym.', 'Nie, na krótkie odległości można taki ładunek przewozić bez mocowania.', 'A', '5C118.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11483.wmv', 'pjm11483a.wmv', 'pjm11483b.wmv', 'pjm11483c.wmv', 'When you transport heavy working machines or construction equipment, are you obliged to use steel ropes and wedges?', 'Yes.', 'No, if the parking brake is put on in the transported vehicles.', 'No, such load may be transported without securing it for short distances.', 'Soll man beim Transport von Arbeitsmaschinen oder Baugeräten Stahlhalteseile und Keile verwenden?', 'Ja.', 'Nein, wenn die transportierten Fahrzeuge mit der angezogenen Feststellbremsen gelassen werden.', 'Nein, auf kurzen Strecken darf man solche Ladung ohne Befestigung befördern.', 'Чи Ви зобов’язані використовувати сталеві розтяжки та клини під час перевезення важких робочих машин або будівельного обладнання?', 'Так.', 'Ні, якщо транспортовані машини залишено з затягнутим стоянковим гальмом.', 'Ні, на короткі відстані такий вантаж можна перевозити без кріплення.'),
(3156, 11486, 'Czy masz prawo kierować samochodem ciężarowym, którego masa wraz z ładunkiem jest większa od dopuszczalnej na danym odcinku drogi?', 'Tak, bez dodatkowych warunków.', 'Tak, ale tylko pod warunkiem uzyskania odpowiedniego zezwolenia.', 'Tak, pod warunkiem uiszczenia specjalnej opłaty u wójta.', 'B', '5C125.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11486.wmv', 'pjm11486a.wmv', 'pjm11486b.wmv', 'pjm11486c.wmv', 'Can you drive a truck whose weight, including the cargo, is higher than the admissible weight along a given section of the road?', 'Yes, without any additional conditions.', 'Yes, but provided that a relevant permit is obtained.', 'Yes, but provided that a special fee is paid to the head of the commune (vogt).', 'Dürfen Sie einen Lkw führen, dessen Masse zusammen mit der Ladung größer als die auf dieser Strecke zulässig sind?', 'Ja, ohne zusätzliche Bedingungen.', 'Ja, aber nur unter der Voraussetzung, dass eine entsprechende Genehmigung eingeholt wird.', 'Ja, unter der Bedingung, dass eine Sondergebühr beim Gemeindevorsteher bezahlt wird.', 'Чи  маєте  Ви право керувати вантажним автомобілем, маса якого разом із вантажем перевищує дозволену на даній ділянці дороги?', 'Так, без додаткових умов.', 'Так, але лише за умови отримання відповідного дозволу.', 'Так, за умови сплати спеціального збору голові громади (вуйтові).'),
(3157, 11487, 'Czy masz prawo kierować samochodem ciężarowym, którego wysokość wraz z ładunkiem jest większa od dopuszczalnej?', 'Tak, ale tylko pod warunkiem uzyskania odpowiedniego zezwolenia.', 'Tak, bez dodatkowego zezwolenia.', 'Nie, w żadnym przypadku.', 'A', '5C126.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11487.wmv', 'pjm11487a.wmv', 'pjm11487b.wmv', 'pjm11487c.wmv', 'Can you drive a truck whose height, including the cargo, exceeds the permissible height?', 'Yes, but provided that a relevant permit is obtained.', 'Yes, without an additional permit.', 'No, under no circumstances.', 'Dürfen Sie einen Lkw führen, dessen Höhe zusammen mit der Ladung größer als die auf dieser Strecke zulässig ist?', 'Ja, aber nur unter der Voraussetzung, dass eine entsprechende Genehmigung eingeholt wird.', 'Ja, ohne zusätzliche Genehmigung.', 'Nein, auf keinen Fall.', 'Чи маєте Ви право керувати вантажним автомобілем, висота якого разом із вантажем перевищує дозволену?', 'Так, але лише за умови отримання відповідного дозволу.', 'Так, без додаткового дозволу.', 'Ні, за жодних обставин.'),
(3158, 11488, 'W jakiej sytuacji, kierując samochodem ciężarowym, masz obowiązek upewnić się, że przewożony ładunek jest właściwie zabezpieczony?', 'Każdorazowo po przejechaniu 100 km.', 'Po gwałtownym hamowaniu.', 'Podczas każdej przerwy w prowadzeniu pojazdu.', 'B', '5C127.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11488.wmv', 'pjm11488a.wmv', 'pjm11488b.wmv', 'pjm11488c.wmv', 'While driving a truck, in what circumstances should you make sure that the transported cargo is properly secured?', 'Each time, after travelling 100 km.', 'After an abrupt braking manoeuver.', 'During each break in driving.', 'In welcher Situation sollen Sie sich vergewissern, dass die beförderte Ladung richtig gesichert ist, wenn Sie einen Lkw fahren?', 'Jeweils nach 100 km.', 'Nach plötzlicher Bremsung.', 'Bei jeder Pause in der Fahrzeugführung.', 'У якій ситуації, керуючи вантажним автомобілем, Ви зобов’язані переконатися, що вантаж правильно закріплений?', 'Кожного разу після проїзду 100 км.', 'Після різкого гальмування.', 'Під час кожної перерви в керуванні транспортним засобом.'),
(3159, 11489, 'Jak sygnalizowana jest niesprawność układu przeciwblokującego (ABS)?', 'Świetlnym sygnałem kontrolnym na tablicy rozdzielczej.', 'Sygnałem dźwiękowym.', 'Włączeniem się świateł awaryjnych.', 'A', '', 'SPECJALISTYCZNY', 1, 'C,C1', 'pjm11489.wmv', 'pjm11489a.wmv', 'pjm11489b.wmv', 'pjm11489c.wmv', 'How is the failure of the anti-block system (ABS) indicated?', 'By a control light on the dashboard.', 'By a sound signal.', 'By activation of the emergency lights.', 'Wie wird eine Störung des Antiblockiersystems (ABS) signalisiert?', 'Durch Kontrollleuchte im Armaturenbrett.', 'Durch akustisches Signal.', 'Durch Einschalten des Warnblinklichtes.', 'Як сигналізується несправність антиблокувальної системи (ABS)?', 'Світловим контрольним сигналом на панелі приладів.', 'Звуковим сигналом.', 'Увімкненням аварійної світлової сигналізації.'),
(3160, 11490, 'Stwierdziłeś wyciek płynu z amortyzatora hydraulicznego, jakie mogą być jego skutki?', 'Zwiększone tłumienie drgań nadwozia na nierównościach drogi.', 'Skrócenie drogi hamowania.', 'Zmniejszenie przyczepności kół do jezdni na nierównej drodze.', 'C', '', 'SPECJALISTYCZNY', 1, 'C,C1', 'pjm11490.wmv', 'pjm11490a.wmv', 'pjm11490b.wmv', 'pjm11490c.wmv', 'What may be the consequences of a leakage of liquid from the hydraulic shock absorber?', 'Increased damping of chassis vibrations on uneven road.', 'Shortening of the braking distance.', 'Reduced wheel traction on uneven road.', 'Welche Folgen kann das Austreten von Flüssigkeit aus einem hydraulischen Stoßdämpfer nach sich ziehen?', 'Höhere Dämmung der Schwingungen des Aufbaus bei Unebenheiten.', 'Verkürzung des Bremsweges.', 'Verringerung der Bodenhaftung der Räder zur Fahrbahn bei Unebenheiten.', 'Виявлено витік рідини з гідравлічного амортизатора. Якими можуть бути його наслідки?', 'Посилене гасіння коливань кузова на нерівностях дороги.', 'Скорочення гальмівного шляху.', 'Зменшення зчеплення коліс із проїжджою частиною на нерівній дорозі.'),
(3161, 11491, 'Jaki może być skutek uszkodzenia jednej z żarówek kierunkowskazów?', 'Pozostałe żarówki kierunkowskazów także nie będą działać.', 'Przerywacz kierunkowskazów będzie pracował ze zwiększoną częstotliwością.', 'Włączą się światła awaryjne.', 'B', '', 'SPECJALISTYCZNY', 1, 'C,C1', 'pjm11491.wmv', 'pjm11491a.wmv', 'pjm11491b.wmv', 'pjm11491c.wmv', 'What might be the result of a damage to one of the direction indicator bulbs?', 'The other indicator bulbs will also stop working.', 'Indicator breaker will operate at an increased rate.', 'Emergency lights will turn on.', 'Was kann die Folge einer beschädigten Blinkerleuchte sein?', 'Sämtliche andere Blinkerleuchten fallen ebenfalls aus.', 'Blinkerunterbrecher arbeitet mit erhöhter Frequenz.', 'Es schaltet sich die Warnblinkanlage ein.', 'Яким може бути наслідок пошкодження однієї з ламп покажчика повороту?', 'Інші лампи покажчиків повороту також не працюватимуть.', 'Реле покажчиків повороту працюватиме з підвищеною частотою.', 'Увімкнеться аварійна світлова сигналізація.'),
(3162, 11492, 'Ile wynosi minimalna dozwolona głębokość rzeźby bieżnika opony samochodu ciężarowego?', '3 mm.', '1,6 mm.', '2,6 mm.', 'B', '', 'SPECJALISTYCZNY', 1, 'C,C1', 'pjm11492.wmv', 'pjm11492a.wmv', 'pjm11492b.wmv', 'pjm11492c.wmv', 'What is the minimum permissible depth of the tyre tread pattern of a lorry?', '3 mm.', '1.6 mm.', '2.6 mm.', 'Wie ist die zulässige Mindesthöhe des Laufflächenprofils eines Lkw-Reifens?', '3 mm.', '1,6 mm.', '2,6 mm.', 'Яка мінімально допустима глибина рисунка протектора шини вантажного автомобіля?', '3 мм.', '1,6 мм.', '2,6 мм.'),
(3163, 11493, 'Które z wymienionych działań należy podjąć, gdy w czasie jazdy zaświeci się na czerwono lampka kontrolna temperatury cieczy chłodzącej?', 'Zatrzymać pojazd i wyłączyć silnik.', 'Zwolnić.', 'Przyspieszyć.', 'A', '', 'SPECJALISTYCZNY', 1, 'C,C1', 'pjm11493.wmv', 'pjm11493a.wmv', 'pjm11493b.wmv', 'pjm11493c.wmv', 'Which of the following actions should be taken when the red warning light of the cooling liquid temperature comes on during a drive?', 'Stop the vehicle and switch off the engine.', 'Slow down.', 'Accelerate.', 'Welche der genannten Maßnahmen ist zu treffen, wenn die Kontrollleuchte der Kühlflüssigkeit während der Fahrt rot aufleuchtet?', 'Das Fahrzeug anhalten und den Motor abstellen.', 'Die Fahrt verlangsamen.', 'Die Fahrt beschleunigen.', 'Які дії слід вжити, якщо під час руху засвітиться червона лампочка температури охолоджувальної рідини?', 'Зупинити транспортний засіб і заглушити двигун.', 'Знизити швидкість.', 'Прискорити.'),
(3164, 11494, 'Które z wymienionych działań należy podjąć, gdy w czasie jazdy zaświeci się na czerwono lampka kontrolna ciśnienia oleju w silniku?', 'Zatrzymać pojazd i wyłączyć silnik.', 'Zwolnić.', 'Zwiększyć obroty silnika.', 'A', '', 'SPECJALISTYCZNY', 1, 'C,C1', 'pjm11494.wmv', 'pjm11494a.wmv', 'pjm11494b.wmv', 'pjm11494c.wmv', 'Which of the following actions should be taken when the red warning light of the engine oil pressure comes on during a drive?', 'Stop the vehicle and switch off the engine.', 'Slow down.', 'Increase the engine revolutions.', 'Welche der genannten Maßnahmen ist zu treffen, wenn die Kontrollleuchte des Motoröldrucks während der Fahrt rot aufleuchtet?', 'Das Fahrzeug anhalten und den Motor abstellen.', 'Die Fahrt verlangsamen.', 'Die Motordrehzahl erhöhen.', 'Які дії слід вжити, якщо під час руху засвітиться червона лампочка тиску оливи в двигуні?', 'Зупинити транспортний засіб і заглушити двигун.', 'Знизити швидкість.', 'Збільшити оберти двигуна.'),
(3165, 11496, 'Czy w tej sytuacji wolno Ci zatrzymać się na poboczu jeżeli potrzebujesz odpoczynku?', '', '', '', 'N', 'MD_D6_04_ERR_org_2.mp4', 'PODSTAWOWY', 2, 'A,B,C,D,AM,A1,A2,B1,C1,D1', 'pjm11496.wmv', '', '', '', 'You need rest. Are you allowed to pull over for a short while on the presented hard shoulder?', '', '', '', 'Darf man zwecks einer kurzen Erholung auf dem gezeigten Randstreifen anhalten?', '', '', '', 'Чи дозволено Вам, у цій ситуації, зупинитися на узбіччі щоб відпочити?', '', '', ''),
(3166, 11497, 'Czy w tej sytuacji wolno Ci kontynuować jazdę na wprost dotychczasowym pasem ruchu?', '', '', '', 'N', 'IMG_0317orgbm.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm11497.wmv', '', '', '', 'Are you allowed to continue driving straight on the current lane if there are no other vehicles on the right half of the road?', '', '', '', 'Dürfen Sie hier geradeaus auf der bisherigen Spur weiterfahren?', '', '', '', 'Чи дозволено Вам, у цій ситуації, продовжувати рух прямо смугою руху, на якій Ви знаходитеся?', '', '', ''),
(3167, 11498, 'Czy w tej sytuacji postępujesz zgodnie z przepisami, kontynuując jazdę zajmowanym pasem ruchu?', '', '', '', 'T', 'MD_D15c_09orgbezmaski.mp4', 'PODSTAWOWY', 2, 'B,C,D,T,B1,C1,D1', 'pjm11498.wmv', '', '', '', 'Is it proper in this situation to continue driving on the same lane?', '', '', '', 'Ist es gesetzlich richtig, die Fahrt auf der bisherigen Spur fortzusetzen?', '', '', '', 'Чи, у цій ситуації, Ви дієте згідно правил, продовжуючи їхати по тій смузі, на якій перебуваєте?', '', '', ''),
(3168, 11499, 'Czy planując opuszczenie tego skrzyżowania, zmieniłeś pas ruchu we właściwym momencie?', '', '', '', 'T', 'W11(51)org.mp4', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm11499.wmv', '', '', '', 'Intending to leave this intersection, did you change the lane in the right moment?', '', '', '', 'Haben Sie beim Verlassen dieser Kreuzung die Spur im richtigen Moment gewechselt?', '', '', '', 'Чи плануючи виїхати з цього перехрестя, Ви у потрібний момент змінили смугу руху?', '', '', ''),
(3169, 11500, 'Czy powinieneś niezwłocznie przystąpić do zmiany pasa ruchu, jeśli zamierzasz skręcić w lewo na najbliższym skrzyżowaniu?', '', '', '', 'T', '4498D15org.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm11500.wmv', '', '', '', 'You intend to turn left at the nearest junction. Should you immediately start changing lanes?', '', '', '', 'Sollen Sie unverzüglich mit dem Fahrspurwechsel anfangen, wenn Sie an der nächsten Kreuzung links abbiegen wollen?', '', '', '', 'Чи потрібно негайно починати змінювати смугу, якщо Ви збираєтеся повернути ліворуч на найближчому перехресті?', '', '', ''),
(3170, 11501, 'Czy w tej sytuacji masz prawo zrezygnować z użycia kierunkowskazu przy zmianie pasa?', '', '', '', 'N', '1.5.2.-1 IMG_7051d8orgbm.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm11501.wmv', '', '', '', 'In this situation, can you resign from using the indicator when changing lanes?', '', '', '', 'Dürfen Sie in dieser Situation beim Spurenwechsel auf das Einschalten des Fahrtrichtungsanzeigers verzichten?', '', '', '', 'Чи, у цій ситуації, Ви маєте право відмовитися від вмикання покажчика повороту при зміні смуги руху?', '', '', ''),
(3171, 11502, 'Przewozisz zespołem pojazdów o długości 10 metrów ładunek wystający z tyłu przyczepy na odległość 0,5 metra. Czy wolno Ci wjechać na drogę za tym znakiem?', '', '', '', 'N', 'D38_5665org.jpg', 'PODSTAWOWY', 3, 'B,C,T,C1', 'pjm11502.wmv', '', '', '', 'You are driving a combination of vehicles whose length is 10 metres, and carrying a load which protrudes from the back of the trailer at 0.5 metres. Are you allowed to drive onto the road beyond this sign?', '', '', '', 'Du transportierst mit einer 10 m langen Fahrzeugkombination eine Ladung, die aus dem Hänger hinten 0,5 m herausragt. Darfst du auf die Straße hinter dem gezeigten Zeichen einfahren?', '', '', '', 'Ви перевозите автопоїздом загальною довжиною 10 метрів, вантаж, який виступає за обриси задньої частини причепа на 0,5 метра. Чи маєте Ви право в\'їхати на дорогу за цим знаком?', '', '', ''),
(3172, 11503, 'Czy wartość podana na widocznym znaku dotyczy rzeczywistej masy całkowitej pojazdu?', '', '', '', 'T', '3044D15org.jpg', 'PODSTAWOWY', 3, 'C,D,T,C1,D1', 'pjm11503.wmv', '', '', '', 'Does the value given on this sign refer to the gross vehicle weight of the vehicle?', '', '', '', 'Betrifft der auf dem gezeigten Zeichen bekannt gegebene Wert die tatsächliche Gesamtmasse des Fahrzeuges?', '', '', '', 'Чи стосується значення, вказане на  знаку, який Ви бачите, фактичної маси транспортного засобу?', '', '', ''),
(3173, 11504, 'Zamierzasz skręcić w lewo. Czy masz pierwszeństwo przed pojazdem nadjeżdżającym z lewej strony?', '', '', '', 'T', 'KW_D22_425_org_2.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm11504.wmv', '', '', '', 'You intend to turn left. Do you have the right of way over the vehicle approaching from the left?', '', '', '', 'Sie haben vor, links abzubiegen. Haben Sie die Vorfahrt vor dem von links kommenden Fahrzeug?', '', '', '', 'Ви збираєтеся повернути ліворуч. Чи маєте Ви перевагу перед транспортним засобом, який наближається зліва?', '', '', ''),
(3174, 11505, 'Czy w tej sytuacji masz obowiązek ustąpić pierwszeństwa pojazdowi nadjeżdżającemu z prawej strony?', '', '', '', 'N', '508_D27KW_org_2.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm11505.wmv', '', '', '', 'You intend to turn left. Are you obliged to yield the right of way to the vehicle approaching from the right?', '', '', '', 'Sie möchten links abbiegen. Haben Sie die Pflicht, dem von rechts kommenden Fahrzeug die Vorfahrt zu geben?', '', '', '', 'Чи зобов\'язані Ви, в цій ситуації, дати дорогу транспортному засобу, який наближається справа?', '', '', ''),
(3175, 11506, 'Czy wolno Ci holować pojazd, którym kieruje osoba w stanie po użyciu alkoholu?', '', '', '', 'N', '30023.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm11506.wmv', '', '', '', 'Are you allowed to haul a vehicle being driven by an intoxicated person?', '', '', '', 'Darf man ein Fahrzeug abschleppen, das von einer Person gelenkt wird, die unter dem Einfluss von Alkohol steht?', '', '', '', 'Чи дозволяється буксирування транспортного засобу, яким керує особа в стані алкогольного сп’яніння?', '', '', ''),
(3176, 11507, 'Czy zażywanie leków nasennych i uspokajających może mieć negatywny wpływ na zdolność prowadzenia pojazdu?', '', '', '', 'T', '1C207_.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm11507.wmv', '', '', '', 'Can taking soporifics or sedatives affect the capability of driving a vehicle?', '', '', '', 'Können Schlaf- und Beruhigungsmittel die Fahrtauglichkeit beeinflussen?', '', '', '', 'Чи може прийом снодійних і заспокійливих ліків негативно вплинути на Вашу здатність керувати автомобілем?', '', '', ''),
(3177, 11508, 'Czy rozmieszczone w taki sposób ozdoby, ograniczają widoczność drogi i rozpraszają uwagę kierującego?', '', '', '', 'T', '1C252_.jpg', 'PODSTAWOWY', 2, 'B,C,D,B1,C1,D1', 'pjm11508.wmv', '', '', '', 'Can placing decorative elements in such a way limit visibility of the road and distract the driver’s attention?', '', '', '', 'Können die so angebrachten Gadgets die Sicht verhindern und die Aufmerksamkeit des Fahrers ablenken?', '', '', '', 'Чи розміщені таким чином прикраси обмежують огляд дороги та відволікають увагу водія?', '', '', ''),
(3178, 11509, 'Czy zaśnieżone szyby lub lusterka samochodu, którym zamierzasz kierować, utrudniają ocenę sytuacji na drodze?', '', '', '', 'T', '1C253_.jpg', 'PODSTAWOWY', 2, 'B,C,D,T,B1,C1,D1', 'pjm11509.wmv', '', '', '', 'Can  snow-covered  windows and mirrors on the car you are going to drive affect your assessment of the situation on the road? 	', '', '', '', 'Können verschneite Autoscheiben und Außenspiegel  eines Autos, das man fahren will, einen Einfluss auf die Einschätzung der Verkehrssituation haben?', '', '', '', 'Чи засніжені вікна або дзеркала автомобіля, яким Ви збираєтеся їхати, утруднюють оцінку ситуації на дорозі?', '', '', ''),
(3179, 11510, 'Czy rano powinieneś zrezygnować z kierowania pojazdem, jeśli wieczorem poprzedniego dnia spożyłeś dużą ilość alkoholu?', '', '', '', 'T', '1C208_1.jpg', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', 'pjm11510.wmv', '', '', '', 'Should you refrain from driving a vehicle in the morning, if the night before you consumed a large amount of alcohol?', '', '', '', 'Soll man am Morgen auf das Autofahren verzichten, wenn man am  Vorabend viel Alkohol getrunken hat?', '', '', '', 'Чи слід відмовитися від водіння вранці, якщо ввечері попереднього дня Ви випили велику кількість алкоголю?', '', '', ''),
(3180, 11513, 'Co należy zrobić, gdy u nieprzytomnego poszkodowanego w wypadku drogowym stwierdzisz brak oddechu?', 'W obawie o ewentualny uraz kręgosłupa pozostawić rannego w pojeździe do przyjazdu ratownictwa medycznego.', 'Wydostać rannego z rozbitego pojazdu i przystąpić do resuscytacji.', 'Pozostawić rannego w pojeździe i przykryć go kocem termoizolacyjnym, czekając na przybycie ratownictwa medycznego.', 'B', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11513.wmv', 'pjm11513a.wmv', 'pjm11513b.wmv', 'pjm11513c.wmv', 'What should you do, if you notice that an unconscious victim of a road accident is not breathing?', 'For fear of a possible spinal injury, leave the injured in the vehicle until  the emergency medical services arrive.', 'Remove the injured from the crashed vehicle and commence resuscitation.', 'Leave the injured in the vehicle, cover him with a thermal insulation blanket and wait for the emergency medical services to arrive.', 'Welche der genannten Maßnahmen ist zu treffen, wenn Sie bei der Versorgung von Verkehrsunfallopfern bei einer der betroffenen Personen festgestellt haben, dass sie keinen Pulsschlag mehr hat und nicht mehr atmet?', 'In Sorge um etwaige Verletzungen an der Wirbelsäule ist die verletzte Person bis zur Ankunft des Medizinischen Rettungsdienstes im Fahrzeug zu belassen.', 'Die verletzte Person ist aus dem Unfallfahrzeug zu bergen, anschließend ist es mit den Wiederbelebungsmaßnahmen zu beginnen.', 'Die verletzte Person ist im Fahrzeug zu belassen und mit einer wärmeisolierenden Decke zu decken. Man muss auf die Ankunft des Medizinischen Rettungsdienstes warten.', 'Які дії необхідно вжити, якщо у непритомного постраждалого після ДТП відсутнє дихання?', 'Залишити постраждалого у транспортному засобі через можливість травми хребта та очікувати прибуття бригади екстреної медичної допомоги.', 'Витягти постраждалого з розбитого автомобіля та розпочати масаж серця разом із штучним диханням.', 'Залишити постраждалого в машині, накрити спеціальною термоізоляційною ковдрою та чекати на прибуття бригади екстреної медичної допомоги.'),
(3181, 11515, 'Kiedy kierując samochodem ciężarowym masz obowiązek przełączyć światła drogowe na światła mijania?', 'Zawsze gdy widzisz pojazd poprzedzający.', 'Zawsze gdy istnieje możliwość oślepienia kierującego pojazdem poprzedzającym.', 'Zawsze gdy widzisz pojedynczego pieszego na jezdni.', 'B', '5B226.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11515.wmv', 'pjm11515a.wmv', 'pjm11515b.wmv', 'pjm11515c.wmv', 'While driving a truck, when must you switch from high-beam to low-beam lights?', 'Always when you see a vehicle in front of you.', 'Always when there is a possibility of blinding the driver of the vehicle in front of you.', 'Always when you see a single pedestrian on the road.', 'Wann müssen Sie von Fernlicht auf Abblendlicht schalten, wenn Sie einen Lkw führen?', 'Immer, wenn Sie das vorausfahrende Fahrzeug sehen.', 'Immer, wenn eine Gefahr besteht, dass der Führer des vorausfahrenden Fahrzeugs geblendet wird.', 'Immer, wenn Sie einen einzelnen Fußgänger auf der Fahrbahn sehen.', 'Коли під час керування вантажним автомобілем Ви зобов\'язані перемкнути дальнє світло на ближнє?', 'Завжди, коли бачите транспортний засіб попереду', 'Завжди, коли існує ризик засліплення водія попереду', 'Завжди, коли бачите окремого пішохода на проїжджій частині'),
(3182, 11516, 'Czy zamierzając kierować samochodem ciężarowym i wykonywać transport masz obowiązek upewnić się, że przewożony ładunek jest prawidłowo zabezpieczony?', 'Tak, musisz sprawdzić zabezpieczenie i prawidłowość rozmieszczenia ładunku.', 'Tak, ale tylko w razie wątpliwości co do bezpieczeństwa transportu ładunku.', 'Nie, kierujący nie odpowiada za załadunek, a jedynie za przewóz ładunku.', 'A', '5C106.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11516.wmv', 'pjm11516a.wmv', 'pjm11516b.wmv', 'pjm11516c.wmv', 'You intend to drive a truck for the purpose of transporting goods. Are you obliged to make sure that the transported cargo is properly secured?', 'Yes, you have to check the safety and correctness of cargo positioning.', 'Yes, but only in the event of doubts regarding the safety of the cargo transportation.', 'No, the driver is not responsible for the cargo itself, but only for its transport.', 'Sollen Sie sich vergewissern, dass die transportierte Ladung richtig abgesichert wurde, wenn Sie als Lkw-Führer die Beförderung im Straßenverkehr ausführen?', 'Ja, es muss geprüft werden, ob die Ladung abgesichert und richtig verstaut ist.', 'Ja, aber nur bei Bedenken hinsichtlich der Transportsicherheit der Ladung.', 'Nein, der Fahrer haftet nicht für die Ladung sondern nur für die Beförderung der Ladung.', 'Чи перед початком перевезення Ви зобов’язані переконатися у тому, що вантаж, який Ви перевозитимете вантажним автомобілем, правильно закріплений?', 'Так, Ви повинні перевірити кріплення і правильність розміщення вантажу.', 'Так, але тільки у випадку сумнівів щодо безпеки перевезення вантажу.', 'Ні, водій не відповідає за завантаження, а лише за перевезення вантажу.'),
(3183, 11517, 'Który sposób oznakowania ładunku wystającego ponad 0,5 m poza tylną płaszczyznę obrysu samochodu ciężarowego jest właściwy?', 'Chorągiewka barwy białej o wymiarach 33 cm x 34 cm.', 'Bryła geometryczna z pasami białymi i czerwonymi o łącznej powierzchni nie mniejszej niż 1000 cm2.', 'Światło stałe o barwie pomarańczowej.', 'B', '5C123.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11517.wmv', 'pjm11517a.wmv', 'pjm11517b.wmv', 'pjm11517c.wmv', 'Which of the following methods of marking a load overhanging more than 0.5 m from the rear outline of the truck is correct?', 'A white flag with the dimensions of 33cm x 34cm.', 'A geometric solid with white-and-red stripes, with a total capacity of at least 1000 cm2.', 'A permanent orange light.', 'Welche von den genannten Kennzeichnungen der Ladung, die mehr als 0,5 m über den Umriss des Fahrzeugs nach hinten hinausragt, ist korrekt?', 'Eine weiße Fahne, 33cm x 34cm groß.', 'Ein geometrischer Körper mit weißen und roten Streifen, mit der Gesamtfläche von mindestens 1000 cm2.', 'Dauerhaftes Licht mit orangefarbenen Farbe.', 'Який спосіб позначення вантажу, що виступає більш ніж на 0,5 м за задню площину обрису вантажного автомобіля, є правильним?', 'Прапорець білого кольору розміром 33 см × 34 см.', 'Геометричне тіло з білими та червоними смугами загальною площею не менше ніж 1000 см².', 'Постійне світло помаранчевого кольору.'),
(3184, 11518, 'Który sposób oznakowania ładunku wystającego ponad 0,5 m poza tylną płaszczyznę obrysu samochodu ciężarowego jest właściwy?', 'Pasy białe i czerwone o łącznej powierzchni co najmniej 1000 cm2 umieszczone bezpośrednio na ładunku.', 'Tarcza o wymiarach co najmniej 50x50 cm z pasami czarnymi i żółtymi.', 'Bryła geometryczna z pasami czarnymi i białymi.', 'A', '5C124.jpg', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11518.wmv', 'pjm11518a.wmv', 'pjm11518b.wmv', 'pjm11518c.wmv', 'Which of the following methods of marking a load overhanging more than 0.5 m from the rear outline of the truck is correct?', 'White-and-red stripes with a total surface area of at least 1000cm2, placed directly on the load.', 'A plaque with the dimensions of at least 50x50 cm with black-and-yellow stripes.', 'A geometric solid with red-and-white stripes.', 'Welche von den genannten Kennzeichnungen der Ladung, die mehr als 0,5 m über den Umriss des Fahrzeugs nach hinten hinausragt, ist korrekt?', 'Weiße und rote Streifen mit der Gesamtfläche von mindestens 1000cm2, die direkt an der Ladung angebracht sind.', 'Ein Schild mit schwarzen und gelben Streifen, mindestens 50x50 cm groß.', 'Ein geometrischer Körper mit weißen und roten Streifen.', 'Який спосіб позначення вантажу, що виступає більш ніж на 0,5 м за задню площину обрису вантажного автомобіля, є правильним?', 'Білі та червоні смуги загальною площею щонайменше 1000 см², розміщені безпосередньо на вантажі.', 'Щит розміром щонайменше 50 × 50 см із чорними та жовтими смугами.', 'Геометричне тіло з чорними та білими смугами.'),
(3185, 11519, 'Jakiej wartości nie może przekraczać rzeczywista masa całkowita przyczepy ciągniętej przez samochód ciężarowy o dopuszczalnej masie całkowitej przekraczającej 3,5 t?', 'Masy własnej tego samochodu.', 'Rzeczywistej masy całkowitej tego samochodu.', 'Rzeczywistej masy całkowitej tego samochodu powiększonej o 40%.', 'C', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11519.wmv', 'pjm11519a.wmv', 'pjm11519b.wmv', 'pjm11519c.wmv', 'The gross vehicle weight of a trailer pulled by a lorry of gross vehicle weight rating over 3.5 tons must not exceed:', 'the kerb weight of the lorry.', 'the gross vehicle weight of the lorry.', 'the gross vehicle weight of the lorry increased by 40%.', 'Die tatsächliche Gesamtmasse eines durch einen LKW mit einer zulässigen Gesamtmasse von mehr als 3,5 t geschleppten Anhängers darf nicht überschreiten:', 'Die Leermasse dieses Fahrzeugs.', 'Die tatsächliche Gesamtmasse dieses Fahrzeugs.', 'Die tatsächliche Gesamtmasse dieses Fahrzeugs zuzüglich 40%.', 'Якого значення не може перевищувати фактична маса причепа, що буксирується вантажним автомобілем з дозволеною максимальною масою понад 3,5 т?', 'Власної маси цього автомобіля.', 'Фактичної повної маси цього автомобіля.', 'Фактичної повної маси цього автомобіля, збільшеної на 40%.'),
(3186, 11520, 'Czy przejazd zespołu pojazdów składającego się z samochodu ciężarowego i dwóch przyczep wymaga zezwolenia?', 'Nie, nie wymaga zezwolenia, niezależnie od przewożonego ładunku.', 'Nie, nie wymaga zezwolenia, jeżeli w przyczepach nie jest przewożony ładunek.', 'Tak wymaga zezwolenia.', 'C', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11520.wmv', 'pjm11520a.wmv', 'pjm11520b.wmv', 'pjm11520c.wmv', 'Passage of the combination of vehicles consisting of a lorry and two trailers:', 'does not require a permit regardless of the load being carried.', 'does not require a permit, if no load is being carried on the trailers.', 'requires a permit .', 'Die Durchfahrt einer Fahrzeugkombination, die aus einem Lastkraftwagen und zwei Anhängern besteht:', 'Bedarf, unabhängig von der beförderten Ladung, keiner Genehmigung.', 'Bedarf keiner Genehmigung, sofern mit den Anhängern keine Ladung befördert wird.', 'Bedarf einer Genehmigung.', 'Чи потрібен дозвіл на проїзд автопоїзда, що складається з вантажного автомобіля та двох причепів?', 'Ні, дозвіл не потрібний, незалежно від вантажу, що перевозиться.', 'Ні, дозвіл не потрібний, якщо причепи порожні.', 'Так, дозвіл обов\'язковий.'),
(3187, 11521, 'W jaki sposób dwukrotne zwiększenie prędkości samochodu ciężarowego wpływa na długość jego drogi hamowania?', 'Zwiększa dwukrotnie długość drogi hamowania.', 'Zwiększa czterokrotnie długość drogi hamowania.', 'Nie powoduje zmiany długości drogi hamowania.', 'B', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11521.wmv', 'pjm11521a.wmv', 'pjm11521b.wmv', 'pjm11521c.wmv', 'How does doubling of the lorry speed influence the length of the braking distance?', 'It doubles the braking distance.', 'It increases the braking distance by four times.', 'It does not change the length of the braking distance.', 'Wie wirkt sich die Verdoppelung der Geschwindigkeit eines Lastkraftwagens auf die Länge seines Bremsweges aus?', 'Der Bremsweg wird doppelt so lang.', 'Der Bremsweg wird viermal so lang .', 'Keine Änderung der Bremsweglänge.', 'Як подвоєння швидкості вантажного автомобіля впливає на довжину його гальмівного шляху?', 'Подвоює довжину гальмівного шляху', 'Збільшує довжину гальмівного шляху вчетверо', 'Не спричиняє зміни довжини гальмівного шляху');
INSERT INTO `pula_pytan` (`ID`, `nr_pyt`, `pyt`, `odp_a`, `odp_b`, `odp_c`, `poprawna`, `media`, `zakres`, `pkt`, `kategorie`, `media_migowy_pyt`, `media_migowy_odp_a`, `media_migowy_odp_b`, `media_migowy_odp_c`, `pyt_en`, `odp_a_en`, `odp_b_en`, `odp_c_en`, `pyt_de`, `odp_a_de`, `odp_b_de`, `odp_c_de`, `pyt_ua`, `odp_a_ua`, `odp_b_ua`, `odp_c_ua`) VALUES
(3188, 11524, 'Czy fakt, że jedziesz we mgle, ma wpływ na długość drogi hamowania?', 'Tak, może się ona zwiększyć ze względu na zawilgocenie jezdni.', 'Tak, może się ona zmniejszyć ze względu na zwiększoną przyczepność opony do nawierzchni jezdni.', 'Nie, nie zwiększa się ani nie zmniejsza, bo mgła i wilgotność nie ma na nią wpływu.', 'A', '', 'SPECJALISTYCZNY', 2, 'C,C1', 'pjm11524.wmv', 'pjm11524a.wmv', 'pjm11524b.wmv', 'pjm11524c.wmv', 'When driving in fog, the braking distance:', 'may increase due to the wet road.', 'may decrease due to the increase of the tyre grip to the road surface.', 'neither increases nor decreases, because both fog or wetness have no impact on it.', 'Während einer Fahrt im Nebel kann die Bremsweglänge werden:', 'Länger, weil die Fahrbahn feucht ist.', 'Kürzer, weil der Kraftschluss zwischen den Reifen und der Fahrbahn größer ist.', 'Weder länger noch kürzer, weil sie weder vom Nebel noch von der Feuchtigkeit beeinflusst wird.', 'Чи факт, що Ви керуєте  транспортним засобом у тумані впливає на довжину гальмівного шляху?', 'Так, він може збільшитися через зволоження дороги', 'Так, він може зменшитися через покращене зчеплення шин з дорогою', 'Ні, не збільшується і не зменшується, оскільки туман і вологість не впливають на довжину гальмівного шляху'),
(3189, 11526, 'Jak należy trzymać kierownicę podczas jazdy samochodem ciężarowym na wprost?', 'Obiema rękami można trzymać kierownicę w dowolnych jej miejscach.', 'Lewa ręka trzyma kierownicę między godziną 9 i 10, a prawa spoczywa na dowolnym miejscu na kierownicy.', 'Lewa ręka trzyma kierownicę między godziną 9 i 10, a prawa - między godziną 2 i 3.', 'C', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11526.wmv', 'pjm11526a.wmv', 'pjm11526b.wmv', 'pjm11526c.wmv', 'How should you hold a steering wheel when driving a truck straight on?', 'With both hands in any place on the steering wheel.', 'With the left hand holding the steering wheel between 9 and 10 o\'clock, and the right hand in any place on the steering wheel.', 'With the left hand holding the steering wheel between 9 and 10 o\'clock and the right hand between 2 and 3 o\'clock.', 'Wie ist das Lenkrad eines Lastkraftwagens zu halten, wenn man mit dem LKW geradeaus fährt?', 'Das Lenkrad kann man an beliebigen Stellen beidhändig halten.', 'Die linke Hand hält das Lenkrad in der Position zwischen 9 und 10 Uhr, während die rechte Hand an einer beliebigen Stelle des Lenkrads aufliegt.', 'Die linke Hand hält das Lenkrad in der Position zwischen 9 und 10 Uhr und die rechte Hand in der Position zwischen 2 und 3 Uhr.', 'Як слід тримати кермо під час їзди вантажним автомобілем прямо?', 'Обидві руки можуть тримати кермо у будь-яких його місцях.', 'Ліва рука тримає кермо між 9 і 10 годинами, а права лежить у будь-якому місці на кермі.', 'Ліва рука тримає кермо між 9 і 10 годинами, а права — між 2 і 3 годинами.'),
(3190, 11527, 'Która z wymienionych technik jazdy jest najlepsza przy zjeżdżaniu ze wzniesienia załadowanym samochodem ciężarowym?', 'Zjeżdżanie na odpowiednio dobranym biegu i z użyciem retardera.', 'Zjeżdżanie na możliwie najwyższym biegu i korygowanie prędkości wyłącznie hamulcem zasadniczym.', 'Zjeżdżanie na biegu neutralnym i korygowanie prędkości hamulcem zasadniczym.', 'A', '', 'SPECJALISTYCZNY', 3, 'C,C1', 'pjm11527.wmv', 'pjm11527a.wmv', 'pjm11527b.wmv', 'pjm11527c.wmv', 'Which of the following driving techniques is the best when driving a loaded lorry downhill?', 'Driving downhill with an appropriately chosen gear and using the retarder.', 'Driving downhill with the highest possible gear and adjusting the speed by using the service brake.', 'Driving downhill with the neutral gear and adjusting the speed by using the service brake.', 'Welche der genannten Fahrtechniken ist am besten anzuwenden, wenn man mit einem beladenen Lastkraftwagen von einer  Steigung herunter fährt?', 'Herunterfahren mit eingelegtem, richtig angepasstem Gang und unter Einsatz vom Retarder.', 'Herunterfahren mit eingelegtem, möglichst hohem Gang, wobei die Geschwindigkeit nur mit der Hauptbremse korrigiert wird.', 'Herunterfahren im Leerlauf, wobei die Geschwindigkeit mit der Hauptbremse korrigiert wird.', 'Яка з перерахованих технік їзди є найкращою під час спуску з пагорба завантаженим вантажним автомобілем?', 'Спуск на правильно підібраній передачі з використанням ретардера.', 'Спуск на якомога вищій передачі та корекція швидкості виключно основним гальмом.', 'Спуск на нейтральній передачі та корекція швидкості основним гальмом'),
(3191, 11528, 'Co grozi kierowcy, który samochodem ciężarowym przewozi o trzy osoby więcej od liczby miejsc wpisanej w dowodzie rejestracyjnym pojazdu?', 'Zatrzymanie prawa jazdy na okres 3 miesięcy.', 'Zatrzymanie prawa jazdy na okres 3 miesięcy i kontrolne sprawdzenie kwalifikacji.', 'Zatrzymanie prawa jazdy na okres 6 miesięcy.', 'A', '', 'SPECJALISTYCZNY', 2, 'B,C', '', '', '', '', 'What is the penalty for a lorry driver carrying three persons more than the number of seats stated on the vehicle\'s registration document?', 'Retention of driving licence for 3 months.', 'Retention of driving licence for 3 months and a driver qualification check.', 'Retention of driving licence for 6 months.', 'Was droht einem LkW-Fahrer, der mit dem LkW um drei Personen mehr befördert, als die Anzahl der im Fahrzeugschein eingetragenen Plätze?', 'Aussetzung der Fahrerlaubnis für 3 Monate.', 'Aussetzung der Fahrerlaubnis für 3 Monate und Überprüfung der Qualifikationen.', 'Aussetzung der Fahrerlaubnis für 6 Monate.', 'Яке покарання загрожує водієві, який перевозить у вантажівці на три особи більше, ніж зазначено в свідоцтві про реєстрацію транспортного засобу?', 'Вилучення посвідчення водія на 3 місяці.', 'Вилучення посвідчення водія на 3 місяці та контроль кваліфікації.', 'Вилучення посвідчення водія на 6 місяців.'),
(3192, 11531, 'Jedziesz drogą z pierwszeństwem. Czy w tej sytuacji, w razie potrzeby, należy powstrzymać się od dalszej jazdy?', '', '', '', 'T', 'GMD29_2_org.mp4', 'PODSTAWOWY', 2, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'You are driving on a priority road. In this situation, should you refrain from driving further, if necessary?', '', '', '', 'Sie fahren die Vorfahrtsstraße. Soll man in dieser Situation die weitere Fahrt einstellen?', '', '', '', 'Ви їдете по дорозі з перевагою. Чи, у цій ситуації, у разі потреби, Вам потрібно утриматися від подальшого руху, (з огляду на обставини)?', '', '', ''),
(3193, 12478, 'Co grozi kierowcy autobusu, z wyłączeniem autobusu publicznego transportu zbiorowego w gminach z przewidzianymi miejscami stojącymi, za przewóz więcej niż pięciu osób od liczby miejsc wpisanej w dowodzie rejestracyjnym pojazdu?', 'Zatrzymanie prawa jazdy na okres 3 miesięcy.', 'Kontrolne sprawdzenie kwalifikacji.', 'Mandat karny w wysokości 500 zł i 10 punktów karnych.', 'A', '', 'SPECJALISTYCZNY', 2, 'D', '', '', '', '', 'What is the penalty for a bus driver, excluding a municipal public transport bus with designated standing places, for carrying more than five persons in excess of the number of seats stated in the vehicle registration document?', 'Retention of driving licence for 3 months.', 'Driver qualification check.', 'A fine of PLN 500 and 10 penalty points.', 'Was droht einem Busfahrer, ausgenommen  Busse des öffentlichen Passagierverkehr in Gemeinden mit vorgesehenen Stehplätzen, für den Transport von über 5 Personen über die Anzahl der im Fahrzeugschein eingetragenen Plätze?', 'Aussetzung der Fahrerlaubnis für 3 Monate.', 'Kontrollmäßige Überprüfung der Qualifikationen.', 'ein Strafzettel in Höhe von 500 PLN und 10 Strafpunkte.', '', '', '', ''),
(3194, 12528, 'Czy włączając się do ruchu musisz zachować szczególną ostrożność?', '', '', '', 'T', '1818ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'Are you required to exercise extreme caution when merging into traffic?', '', '', '', 'Soll man beim Einordnen in den Verkehr besonders vorsichtig sein?', '', '', '', 'Чи розпочинаючи рух потрібно бути особливо обережним?', '', '', ''),
(3195, 12556, 'Czy postój pojazdu bezpośrednio za widocznym słupkiem wskaźnikowym jest zabroniony?', '', '', '', 'T', '1837ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'Is it prohibited to stop a vehicle directly behind a visible indicator post?', '', '', '', 'Ist das Parken direkt hinter dem Markpfahl verboten?', '', '', '', 'Чи заборонено паркувати автомобіль безпосередньо за знаком додаткового попередження, який Ви бачите?', '', '', ''),
(3196, 12562, 'Czy w tej sytuacji musisz umożliwić włączenie się do ruchu pojazdowi ciężarowemu?', '', '', '', 'N', '1841ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'Are you required to permit a lorry to merge into traffic in this situation?', '', '', '', 'Soll man in dieser Situation dem sich einordnenden LkW dies ermöglichen?', '', '', '', 'Чи, у цій ситуації, Ви зобов\'язані дати можливість вантажівці приєднатися до руху (розпочати рух)?', '', '', ''),
(3197, 12564, 'Czy w tej sytuacji masz obowiązek zatrzymać pojazd przed przejazdem kolejowym?', '', '', '', 'N', '1842ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'In this situation, are you obliged to stop your vehicle before the level crossing?', '', '', '', 'Sollen Sie in dieser Situation vor dem Bahnübergang anhalten?', '', '', '', 'Чи зобов\'язані Ви, у цій ситуації, зупиняти транспортний засіб перед залізничним переїздом?', '', '', ''),
(3198, 12575, 'Czy w tej sytuacji wolno kontynuować jazdę lewym pasem jeżeli prawy pas jest wolny?', '', '', '', 'N', '1850ztV.mp4', 'PODSTAWOWY', 2, 'B', '', '', '', '', 'In this situation, is it permissible to continue driving in the left lane if the right lane is free?', '', '', '', 'Darf man in der Situation weiterhin linke Spur fahren, falls die rechte Spur frei ist?', '', '', '', 'Чи можна, у цій ситуації, продовжувати рух по лівій смузі, якщо права смуга вільна?', '', '', ''),
(3199, 12605, 'Czy w tej sytuacji należy zachować ostrożność i bezpieczny odstęp od wymijanego pojazdu?', '', '', '', 'T', '1868ztV.mp4', 'PODSTAWOWY', 2, 'B', '', '', '', '', 'Should you exercise caution in this situation and keep a safe distance from the passing vehicle coming from the opposite direction?', '', '', '', 'Soll man in dieser Situation vorsichtig sein und einen Sicherheitsabstand zum umfahrenen Fahrzeug einhalten?', '', '', '', 'Чи у цій ситуації потрібно бути обережним і триматися на безпечній відстані від зустрічного транспортного засобу, щоб з ним розминутися без проблем?', '', '', ''),
(3200, 12618, 'Czy za tym znakiem wolno Ci zwiększyć prędkość do 130 km/h?', '', '', '', 'N', '1875ztV.mp4', 'PODSTAWOWY', 1, 'B', '', '', '', '', 'Are you allowed to increase your speed to 130 km/h beyond this sign?', '', '', '', 'Darf man hinter diesem Zeichen die Geschwindigkeit bis 130 km/h erhöhen?', '', '', '', 'Чи після проїзду цього знака Вам дозволяється збільшити швидкість до 130 км/год?', '', '', ''),
(3201, 12640, 'Czy w tak oznakowanym miejscu wolno Ci zmienić pas ruchu?', '', '', '', 'N', '1887ztV.mp4', 'PODSTAWOWY', 2, 'B', '', '', '', '', 'Are you permitted to change lanes at a point marked in this way?', '', '', '', 'Darf man an einer folgendermaßen ausgeschilderten Stelle die Fahrspur  wechseln?', '', '', '', 'Чи дозволяється перестроюватися (змінювати смугу руху) в так позначеному місці?', '', '', ''),
(3202, 12714, 'Czy za tym znakiem należy spodziewać się trzech niebezpiecznych zakrętów, z których wszystkie mogą być w lewo?', '', '', '', 'T', '1928ztV.mp4', 'PODSTAWOWY', 2, 'B', '', '', '', '', 'Should you expect three dangerous bends beyond this sign, all of which may be to the left?', '', '', '', 'Soll man nach diesem Zeichen  drei gefährliche Kurven erwarten, von denen alle nach links sein können?', '', '', '', 'Чи варто очікувати після цього знаку три небезпечні повороти, з яких всі три можуть бути вліво?', '', '', ''),
(3203, 12737, 'Czy ten znak ostrzega o możliwości wystąpienia gołoledzi na jezdni?', '', '', '', 'T', '1937ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'Does this sign warn of the possibility of ice on the roadway?', '', '', '', 'Warnt dieses Zeichen vor möglichem Glatteis auf der Fahrbahn?', '', '', '', 'Чи попереджає цей знак про можливість ожеледиці на дорозі?', '', '', ''),
(3204, 12741, 'Czy ten znak ostrzega o niebezpiecznym zakręcie w prawo?', '', '', '', 'T', '1939ztV.mp4', 'PODSTAWOWY', 2, 'B', '', '', '', '', 'Does this sign warn of a dangerous turn to the right?', '', '', '', 'Warnt das Zeichen vor einer gefährlichen Kurve nach rechts?', '', '', '', 'Чи цей знак попереджає про небезпечний поворот вправо?', '', '', ''),
(3205, 12779, 'Czy wyprzedzając rowerzystę musisz zachować szczególną ostrożność?', '', '', '', 'T', '1952ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'Do you have to exercise extra caution when overtaking the cyclist?', '', '', '', 'Soll man beim Überholen eines Radfahrers besonders vorsichtig sein?', '', '', '', 'Чи потрібно бути особливо обережним, обганяючи велосипедиста?', '', '', ''),
(3206, 12786, 'Czy na najbliższym skrzyżowaniu musisz ustąpić pierwszeństwa pojazdom nadjeżdżającym z lewej strony?', '', '', '', 'T', '1955ztV.mp4', 'PODSTAWOWY', 2, 'B', '', '', '', '', 'Are you obliged to yield the right of way to vehicles approaching from the left at the nearest junction?', '', '', '', 'Sollen Sie in der nächsten Kreuzung den von links kommenden Fahrzeugen Vorfahrt gewähren?', '', '', '', 'Чи потрібно на найближчому перехресті дати дорогу автомобілям, які наближаються зліва?', '', '', ''),
(3207, 12825, 'Czy w tej sytuacji masz prawo wyprzedzić pojazd szynowy?', '', '', '', 'T', '1970ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'Are you permitted to overtake a rail vehicle in this situation?', '', '', '', 'Dürfen Sie in dieser Situation das Schienenfahrzeug überholen?', '', '', '', 'Чи дозволено Вам обганяти рейковий транспортний засіб у цій ситуації?', '', '', ''),
(3208, 12826, 'Czy w tej sytuacji zabronione jest wyprzedzanie pojazdu szynowego?', '', '', '', 'N', '1970ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'Is it prohibited to overtake a rail vehicle in this situation?', '', '', '', 'Ist es in dieser Situation verboten, das Schienenfahrzeug zu überholen?', '', '', '', 'Чи забороняється, в цій ситуації, обгін рейкового транспортного засобу?', '', '', ''),
(3209, 12832, 'Czy zbliżając się do przejścia dla pieszych masz obowiązek obserwować jego otoczenie?', '', '', '', 'T', '1974ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'When approaching a pedestrian crossing, are you obliged to observe the surrounding area?', '', '', '', 'Wenn Sie sich einem Fußgängerüberweg nähern, sollen Sie seine Umgebung beobachten?', '', '', '', 'Чи зобов’язані Ви, наближаючись до пішохідного переходу, стежити за його оточенням?', '', '', ''),
(3210, 12890, 'Czy prędkość jazdy i odstęp od innych uczestników ruchu drogowego należy dostosować do stanu nawierzchni?', 'Tak, ale tylko w obszarze zabudowanym.', 'Tak, ponieważ stan nawierzchni ma istotny wpływ na drogę hamowania.', 'Tak, ale tylko podczas opadów śniegu.', 'B', 'Bb1_5005pic-zt.jpg', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'Should speed and distance from other road users be adapted to the road surface condition?', 'Yes, but only in built-up areas.', 'Yes, because the condition of the road surface has a significant impact on braking distances.', 'Yes, but only during snowfall.', 'Soll man die  Fahrtgeschwindigkeit und  den  Abstand zu  anderen Verkehrsteilnehmern an den Fahrbahnzustand anpassen?', 'Ja, aber  nur in geschlossener Ortschaft.', 'Ja, weil der  Fahrbahnzustand einen wesentlichen Einfluss auf den Bremsweg hat.', 'Ja, aber nur  beim Schneefall.', 'Чи потрібно регулювати швидкість руху та відстань до інших учасників дорожнього руху в залежності від стану дорожнього покриття?', 'Так, але тільки в населених пунктах.', 'Так, тому що стан дорожнього покриття має істотний вплив на гальмівний шлях.', 'Так, але тільки під час снігопаду.'),
(3211, 12942, 'Czy prędkość dopuszczalna 50 km/h obowiązuje na obszarze zabudowanym przez całą dobę?', 'Tak.', 'Nie, tylko od godziny 5:00 do 23:00.', 'Nie, tylko od zmierzchu do świtu.', 'A', 'Ba1_6011ztVpic.jpg', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'Does the 50 km/h speed limit apply 24 hours a day in built-up areas?', 'Yes', 'No, only from 5 a.m. to 11 p.m.', 'No, only from dusk to dawn.', 'Gilt die zulässige Höchstgeschwindigkeit 50 km/h in geschlossenen Ortschaften rund um die Uhr?', 'Ja.', 'Nein,  nur von 5:00 bis 23:00  Uhr.', 'Nein, nur von der Abenddämmerung bis zur Morgendämmerung.', 'Чи обмеження швидкості до 50 км/год діє в межах, визначених знаками початок забудови населеного пункту і кінець забудови населеного пункту цілодобово?', 'Так.', 'Ні, тільки з 5:00 до 23:00.', 'Ні, тільки від сутінок до світанку.'),
(3212, 13005, 'Czy zbliżając się do przejścia dla pieszych, masz obowiązek obserwować jego otoczenie?', '', '', '', 'T', '1919ztVX.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'When approaching a pedestrian crossing, are you obliged to observe the surrounding area?', '', '', '', 'Wenn Sie sich einem Fußgängerüberweg nähern, sollen Sie seine Umgebung beobachten?', '', '', '', 'Чи зобов’язані Ви стежити за оточенням пішохідного переходу, наближаючись до нього?', '', '', ''),
(3213, 13006, 'Czy w tej sytuacji wolno Ci kontynuować jazdę bez zatrzymania przed przejściem dla pieszych?', '', '', '', 'N', '1990ztV.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'In this situation, are you allowed to continue driving without stopping before the pedestrian crossing?', '', '', '', 'Dürfen Sie in dieser Situation weiter fahren, ohne vor dem Fußgängerüberweg anzuhalten?', '', '', '', 'Чи дозволено Вам, у цій ситуації, продовжувати рух без зупинки перед пішохідним переходом?', '', '', ''),
(3214, 13034, 'Czy w widocznej sytuacji z tego pasa ruchu dopuszczalne jest tylko skręcanie w lewo?', '', '', '', 'N', 'Slajd385_cen_1024x576.jpg', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'In the visible situation, is it only permissible to turn left from this lane?', '', '', '', 'Ist in der gezeigten Situation in dieser Fahrspur nur das Linksabbiegen möglich?', '', '', '', 'Чи з цієї смуги руху дозволяється повертати лише ліворуч, у ситуації, яка перед Вами?', '', '', ''),
(3215, 13035, 'Czy prowadząc pojazd silnikowy z przyczepą w strefie zamieszkania masz prawo jechać z prędkością 30 km/h?', 'Tak, ale tylko po zmroku.', 'Tak.', 'Nie.', 'C', 'Slajd_001500_1024x576.jpg', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'When driving a motor vehicle with a trailer in a residential area, are you entitled to drive at 30 km/h?', 'Yes, but only after nightfall.', 'Yes.', 'No.', 'Wenn Sie einen Krafwagen  mit  einem Anhänger im Wohngebiet fahren, dürfen Sie  30  km/h fahren?', 'Ja, aber nur nach der Abenddämmerung.', 'Ja.', 'Nein.', 'Чи може автомобіль з причепом рухатися зі швидкістю 30 км/год у житловій зоні?', 'Так, але тільки після настання темряви.', 'Так.', 'Ні.'),
(3216, 13037, 'Z jaką prędkością, kierując samochodem osobowym, należy poruszać się za tym pojazdem, jeżeli tunel znajduje się poza obszarem zabudowanym, a jego długość wynosi 600 m?', 'Z taką, aby utrzymywać, co najmniej 50 m odstępu.', 'Z taką, aby utrzymywć, co najmniej 80 m odstępu.', 'Z taką, aby utrzymywć, co najmniej 5 m odstępu.', 'A', 'mw12nn.jpg', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'At what speed should the driver of a passenger car drive behind this vehicle if the tunnel is outside a built-up area and its length is 600 m?', 'Such speed as to maintain a distance of at least 50 m.', 'Such speed as to maintain a distance of at least 80 m.', 'Such speed as to maintain a distance of at least 5 m.', 'Mit welcher Geschwindigkeit soll man mit einem PkW hinter diesem Fahrzeug fahren, falls der Tunnel sich außerhalb geschlossener Ortschaft befindet und seine Länge 600 m beträgt?', 'mit einer Geschwindigkeit, die erlaubt, wenigstens 50 m Abstand einzuhalten.', 'mit einer Geschwindigkeit, die erlaubt, wenigstens 80 m Abstand einzuhalten.', 'mit einer Geschwindigkeit, die erlaubt, wenigstens 5 m Abstand einzuhalten.', 'З якою швидкістю слід їхати за цим транспортним засобом, якщо тунель знаходиться поза населеним пунктом і його довжина становить 600 м?', 'З такою, яка дозволить дотримуватися дистанції не менше 50 м.', 'З такою, яка дозволить дотримуватися дистанції не менше 80 м.', 'З такою, яка дозволить дотримуватися дистанції не менше 5 м.'),
(3217, 13038, 'Jaki minimalny odstęp masz obowiązek zachować od jadącego przed Tobą pojazdu, jeżeli poruszasz się samochodem osobowym tą drogą z maksymalną dozwoloną prędkością?', '60 m.', '70 m.', '80 m.', 'B', 'mw18.JPG', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'What is the minimum distance you must maintain from the vehicle in front of you if you are travelling on this road with your passenger car at the maximum permitted speed?', '60 m.', '70 m.', '80 m.', 'Welchen minimalen Abstand sollen Sie zum vorausfahrenden Fahrzeug einhalten, falls Sie mit einem PkW mit zulässiger Höchstgeschwindigkeit diese Straße fahren?', '60 m.', '70 m.', '80 m.', 'Якої мінімальної дистанції Ви повинні дотримуватися від транспортного засобу, що рухається попереду, якщо Ви їдете легковим автомобілем по цій дорозі з максимально дозволеною швидкістю?', '60 м', '70 м', '80 м'),
(3218, 13040, 'Czy konstrukcja motoroweru powinna ograniczać jego prędkość jazdy?', 'Nie', 'Tak, do 40 km/h', 'Tak, do 45 km/h.', 'C', '', 'SPECJALISTYCZNY', 3, 'AM', '', '', '', '', 'Should the design of the moped limit its speed?', 'No.', 'Yes, up to 40 km/h', 'Yes, up to 45 km/h', 'Sollte die Mopedbauweise seine Fahrtgeschwindigkeit beschränken?', 'Nein.', 'Ja, bis 40 km/h.', 'Ja, bis 45 km/h.', '', '', '', ''),
(3219, 13041, 'Z jaką maksymalną prędkością wolno poruszać się za tymi znakami, gdy w bocznym wózku motocykla przewozisz sześcioletnie dziecko?', '50 km/h.', '40 km/h.', '70 km/h.', 'B', 'mw1.jpg', 'SPECJALISTYCZNY', 3, 'A,A1,A2', '', '', '', '', 'What is the maximum speed allowed beyond these signs when you are carrying a six-year-old child in the sidecar of a motorbike?', '50 km/h.', '40 km/h.', '70 km/h.', 'Mit welcher Höchstgeschwindigkeit darf man hinter diesen Verkehrszeichen fahren,  wenn im Motorradbeiwagen ein 6-jähriges Kind transportiert wird?', '50 km/h.', '40 km/h.', '70 km/h.', '', '', '', ''),
(3220, 13042, 'Jaki odstęp od poprzedzającego pojazdu należy zachować kierując samochodem osobowym tą drogą?', 'Co najmniej 30 m, jeżeli poruszam się z prędkością 60 km/h.', 'Niezbędny do uniknięcia zderzenia w razie hamowania lub zatrzymania się poprzedzającego pojazdu.', 'Dowolny, jeżeli pojazd poprzedzający jadący tym samym pasem ruchu porusza się ze stałą prędkością.', 'B', 'mw19.jpg', 'SPECJALISTYCZNY', 3, 'B,B1', '', '', '', '', 'What distance from the preceding vehicle should you maintain when driving a passenger car on this road?', 'At least 30 m if I am travelling at 60 km/h.', 'A distance necessary to avoid a collision should the preceding vehicle brake or stop.', 'Any distance, if the preceding vehicle in the same lane is travelling at a constant speed.', 'Welchen Abstand zum vorausfahrenden Fahrzeug soll man beim Fahren mit einem PkW auf dieser Straße einhalten?', 'Wenigstens 30 m, falls ich mit der Geschwindigkeit 60 km/h fahre.', 'Mit einem Abstand, der ermöglicht, einen Zusammenstoß zu verhindern, falls das vorausfahrende Fahrzeug bremst bzw. anhält.', 'Mit einem beliebigen Abstand, falls das auf der gleichen Spur vorausfahrende Fahrzeug mit konstanter Geschwindigkeit fährt.', 'Якої дистанції до транспортного засобу, що їде попереду, слід дотримувати під час руху легковим автомобілем цією дорогою?', 'Принаймні 30 м, якщо я рухаюся зі швидкістю 60 км/год.', 'Дистанції, необхідної для уникнення зіткнення, коли автомобіль попереду загальмує або зупиниться.', 'Будь-якої, якщо транспортний засіб, що їде попереду по тій же смузі що і я, рухається з постійною швидкістю.'),
(3221, 13044, 'Jaki minimalny odstęp należy zachować od poprzedzającego pojazdu, kierując samochodem ciężarowym o dmc 6 t z maksymalną dopuszczalną prędkością obowiązującą na tej drodze?', '70 m.', '40 m.', '35 m.', 'B', 'mw25.jpg', 'SPECJALISTYCZNY', 3, 'C,C1', '', '', '', '', 'What is the minimum distance you must maintain from the vehicle in front of you when driving a 6-tonne lorry at the maximum permitted speed on this road?', '70 m.', '40 m.', '35 m.', 'Welchen Abstand zum vorausfahrenden Fahrzeug sollen Sie einhalten, wenn Sie einen LkW mit zulässigem Gesamtgewicht 6 t mit maximaler zugelassener Höchstgeschwindigkeit auf dieser Straße fahren?', '70 m.', '40 m.', '35 m.', 'Якої мінімальної дистанції слід дотримуватися від транспортного засобу, що їде попереду, під час керування вантажним автомобілем з дозволеною максимальною  масою 6 тонн при русі з максимально дозволеною швидкістю на даній ділянці дороги?', '70 м', '40 м', '35 м'),
(3222, 13046, ' Jaki minimalny odstęp masz obowiązek utrzymywać od pojazdu poprzedzającego?', 'Zawsze 50 m.', 'Taki aby inne wyprzedzające pojazdy mogły bezpiecznie wjechać w lukę utrzymywaną między tymi pojazdami.', '40 m, jeżeli poruszasz się z prędkością 80 km/h.', 'C', 'mw31.jpg', 'SPECJALISTYCZNY', 3, 'D,D1', '', '', '', '', 'What is the minimum distance you must maintain from the vehicle in front?', 'Always 50 m.', 'Such that other overtaking vehicles can safely enter the gap maintained between these vehicles.', '40 m if you are travelling at 80 km/h.', 'Welchen Mindestabstand sollen Sie zum vorausfahrenden Fahrzeug einhalten?', 'Immer 50 m.', 'Solch einen Abstand, dass die überholenden Fahrzeuge in die Lücke zwischen den Fahrzeugen einfahren können.', '40 m, wenn Sie mit der Geschwindigkeit 80 km/h fahren.', '', '', '', ''),
(3223, 13047, 'Z jaką prędkością nie wolno poruszać się motocyklem po tej drodze?', '20 km/h, bez względu na warunki panujące na drodze.', '140 km/h.', '80 km/h, jeżeli przewozisz 6 letnie dziecko.', 'C', 'mw3.jpg', 'SPECJALISTYCZNY', 3, 'A,A1,A2', '', '', '', '', 'At what speed is a motorbike not allowed to travel on this road?', '20 km/h, regardless of the prevailing road conditions.', '140 km/h.', '80 km/h if you are carrying a 6 year old child.', 'Mit welcher Geschwindigkeit darf man auf dieser Straße Motorrad fahren?', '20 km/h, unabhängig von den Bedingungen auf der Straße.', '140 km/h.', '80 km/h, falls ein 6-jähriges Kind transportiert wird.', '', '', '', ''),
(3224, 13048, 'Który ze znaków ograniczających dopuszczalną prędkość nie dotyczy kierującego motorowerem?', 'A.', 'B.', 'C.', 'C', 'mw5.jpg', 'SPECJALISTYCZNY', 3, 'AM', '', '', '', '', 'Which of the speed limit signs does not apply to the driver of a moped?', 'A.', 'B.', 'C.', 'Welches der die zulässige Geschwindigkeit begrenzenden Verkehrszeichen gilt nicht für den Mopedfahrer?', 'A.', 'B.', 'C.', '', '', '', ''),
(3225, 13049, 'Kogo dotyczy ograniczenie prędkości wyrażone tymi znakami?', 'Kierującego motorowerem.', 'Kierującego motocyklem.', 'Kierującego pojazdem silnikowym za wyjątkiem motocykla.', 'B', 'mw2n.jpg', 'SPECJALISTYCZNY', 3, 'A,A1,A2', '', '', '', '', 'Who does the speed limit expressed by these signs apply to?', 'The driver of a moped.', 'Motorbike rider.', 'The driver of a motor vehicle with the exception of a motorbike.', 'Für wen gilt die Geschwindigkeitsbegrenzung auf diesen Verkehrszeichen?', 'Für den Mopedfahrer.', 'Für den Motorradfahrer.', 'Für den Kraftfahrer, ausgenommen Motorradfahrer.', '', '', '', ''),
(3226, 13050, 'Z jaką maksymalną prędkością wolno poruszać się w obszarze zabudowanym, gdy czterokołowcem lekkim przewozisz pięcioletnie dziecko?', '45 km/h.', '40 km/h.', '50 km/h.', 'B', '', 'SPECJALISTYCZNY', 3, 'AM', '', '', '', '', 'What is the maximum speed permitted in a built-up area when you are carrying a five-year-old child on a light quadricycle?', '45 km/h.', '40 km/h.', '50 km/h.', 'Mit welcher maximalen Geschwindigkeit darf man in geschlossener Ortschaft fahren, wenn Sie mit einem leichten Quad ein fünfjähriges Kind befördern?', '45 km/h.', '40 km/h.', '50 km/h.', '', '', '', ''),
(3227, 13051, 'Z jaką prędkością wolno poruszać się tak oznakowaną drogą jednojezdniową kierując samochodem osobowym?', '140 km/h.', '100 km/h.', '120 km/h.', 'B', 'mw10.jpg', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'At what speed may one drive on a single carriageway road marked as such?', '140 km/h.', '100 km/h.', '120 km/h.', 'Mit welcher Geschwindigkeit darf man so ausgeschilderte Straße mit einer Fahrbahn mit einem PkW fahren?', '140 km/h.', '100 km/h.', '120 km/h.', 'З якою швидкістю можна їхати легковим автомобілем по дорозі з однією проїжджою частиною, позначеною таким знаком ?', '140 км/год', '100 км/год', '120 км/год'),
(3228, 13052, 'Na jakiej drodze obowiązuje kierującego zachowanie ściśle określonego minimalnego odstępu od pojazdu poprzedzającego?', 'Na drodze ekspresowej.', 'Na drodze dwujezdniowej co najmniej o dwóch pasach przeznaczonych dla każdego kierunku ruchu.', 'Na drodze jednojezdniowej poza obszarem zabudowanym.', 'A', '', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'On which road does the driver have to keep a strict minimum distance from the preceding vehicle?', 'On the expressway.', 'On a dual carriageway road with at least two lanes dedicated to each direction of traffic.', 'On a single carriageway road outside a built-up area.', 'Auf welcher Straße ist der Fahrer verpflichtet, einen strikt bestimmten Mindestabstand zum vorausfahrenden Fahrzeug einzuhalten?', 'Auf einer Schnellstraße.', 'Auf einer Zweibahnstraße mit wenigstens zwei Streifen für jede Fahrtrichtung.', 'auf einer Straße mit einer Fahrbahn außerhalb geschlossener Ortschaft.', 'На якій дорозі водій зобов\'язаний суворо дотримуватися визначеної мінімальної дистанції до автомобіля, що їде попереду?', 'На швидкісній дорозі (S).', 'На дорозі, що має 2 проїжджі частини і не менше двох смуг для кожного напрямку руху.', 'На дорозі з однією проїжджою частиною, поза населеним пунктом.'),
(3229, 13053, 'Jakie urządzenia wspomagania kierowcy ułatwiają właściwe utrzymanie odstępu od pojazdu poprzedzającego?', 'Tempomat adaptacyjny (aktywny).', 'Asystent pasa ruchu.', 'Elektroniczny układ stabilizacji toru jazdy.', 'A', '', 'SPECJALISTYCZNY', 3, 'D,D1', '', '', '', '', 'What driver assistance devices help to maintain a proper distance from the preceding vehicle?', 'Adaptive cruise control (active).', 'Lane keep assist system.', 'Electronic Stability Control.', 'Welche Ausrüstung erlaubt dem Fahrer einen richtigen Abstand zum vorausfahrenden Fahrzeug einzuhalten?', 'adaptiver Tempomat (aktiv).', 'Assistent der Fahrspur.', 'System der elektronischen Stabilitätskontrolle.', '', '', '', ''),
(3230, 13054, 'Jaka jest dopuszczalna prędkość pojazdu z urządzeniem wystającym do przodu więcej niż 1,5 m od siedzenia dla kierującego?', '40 km/h na obszarze zabudowanym.', '60 km/h poza obszarem zabudowanym.', '30 km/h bez względu na obszar w jakim się porusza.', 'B', '', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'What is the permissible speed limit for a vehicle with a device projecting forward more than 1.5 m from the driver\'s seat?', '40 km/h in built-up areas.', '60 km/h outside built-up areas.', '30 km/h regardless of the area in which it is travelling.', 'Wie ist die zulässige Höchstgeschwindigkeit eines Fahrzeugs mit einem nach vorne mehr als 1,5 m vom Fahrersitz hinausragenden Gerät?', '40 km/h in geschlossener Ortschaft.', '60 km/h außerhalb geschlossener Ortschaft.', '30 km/h unabhängig vom befahrenden Gebiet.', 'Яка максимально дозволена швидкість транспортного засобу з пристроєм, що виступає за його габарити спереду більше ніж на 1,5 м від сидіння водія?', '40 км/год у населених пунктах.', '60 км/год поза населеними пунктами.', '30 км/год незалежно від території, по якій він рухається.'),
(3231, 13056, 'Jaka jest dopuszczalna prędkość samochodu osobowego z przyczepą na tak oznakowanej drodze?', '70 km/h za znakiem zakazu.', '50 km/h.', '40 km/h.', 'B', 'mw16n.jpg', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'What is the permissible speed limit for a passenger car with a trailer on a road signposted as such?', '70 km/h beyond the prohibition sign.', '50 km/h.', '40 km/h.', 'Wie ist die zulässige Höchstgeschwindigkeit eines PkWs mit einem Anhänger auf der folgendermaßen ausgeschilderten Straße?', '70 km/h hinter dem Verbot.', '50 km/h.', '40 km/h.', 'Яка максимально дозволена швидкість легкового автомобіля з причепом на дорозі з таким знаком?', '70 км/год після заборонного знаку.', '50 км/год', '40 км/год'),
(3232, 13057, 'Jaka jest wymagana minimalna odległość między zorganizowanymi kolumnami motocykli poruszającymi się autostradą?', '200 m.', 'Równa połowie prędkości w km/h wyrażonej w metrach pierwszego motocyklisty na czele drugiej kolumny.', '500 m.', 'C', '', 'SPECJALISTYCZNY', 3, 'A,A1,A2', '', '', '', '', 'What is the required minimum distance between organised columns of motorbikes travelling on a motorway?', '200 m.', 'A distance equal to half the speed in km/h expressed in metres of the first motorcyclist at the head of the second column.', '500 m.', 'Wie ist der notwendige Mindestabstand zwischen organisierten Motorradgruppen auf einer Autobahn?', '200 m.', 'Der Abstand gleicht der Hälfte der km/h in Metern des ersten Motorradfahrers am Anfang der zweiten Motorradgruppe.', '500 m.', '', '', '', ''),
(3233, 13058, 'Z jaką prędkością wolno poruszać się po autostradzie kierując samochodem osobowym?', 'Zapewniającą panowanie nad pojazdem z uwzględnieniem warunków, w jakich ruch się odbywa, nie wyższą niż 140 km/h.', 'Uwzględniającą warunki atmosferyczne, w jakich ruch się odbywa / śnieżyca, ulewa itp./, nie mniejszą niż 40 km/h.', 'Dowolną zapewniającą panowanie nad pojazdem.', 'A', '', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'At what speed is a passenger car permitted to travel on a motorway?', 'At a speed of not more than 140 km/h, while maintaining control of the vehicle and taking into account the prevailing traffic conditions.', 'At a speed of not less than 40 km/h, taking into account the prevailing weather conditions (blizzard, downpour, etc.).', 'At any speed that ensures control of the vehicle.', 'Mit welcher Geschwindigkeit darf man auf der Autobahn mit einem PkW fahren?', 'Mit einer Geschwindigkeit, die die Kontrolle über dem Fahrzeug gewährt, nicht höher als 140 km/h.', 'Mit Beachtung der Wetterlage beim Verkehr (Schneesturm, Regen u.ä.), nicht weniger als 40 km/h.', 'Mit beliebiger Geschwindigkeit, die die Kontrolle über dem Fahrzeug gewährt.', 'З якою швидкістю можна їхати легковим автомобілем по автомагістралі (А)?', 'Зі швидкістю, яка забезпечує контроль над транспортним засобом з урахуванням дорожніх умов і яка не перевищує 140 км/год.', 'Зі швидкістю, яка враховує погодні умови, за яких відбувається рух (хуртовина, злива тощо), не меншою ніж 40 км/год.', 'З будь-якою, що забезпечує контроль над транспортним засобом.'),
(3234, 13059, 'Jaka jest maksymalna dopuszczalna prędkość autobusu na autostradzie?', '100 km/h, jeżeli spełnia dodatkowe warunki techniczne określone w przepisach.', '80 km/h każdego autobusu.', '70 km/h, jeżeli ciągnie przyczepę.', 'A', '', 'SPECJALISTYCZNY', 3, 'D,D1', '', '', '', '', 'What is the maximum speed permitted for a bus on a motorway?', '100 km/h if it meets the additional technical conditions stipulated by the legislation.', '80 km/h for any bus.', '70 km/h when towing a trailer.', 'Wie ist die zulässige Höchstgeschwindigkeit eines Busses auf der Autobahn?', '100 km/h, falls er zusätzliche technische Bedingungen in Vorschriften erfüllt.', '80 km/h für jeden Bus.', '70 km/h, falls der Bus einen Anhänger abschleppt.', '', '', '', ''),
(3235, 13060, 'Z jaką maksymalną prędkością kierującemu samochodem osobowym z przyczepą wolno jechać po tej drodze poza obszarem zabudowanym?', '80 km/h.', '100 km/h.', '90 km/h.', 'A', 'mw11n.jpg', 'SPECJALISTYCZNY', 3, 'B', '', '', '', '', 'What is the maximum speed the driver of a passenger car with a trailer is permitted to travel on this road outside built-up areas?', '80 km/h.', '100 km/h.', '90 km/h.', 'Wie ist die zulässige Höchstgeschwindigkeit eines PkWs mit Anhänger auf dieser Straße außerhalb geschlossener Ortschaft?', '80 km/h.', '100 km/h.', '90 km/h.', 'З якою максимальною швидкістю водій легкового автомобіля з причепом має право рухатися цією дорогою поза населеним пунктом?', '80 км/год', '100 км/год', '90 км/год'),
(3236, 13061, 'Z jaką dopuszczalną prędkością kierującemu autobusem wolno kontynuować jazdę za tym znakiem zakazu?', '70 km/h, jeżeli dmc autobusu nie przekracza 3,5 tony.', '70 km/h, bez względu na jego dmc.', '50 km/h ciągnącym przyczepę bez względu na dmc zespołu.', 'C', 'mw28n.jpg', 'SPECJALISTYCZNY', 3, 'D,D1', '', '', '', '', 'At what speed is the bus driver allowed to continue driving past this prohibition sign?', '70 km/h if the GVM (gross vehicle mass) of the bus does not exceed 3.5 tonnes.', '70 km/h, regardless of its GVM.', '50 km/h when towing a trailer regardless of the GVM of the combination.', 'Mit welcher zulässigen Höchstgeschwindigkeit darf der Busfahrer hinter diesem Verbot weiter fahren?', '70 km/h, falls das zulässige Gesamtgewicht des Busses keine 3,5 t übersteigt.', '70 km/h, unabhängig von seinem zulässigen Gesamtgewicht.', '50 km/h beim Anhängerabschleppen, unabhängig vom zulässigen Gesamtgewicht der Fahrzeuggruppe.', '', '', '', ''),
(3237, 13062, 'Jaki minimalny odstęp boczny należy zachować, wyprzedzając motocyklem kierującego rowerem?', '1 m.', '2 m.', '1,5 m, gdy jest to motocykl z bocznym wózkiem.', 'A', 'mw8.jpg', 'SPECJALISTYCZNY', 3, 'A,A1,A2', '', '', '', '', 'What is the minimum lateral distance you must maintain when overtaking a cyclist, with a motorbike?', '1 m.', '2 m.', '1.5 m, if it is a motorbike with a sidecar.', 'Welchen minimalen Seitenabstand soll man einhalten, wenn man mit einem Motorrad ein Fahrrad überholt?', '1 m.', '2 m.', '1,5 m, wenn dies ein Motorrad mit einem Beiwagen ist.', '', '', '', ''),
(3238, 13063, 'Z jaką prędkością wolno kontynuować jazdę samochodem osobowym za tymi znakami?', '30 km/h do najbliższego skrzyżowania a następnie 50 km/h.', '30 km/h do tablicy z nazwą początku miejscowości a następnie 90 km/h.', '30 km/h na całym odcinku drogi biegnącej na obszarze zabudowanym.', 'C', 'mw22.jpg', 'SPECJALISTYCZNY', 3, 'B,B1', '', '', '', '', 'At what speed is a passenger car allowed to continue driving beyond these signs?', '30 km/h to the nearest intersection and then 50 km/h.', '30 km/h to the signpost with information indicating the beginning of a city, and then 90 km/h.', '30 km/h on the entire stretch of road running through a built-up area.', 'Mit welcher Geschwindigkeit darf man mit einem PkW hinter diesen Verkehrszeichen fahren?', '30 km/h bis zur nächsten Kreuzung und danach 50 km/h.', '30 km/h bis zum Ortschaftsschild und danach 90 km/h.', '30 km/h auf der ganzen Straßenstrecke in geschlossener Ortschaft.', 'З якою швидкістю легковий автомобіль може продовжити рух після проїзду цих знаків?', '30 км/год до найближчого перехрестя, а потім 50 км/год.', '30 км/год до таблички з назвою початку населеного пункту і далі 90 км/год.', '30 км/год на всій ділянці дороги в межах забудови населеного пункту (тобто до знаку кінець забудови населеного пункту).'),
(3239, 13064, 'Jaka jest dopuszczalna prędkość czterokołowca na obszarze zabudowanym?', '50 km/h bez względu na jego dopuszczalną masę całkowitą.', '40 km/h, jeżeli jego dopuszczalna masa całkowita przekracza 3,5 t.', '20 km/h.', 'A', '', 'SPECJALISTYCZNY', 3, 'B,B1', '', '', '', '', 'What is the permissible speed limit for a quadricycle in a built-up area?', '50 km/h regardless of its gross vehicle weight rating.', '40 km/h if its gross vehicle weight exceeds 3.5 t.', '20 km/h.', 'Wie ist die zulässige Höchstgeschwindigkeit eines Quads in geschlossener Ortschaft?', '50 km/h unabhängig von seinem zulässigen Gesamtgewicht.', '40 km/h, wenn sein zulässiges Gesamtgewicht 3,5 t übersteigt.', '20 km/h.', 'Яке обмеження швидкості для квадроцикла (чотириколісного мікроавтомобіля) в межах забудови населеного пункту (тобто від знака початок забудови населеного пункта до знака кінець забудови населеного пункта ?', '50 км/год незалежно від його дозволеної максимальної маси.', '40 км/год, якщо його дозволена максимальна маса перевищує 3,5 т.', '20 км/год'),
(3240, 13067, 'Czy w tej sytuacji masz obowiązek ustąpienia pierwszeństwa pieszemu?', '', '', '', 'T', '4 dod.2021.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1', '', '', '', '', 'In this situation, are you obliged to yield the right of way to the pedestrian?', '', '', '', 'Sollen Sie in dieser Situation dem Fußgänger den Vorrang gewähren?', '', '', '', 'Чи зобов\'язані Ви уступити дорогу пішоходу в цій ситуації?', '', '', ''),
(3241, 13069, 'Czy w tej sytuacji wystarczy, że zachowasz wyłącznie szczególną ostrożność?', '', '', '', 'N', '2 dod.2021.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In this situation, is it enough if you only exercise extreme caution?', '', '', '', 'Reicht es in dieser Situation aus, dass Sie besonders vorsichtig sind?', '', '', '', 'Чи, у цій ситуації, достатньо бути тільки особливо обережним?', '', '', ''),
(3242, 13070, 'Czy w tej sytuacji masz obowiązek zmniejszenia prędkości?', '', '', '', 'N', '2-9.2021.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you obliged in this situation to reduce your speed?', '', '', '', 'Sollen Sie in dieser Situation die Geschwindigkeit reduzieren?', '', '', '', 'Чи зобов\'язані Ви зменшити швидкість у цій ситуації?', '', '', ''),
(3243, 13071, 'Czy w tej sytuacji masz obowiązek zachować jedynie ostrożność?', '', '', '', 'N', '2-9.2021.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In this situation, are you only obliged to be cautious?', '', '', '', 'Sollen Sie in dieser Situation nur vorsichtig sein?', '', '', '', 'Чи, у цій ситуації, Ви маєте обов\'язок лише проявити обережність?', '', '', ''),
(3244, 13072, 'Czy w tej sytuacji, zbliżając się do przejścia dla pieszych, masz obowiązek zmniejszyć prędkość?', '', '', '', 'N', '3-9.2021.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you obliged in this situation to reduce your speed when approaching a pedestrian crossing?', '', '', '', 'Sollen Sie beim Ankommen zum Fußgängerüberweg die Geschwindigkeit reduzieren?', '', '', '', 'Чи, у цій ситуації, наближаючись до пішохідного переходу, Ви зобов’язані зменшити швидкість?', '', '', ''),
(3245, 13074, 'Czy w tej sytuacji, nie widząc innych uczestników ruchu drogowego, jesteś zwolniony z obowiązku zachowania szczególnej ostrożności?', '', '', '', 'N', '5-9.2021.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In this situation, if you do not see other road users, are you absolved of the obligation to exercise extra caution?', '', '', '', 'Können Sie in dieser Situation, wenn Sie keine anderen Verkehrsteilnehmer sehen, von besonderer Vorsicht absehen?', '', '', '', 'Чи, у цій ситуації, якщо Ви не бачите інших учасників дорожнього руху, Ви звільняєтеся від обов’язку проявляти особливу обережність?', '', '', ''),
(3246, 13076, 'Czy w tej sytuacji dozwolony jest przejazd przez skrzyżowanie bez zmniejszenia prędkości pojazdu?', '', '', '', 'T', '6-9.2021.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In this situation, is it permissible to drive through the intersection without reducing the vehicle speed?', '', '', '', 'Ist in dieser Situation die Fahrt über die Kreuzung erlaubt, ohne die Fahrzeuggeschwindigkeit zu senken?', '', '', '', 'Чи можна в даній ситуації проїхати перехрестя без зниження швидкості?', '', '', ''),
(3247, 13080, 'Czy w tej sytuacji znak ustąp pierwszeństwa ustawiony przed skrzyżowaniem ma zastosowanie?', '', '', '', 'N', '5-9.2021 bis.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Does the give way sign placed before the intersection apply in this situation?', '', '', '', 'Findet in dieser Situation das Verkehrszeichen Vorrang gewähren vor der Kreuzung die Anwendung?', '', '', '', 'Чи діє в даній ситуації знак «уступи дорогу», розміщений перед перехрестям?', '', '', ''),
(3248, 13082, 'Czy w tej sytuacji przejeżdżając na wprost przez skrzyżowanie, możesz zrezygnować z zachowania szczególnej ostrożności?', '', '', '', 'N', '7-9.2021.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In this situation, when driving straight through an intersection, can you refrain from taking extra care?', '', '', '', 'Dürfen Sie beim Geradeausfahren über die Kreuzung von besonderer Vorsicht absehen?', '', '', '', 'Проїжджаючи прямо через перехрестя в такій ситуації, чи можете Ви відмовитися від прояву особливої обережності?', '', '', ''),
(3249, 13085, 'Czy w tej sytuacji wolno Ci zawrócić pod warunkiem upewnienia się, że nie utrudnisz ruchu innym jego uczestnikom?', '', '', '', 'N', '3-9.2021 bis.mp4', 'PODSTAWOWY', 3, 'B', '', '', '', '', 'In this situation, are you permitted to make a U-turn if you are sure it will not obstruct other traffic users?', '', '', '', 'Darf man in dieser Situation umkehren, soweit man den anderen Verkehrsteilnehmern die Fahrt nicht behindert?', '', '', '', 'Чи дозволено Вам у цій ситуації розвернутися, за умови що Ви переконаєтеся, що не заважаєте іншим учасникам дорожнього руху?', '', '', ''),
(3250, 13088, 'Z jaką maksymalną dopuszczalną prędkością możesz holować inny pojazd?', '50 km/h w obszarze zabudowanym.', '60 km/h poza obszarem zabudowanym.', '80 km/h na drodze dwujezdniowej o co najmniej dwóch pasach przeznaczonych dla każdego kierunku ruchu.', 'B', '', 'SPECJALISTYCZNY', 3, 'B,B1', '', '', '', '', 'At what maximum permissible speed can you tow another vehicle?', '50 km/h in built-up areas.', '60 km/h outside built-up areas.', '80 km/h on a dual carriageway road with at least two lanes in each direction.', 'Wie ist die zulässige Höchstgeschwindigkeit eines Fahrzeugs beim Abschleppen eines anderen Fahrzeugs?', '50 km/h in geschlossener Ortschaft.', '60 km/h außerhalb der geschlossenen Ortschaft.', '80 km/h auf einer Zweibahnstraße mit wenigstens zwei Streifen für jede Fahrtrichtung.', 'З якою максимальною швидкістю Ви можете буксирувати інший транспортний засіб?', '50 км/год у межах забудови населеного пункту.', '60 км/год поза зоною забудови населеного пункту.', '80 км/год на дорозі, що має 2 проїжджі частини і не менше двох смуг для кожного напрямку руху.'),
(3251, 13101, 'Czy w tej sytuacji zbliżasz się do przecięcia z torowiskiem, które jest z pierwszeństwem przejazdu?', '', '', '', 'T', 'GM_ W1(352)1.jpg', 'PODSTAWOWY', 1, 'PT', '', '', '', '', 'In this situation, are you approaching an intersection with a track that has the right of way?', '', '', '', 'Kommen Sie in dieser Situation zur Kreuzung mit Schienenverkehr, der Vorrang hat?', '', '', '', '', '', '', ''),
(3252, 13102, 'Czy w tej sytuacji masz obowiązek ustąpienia pierwszeństwa pojazdom poruszającym się drogą poprzeczną?', '', '', '', 'T', 'GM_W1_353_.mp4', 'PODSTAWOWY', 1, 'PT', '', '', '', '', 'In this situation, are you obliged to yield the right of way to vehicles travelling on the transverse road?', '', '', '', 'Sollen Sie in dieser Situation den auf der Querstraße fahrenden Fahrzeugen Vorfahrt gewähren?', '', '', '', '', '', '', ''),
(3253, 13105, 'Czy masz obowiązek wyłączyć światła przeciwmgłowe tylne, jeżeli widoczność jest większa niż 50 m?', '', '', '', 'T', 'GM_W14(155)1.jpg', 'PODSTAWOWY', 1, 'PT', '', '', '', '', 'Are you obliged to switch off your rear fog lights if visibility is more than 50 m?', '', '', '', 'Soll man hinteres Nebellicht einschalten, falls die Sicht weiter als 50 m ist?', '', '', '', '', '', '', ''),
(3254, 13106, 'Czy masz obowiązek ustąpić pierwszeństwa pieszemu zbliżającemu się do przejścia dla pieszych?', '', '', '', 'N', 'GM_W16_316_317.mp4', 'PODSTAWOWY', 3, 'PT', '', '', '', '', 'Are you obliged to yield the right of way to a pedestrian approaching a pedestrian crossing?', '', '', '', 'Sollen Sie dem zum Fußgängerüberweg kommenden Fußgänger den Vorrang gewähren?', '', '', '', '', '', '', ''),
(3255, 13107, 'Czy w tej sytuacji masz obowiązek zwiększyć uwagę w stopniu umożliwiającym odpowiednio szybkie reagowanie?', '', '', '', 'T', 'GM_W16_327n.mp4', 'PODSTAWOWY', 3, 'PT', '', '', '', '', 'In this situation, are you obliged to heighten your attention to the extent that permits you to react quickly enough?', '', '', '', 'Sollen Sie in dieser Situation mehr aufmerksam sein, damit Sie entsprechend schnell reagieren können?', '', '', '', '', '', '', ''),
(3256, 13108, 'Czy w tej sytuacji masz obowiązek zatrzymać pojazd?', '', '', '', 'T', 'GM_W16(318,319).mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Are you obliged in this situation to stop the vehicle?', '', '', '', 'Sollen Sie in dieser Situation anhalten?', '', '', '', 'Чи зобов\'язані Ви зупинити транспортний засіб у цій ситуації?', '', '', ''),
(3257, 13109, 'Czy w tej sytuacji możesz kontynuować jazdę?', '', '', '', 'N', 'GM_W16(318,319)NN.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Can you continue driving in this situation?', '', '', '', 'Dürfen Sie in dieser Situation weiter fahren?', '', '', '', 'Чи можете Ви продовжувати рух у цій ситуації?', '', '', '');
INSERT INTO `pula_pytan` (`ID`, `nr_pyt`, `pyt`, `odp_a`, `odp_b`, `odp_c`, `poprawna`, `media`, `zakres`, `pkt`, `kategorie`, `media_migowy_pyt`, `media_migowy_odp_a`, `media_migowy_odp_b`, `media_migowy_odp_c`, `pyt_en`, `odp_a_en`, `odp_b_en`, `odp_c_en`, `pyt_de`, `odp_a_de`, `odp_b_de`, `odp_c_de`, `pyt_ua`, `odp_a_ua`, `odp_b_ua`, `odp_c_ua`) VALUES
(3258, 13112, 'Czy w tej sytuacji musisz ograniczyć zaufanie do pieszego?', '', '', '', 'T', 'GM_W16_(322)N.mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'Should you mitigate your trust in the pedestrian in this situation?', '', '', '', 'Sollen Sie in dieser Situation das Vertrauen zum Fußgänger begrenzen?', '', '', '', 'Чи потрібно в цій ситуації обмежити свою довіру до пішохода?', '', '', ''),
(3259, 13113, 'Czy w tej sytuacji masz obowiązek powstrzymać się od ruchu w celu ustąpienia pierwszeństwa pieszemu wchodzącemu na przejście?', '', '', '', 'T', 'GM_W16(323).mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In this situation, are you obliged to stop moving to yield the right of way to a pedestrian entering the crossing?', '', '', '', 'Sollen Sie in dieser Situation die weitere Fahrt einstellen, um dem auf den Fußgängerüberweg einschreitenden Fußgänger den Vorrang zu gewähren?', '', '', '', 'Чи зобов\'язані Ви, в цій ситуації, утриматися від руху, щоб дати дорогу пішоходу, який входить на перехід?', '', '', ''),
(3260, 13114, 'Czy w tej sytuacji masz obowiązek zatrzymać pojazd w celu ustąpienia pierwszeństwa pieszemu?', '', '', '', 'T', 'GM_W16(324).mp4', 'PODSTAWOWY', 3, 'A,B,C,D,T,AM,A1,A2,B1,C1,D1', '', '', '', '', 'In this situation, are you obliged to stop your vehicle to yield the right of way to a pedestrian?', '', '', '', 'Sollen Sie in dieser Situation anhalten, um dem Fußgänger den Vorrang zu gewähren?', '', '', '', 'Чи, у цій ситуації, Ви зобов’язані зупинити свій транспортний засіб, щоб дати дорогу пішоходу?', '', '', ''),
